const FILES = {"fastapi": {"async-await.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# Python Async/Await Guide with FastAPI  (~25 patterns, condensed)\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\nimport asyncio, httpx\nfrom fastapi import FastAPI, HTTPException\nfrom typing import Optional\napp = FastAPI()\nshipment_data = {\n    1: {\"id\": 1, \"content\": \"Shipment 1\", \"weight\": 10, \"status\": \"In Transit\"},\n    2: {\"id\": 2, \"content\": \"Shipment 2\", \"weight\": 20, \"status\": \"Delivered\"},\n    3: {\"id\": 3, \"content\": \"Shipment 3\", \"weight\": 15, \"status\": \"Pending\"},\n}\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘               BEGINNER                           в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Sync vs Async Endpoints в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  def        вҶ’ thread pool (CPU work)  |  async def вҶ’ event loop (I/O)\n#  KEY RULE: inside async def, \"await\" before any async op\n@app.get(\"/sync/shipment/{id}\")\ndef get_shipment_sync(id: int):                       # sync вҖ” thread pool\n    if id not in shipment_data: raise HTTPException(404, \"Not found\")\n    return shipment_data[id]\n@app.get(\"/async/shipment/{id}\")\nasync def get_shipment_async(id: int):                # async вҖ” event loop\n    if id not in shipment_data: raise HTTPException(404, \"Not found\")\n    return shipment_data[id]\n\n# в”Җв”Җ 2. Await a Sleep в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  asyncio.sleep() = non-blocking  |  time.sleep() = BLOCKING (freezes server!)\n@app.get(\"/async/slow-shipment/{id}\")\nasync def get_shipment_slow(id: int):\n    await asyncio.sleep(2)  # server handles other requests during wait\n    if id not in shipment_data: raise HTTPException(404, \"Not found\")\n    return {\"shipment\": shipment_data[id]}\n\n# в”Җв”Җ 3. Await HTTP Call (httpx) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  httpx.AsyncClient = async  |  requests.get() = BLOCKING (never in async def!)\n@app.get(\"/async/external-api\")\nasync def call_external_api():\n    async with httpx.AsyncClient() as client:\n        resp = await client.get(\"https://jsonplaceholder.typicode.com/todos/1\")\n    return {\"external_data\": resp.json()}\n\n# в”Җв”Җ 4. Sequential Awaits в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  Each await waits for previous вҶ’ total = sum of all waits\n@app.get(\"/async/sequential\")\nasync def sequential_calls():\n    async with httpx.AsyncClient() as client:\n        r1 = await client.get(\"https://jsonplaceholder.typicode.com/todos/1\")\n        r2 = await client.get(\"https://jsonplaceholder.typicode.com/todos/2\")\n        r3 = await client.get(\"https://jsonplaceholder.typicode.com/todos/3\")\n    return {\"t1\": r1.json()[\"title\"], \"t2\": r2.json()[\"title\"], \"t3\": r3.json()[\"title\"]}\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘             INTERMEDIATE                         в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 5. asyncio.gather() вҖ” Parallel в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  gather(*coros) вҶ’ all at once, results IN ORDER, total = max wait\n@app.get(\"/async/parallel\")\nasync def parallel_calls():\n    async with httpx.AsyncClient() as client:\n        r1, r2, r3 = await asyncio.gather(\n            client.get(\"https://jsonplaceholder.typicode.com/todos/1\"),\n            client.get(\"https://jsonplaceholder.typicode.com/todos/2\"),\n            client.get(\"https://jsonplaceholder.typicode.com/todos/3\"),\n        )  # ~1s total instead of ~3s\n    return {\"t1\": r1.json()[\"title\"], \"t2\": r2.json()[\"title\"], \"t3\": r3.json()[\"title\"]}\n\n# в”Җв”Җ 6. Gather вҖ” Dynamic List в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/async/parallel-dynamic\")\nasync def parallel_dynamic(ids: str = \"1,2,3,4,5\"):\n    todo_ids = [int(i) for i in ids.split(\",\")]\n    async with httpx.AsyncClient() as client:\n        responses = await asyncio.gather(\n            *[client.get(f\"https://jsonplaceholder.typicode.com/todos/{t}\") for t in todo_ids])\n    return {\"results\": [r.json()[\"title\"] for r in responses]}\n\n# в”Җв”Җ 7. Gather вҖ” Error Handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  return_exceptions=True вҶ’ failed tasks return Exception, others still complete\n@app.get(\"/async/parallel-safe\")\nasync def parallel_with_error_handling():\n    async with httpx.AsyncClient() as client:\n        results = await asyncio.gather(\n            client.get(\"https://jsonplaceholder.typicode.com/todos/1\"),\n            client.get(\"https://invalid-url.com/data\"),\n            client.get(\"https://jsonplaceholder.typicode.com/todos/3\"),\n            return_exceptions=True)\n    return [{\"task\": i+1, \"error\": str(r)} if isinstance(r, Exception)\n            else {\"task\": i+1, \"data\": r.json()[\"title\"]} for i, r in enumerate(results)]\n\n# в”Җв”Җ 8-9. Async Helpers (Sequential & Parallel) в”Җв”Җв”Җв”Җ\nasync def fetch_from_db(id: int) -> dict:\n    await asyncio.sleep(0.5); return shipment_data.get(id)\nasync def enrich(shipment: dict) -> dict:\n    await asyncio.sleep(0.3); shipment[\"tracking\"] = f\"https://track.example.com/{shipment['id']}\"; return shipment\nasync def get_weight(id: int): await asyncio.sleep(0.5); return shipment_data.get(id, {}).get(\"weight\", 0)\nasync def get_status(id: int): await asyncio.sleep(0.5); return shipment_data.get(id, {}).get(\"status\", \"?\")\n\n@app.get(\"/async/helper/{id}\")\nasync def get_with_helpers(id: int):                  # sequential: 0.5 + 0.3 = 0.8s\n    s = await fetch_from_db(id)\n    if not s: raise HTTPException(404, \"Not found\")\n    return await enrich(s.copy())\n\n@app.get(\"/async/parallel-helpers/{id}\")\nasync def get_with_parallel_helpers(id: int):         # parallel: max(0.5, 0.5) = 0.5s\n    if id not in shipment_data: raise HTTPException(404, \"Not found\")\n    weight, status = await asyncio.gather(get_weight(id), get_status(id))\n    return {\"id\": id, \"weight\": weight, \"status\": status}\n\n# в”Җв”Җ 10. create_task() вҖ” Fire and Forget в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  Starts background work; endpoint returns immediately. Task lost on shutdown.\nasync def send_notification(sid: int, msg: str):\n    await asyncio.sleep(2); print(f\"NOTIFICATION: Shipment {sid} - {msg}\")\n\n@app.post(\"/async/fire-and-forget/{id}\")\nasync def update_and_notify(id: int):\n    if id not in shipment_data: raise HTTPException(404, \"Not found\")\n    shipment_data[id][\"status\"] = \"Delivered\"\n    asyncio.create_task(send_notification(id, \"Status changed\"))\n    return {\"shipment\": shipment_data[id]}\n\n# в”Җв”Җ 11. wait_for() вҖ” Timeout в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nasync def slow_db_query(id: int): await asyncio.sleep(5); return shipment_data.get(id)\n\n@app.get(\"/async/timeout/{id}\")\nasync def get_with_timeout(id: int):\n    try: return await asyncio.wait_for(slow_db_query(id), timeout=2.0)\n    except asyncio.TimeoutError: raise HTTPException(504, \"Timed out after 2s\")\n\n# в”Җв”Җ 12. Semaphore вҖ” Limit Concurrency в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  Semaphore(N) = max N concurrent; others wait for a slot\nsem = asyncio.Semaphore(3)\nasync def rate_limited_fetch(client: httpx.AsyncClient, tid: int):\n    async with sem:\n        return (await client.get(f\"https://jsonplaceholder.typicode.com/todos/{tid}\")).json()\n\n@app.get(\"/async/semaphore\")\nasync def get_with_semaphore():\n    async with httpx.AsyncClient() as client:\n        results = await asyncio.gather(*[rate_limited_fetch(client, i) for i in range(1, 11)])\n    return {\"count\": len(results), \"titles\": [r[\"title\"] for r in results]}\n\n# в”Җв”Җ 13. Lock вҖ” Prevent Race Conditions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  Lock = only ONE task at a time  (vs Semaphore = N at a time)\ncounter = {\"value\": 0}\nlock = asyncio.Lock()\nasync def inc_safe():\n    async with lock: c = counter[\"value\"]; await asyncio.sleep(0.01); counter[\"value\"] = c + 1\nasync def inc_unsafe():\n    c = counter[\"value\"]; await asyncio.sleep(0.01); counter[\"value\"] = c + 1\n\n@app.get(\"/async/lock-demo\")\nasync def lock_demo():\n    counter[\"value\"] = 0; await asyncio.gather(*[inc_safe() for _ in range(10)])\n    safe = counter[\"value\"]  # always 10\n    counter[\"value\"] = 0; await asyncio.gather(*[inc_unsafe() for _ in range(10)])\n    return {\"with_lock\": safe, \"without_lock\": counter[\"value\"]}  # unsafe might be < 10\n\n# в”Җв”Җ 14. Event вҖ” Coordinate Tasks в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  set() = signal  |  wait() = block until set  |  clear() = reset\n@app.get(\"/async/event-demo\")\nasync def event_demo():\n    ready, steps = asyncio.Event(), []\n    async def setup():\n        steps.append(\"DB starting\"); await asyncio.sleep(1); steps.append(\"DB ready\"); ready.set()\n    async def query():\n        steps.append(\"Query waiting\"); await ready.wait(); steps.append(\"Query running\")\n    await asyncio.gather(setup(), query())\n    return {\"steps\": steps}\n\n# в”Җв”Җ 15. Queue вҖ” Producer/Consumer в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.post(\"/async/queue-demo\")\nasync def queue_demo():\n    q, results = asyncio.Queue(), []\n    async def producer():\n        for id in shipment_data: await q.put(id); await asyncio.sleep(0.1)\n        await q.put(None)\n    async def consumer():\n        while (id := await q.get()) is not None:\n            await asyncio.sleep(0.2); results.append({\"id\": id, \"ok\": True}); q.task_done()\n    await asyncio.gather(producer(), consumer())\n    return {\"processed\": results}\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘               ADVANCED                           в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 16. async for вҖ” Async Generators в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nasync def fetch_pages(page_size: int = 2):\n    ids = list(shipment_data.keys())\n    for i in range(0, len(ids), page_size):\n        await asyncio.sleep(0.3)\n        yield [shipment_data[sid] for sid in ids[i:i+page_size]]\n\n@app.get(\"/async/async-for\")\nasync def get_with_async_for():\n    items, pages = [], 0\n    async for page in fetch_pages():\n        pages += 1; items.extend(page)\n    return {\"pages\": pages, \"total\": len(items), \"data\": items}\n\n# в”Җв”Җ 17. async with вҖ” Async Context Manager в”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass AsyncDBConn:\n    async def __aenter__(self):\n        await asyncio.sleep(0.2); self.connected = True; return self\n    async def __aexit__(self, *exc):\n        await asyncio.sleep(0.1); self.connected = False; return False\n    async def query(self, id: int) -> Optional[dict]:\n        await asyncio.sleep(0.1); return shipment_data.get(id)\n\n@app.get(\"/async/context-manager/{id}\")\nasync def get_with_ctx(id: int):\n    async with AsyncDBConn() as db:\n        result = await db.query(id)\n        if not result: raise HTTPException(404, \"Not found\")\n        return {\"shipment\": result, \"connected\": db.connected}\n\n# в”Җв”Җ 18. shield() вҖ” Protect from Cancellation в”Җв”Җв”Җв”Җв”Җ\n#  Inner task survives even if outer is cancelled. Use for payments, saves.\nasync def critical_save(id: int):\n    await asyncio.sleep(1); shipment_data[id][\"status\"] = \"Saved\"; return shipment_data[id]\n\n@app.post(\"/async/shield/{id}\")\nasync def save_with_shield(id: int):\n    if id not in shipment_data: raise HTTPException(404, \"Not found\")\n    try: return await asyncio.wait_for(asyncio.shield(critical_save(id)), timeout=0.5)\n    except asyncio.TimeoutError: return {\"note\": \"Timed out, but save still running\"}\n\n# в”Җв”Җ 19. to_thread() вҖ” Sync in Async в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef heavy_cpu_work(id: int): return {\"id\": id, \"sum\": sum(range(1_000_000))}\n\n@app.get(\"/async/sync-in-async/{id}\")\nasync def call_sync_from_async(id: int):\n    return await asyncio.to_thread(heavy_cpu_work, id)\n\n# в”Җв”Җ 20. as_completed() вҖ” Fastest First в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  gather = input order  |  as_completed = finish order\nasync def fetch_delayed(id: int, delay: float):\n    await asyncio.sleep(delay); return {\"id\": id, \"delay\": delay}\n\n@app.get(\"/async/as-completed\")\nasync def process_as_completed():\n    tasks = [asyncio.create_task(fetch_delayed(1, 2.0)),\n             asyncio.create_task(fetch_delayed(2, 0.5)),\n             asyncio.create_task(fetch_delayed(3, 1.0))]\n    results, n = [], 1\n    for done in asyncio.as_completed(tasks):\n        r = await done; r[\"order\"] = n; results.append(r); n += 1\n    return {\"results\": results}  # id=2 first, id=3 second, id=1 last\n\n# в”Җв”Җ 21. Retry Pattern в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n_attempts = {\"n\": 0}\nasync def unreliable():\n    _attempts[\"n\"] += 1\n    if _attempts[\"n\"] < 3: raise Exception(f\"Fail #{_attempts['n']}\")\n    return {\"data\": \"ok\", \"attempts\": _attempts[\"n\"]}\n\nasync def retry_async(func, retries=3, delay=0.5):\n    for i in range(1, retries + 1):\n        try: return await func()\n        except Exception as e:\n            if i == retries: raise\n            await asyncio.sleep(delay * i)\n\n@app.get(\"/async/retry\")\nasync def get_with_retry():\n    _attempts[\"n\"] = 0\n    try: return await retry_async(unreliable, retries=5, delay=0.3)\n    except Exception as e: raise HTTPException(503, str(e))\n\n# в”Җв”Җ 22. Async Comprehension в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nasync def process_one(id: int):\n    await asyncio.sleep(0.1); s = shipment_data.get(id)\n    return {**s, \"processed\": True} if s else {\"id\": id, \"processed\": False}\n\n@app.get(\"/async/comprehension\")\nasync def async_comprehension():\n    # WRONG: [await process_one(id) for id in ids]  вҶҗ sequential!\n    # RIGHT: gather for parallel\n    return {\"results\": list(await asyncio.gather(*[process_one(id) for id in shipment_data]))}\n\n# в”Җв”Җ 23. Chaining вҖ” fetch -> transform -> validate\nasync def s_fetch(id: int): await asyncio.sleep(0.2); return shipment_data.get(id, {})\nasync def s_transform(d: dict): await asyncio.sleep(0.2); d[\"weight_lbs\"] = round(d.get(\"weight\", 0) * 2.205, 2); return d\nasync def s_validate(d: dict): await asyncio.sleep(0.1); d[\"valid\"] = d.get(\"weight_lbs\", 0) > 0; return d\n\n@app.get(\"/async/chain/{id}\")\nasync def chained_pipeline(id: int):\n    if id not in shipment_data: raise HTTPException(404, \"Not found\")\n    return await s_validate(await s_transform((await s_fetch(id)).copy()))\n\n# в”Җв”Җ 24. Fan-Out / Fan-In в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  Fan-out: 1 input -> N parallel tasks  |  Fan-in: N results -> 1 output\nasync def check_warehouse(wh: str, id: int):\n    await asyncio.sleep(0.3); return {\"wh\": wh, \"avail\": (id + hash(wh)) % 2 == 0}\n\n@app.get(\"/async/fan-out/{id}\")\nasync def fan_out_fan_in(id: int):\n    whs = [\"NYC\", \"LON\", \"TYO\", \"SYD\", \"BER\"]\n    results = await asyncio.gather(*[check_warehouse(w, id) for w in whs])\n    return {\"id\": id, \"available\": [r[\"wh\"] for r in results if r[\"avail\"]], \"checked\": len(results)}", "cheatSheet": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# CHEAT SHEET\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  CONCEPT              в”Ӯ TOOL                        в”Ӯ USE WHEN\n# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  Non-blocking wait    в”Ӯ await asyncio.sleep(n)      в”Ӯ Simulate delay, yield control\n#  Async HTTP           в”Ӯ httpx.AsyncClient           в”Ӯ External API calls\n#  Run in parallel      в”Ӯ asyncio.gather(*coros)      в”Ӯ Multiple independent I/O ops\n#  Safe parallel        в”Ӯ gather(return_exceptions=T) в”Ӯ Some tasks may fail\n#  Background task      в”Ӯ asyncio.create_task(coro)   в”Ӯ Fire-and-forget (logs, notifs)\n#  Timeout              в”Ӯ asyncio.wait_for(c, t)      в”Ӯ Cancel if too slow\n#  Limit concurrency    в”Ӯ asyncio.Semaphore(N)        в”Ӯ Rate-limit API/DB calls\n#  Mutual exclusion     в”Ӯ asyncio.Lock()              в”Ӯ Prevent race conditions\n#  Signal readiness     в”Ӯ asyncio.Event()             в”Ӯ \"Wait until X is ready\"\n#  Producer/consumer    в”Ӯ asyncio.Queue()             в”Ӯ Job processing pipelines\n#  Protect from cancel  в”Ӯ asyncio.shield(coro)        в”Ӯ Critical ops (payments, saves)\n#  Sync in async        в”Ӯ asyncio.to_thread(fn)       в”Ӯ CPU work / blocking libraries\n#  Fastest first        в”Ӯ asyncio.as_completed(tasks) в”Ӯ Process results as they arrive\n#  Retry on failure     в”Ӯ retry_async(fn, n, delay)   в”Ӯ Unreliable external services\n#  Async iteration      в”Ӯ async for x in gen()        в”Ӯ Paginated/streaming data\n#  Async context mgr    в”Ӯ async with Resource() as r  в”Ӯ Setup/teardown needing await\n#  Async comprehension  в”Ӯ gather(*[coro for ...])     в”Ӯ Parallel list processing\n#  Chaining             в”Ӯ await g(await f(x))         в”Ӯ Pipeline: fetch->transform->save\n#  Fan-out/fan-in       в”Ӯ gather вҶ’ filter/combine     в”Ӯ Split work, merge results\n#\n#  COMPARISON           в”Ӯ A                           в”Ӯ B\n# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  Blocking vs async    в”Ӯ time.sleep() вҖ” blocks       в”Ӯ asyncio.sleep() вҖ” yields\n#  HTTP client          в”Ӯ requests.get() вҖ” sync       в”Ӯ httpx.AsyncClient вҖ” async\n#  Endpoint             в”Ӯ def f() вҖ” thread pool       в”Ӯ async def f() вҖ” event loop\n#  gather vs create_taskв”Ӯ gather: await all results   в”Ӯ create_task: fire-and-forget\n#  gather vs as_compl.  в”Ӯ gather: input order         в”Ӯ as_completed: finish order\n#  Semaphore vs Lock    в”Ӯ Semaphore(N): N concurrent  в”Ӯ Lock: exactly 1 at a time\n#  Sequential vs ||     в”Ӯ await a; await b вҖ” sum time в”Ӯ gather(a,b) вҖ” max time\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#", "reference": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  ASYNC/AWAIT вҖ” DETAILED REFERENCE\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n# в”Җв”Җ async def vs def вҖ” When to use which в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   async def route():     вҶ’ runs on event loop, use for I/O (HTTP, DB, files)\n#   def route():           вҶ’ runs in thread pool, use for CPU work (calculations)\n#   KEY RULE: inside async def, you MUST \"await\" any async operation\n#   NEVER use time.sleep() or requests.get() in async def вҖ” they BLOCK the event loop\n#\n#   BEGINNER EXAMPLE вҖ” async vs sync endpoints:\n#\n#     # Async вҖ” for I/O (HTTP calls, DB queries, file reads):\n#     @app.get(\"/async\")\n#     async def async_route():\n#         data = await fetch_from_db()    # вҶҗ yields control, doesn't block\n#         return data\n#\n#     # Sync вҖ” for CPU work (calculations, image processing):\n#     @app.get(\"/sync\")\n#     def sync_route():\n#         result = heavy_calculation()     # вҶҗ runs in thread pool automatically\n#         return result\n#\n#     # Both called the same way:\n#     #   curl \"http://localhost:8000/async\"\n#     #   curl \"http://localhost:8000/sync\"\n#     #\n#     # Difference is INTERNAL вҖ” async yields to event loop, sync gets a thread\n#\n# в”Җв”Җ await вҖ” Pause and yield control в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   result = await some_async_function()\n#   Pauses THIS function, lets event loop handle other requests.\n#   Only works inside async def. The awaited function must be a coroutine.\n#\n# в”Җв”Җ asyncio.gather() вҖ” Run tasks in parallel в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   r1, r2, r3 = await asyncio.gather(coro1(), coro2(), coro3())\n#   All run concurrently. Results returned IN INPUT ORDER.\n#   Total time = max(individual times), not sum.\n#   return_exceptions=True вҶ’ failed tasks return Exception object instead of crashing all.\n#   Dynamic: await asyncio.gather(*[fetch(id) for id in ids])\n#\n#   BEGINNER EXAMPLE вҖ” gather():\n#\n#     async def fetch_user(id): await asyncio.sleep(1); return {\"id\": id}\n#     async def fetch_orders(id): await asyncio.sleep(1); return [{\"order\": 1}]\n#     async def fetch_prefs(id): await asyncio.sleep(1); return {\"theme\": \"dark\"}\n#\n#     @app.get(\"/user/{id}\")\n#     async def get_user_full(id: int):\n#         user, orders, prefs = await asyncio.gather(\n#             fetch_user(id), fetch_orders(id), fetch_prefs(id)\n#         )\n#         return {\"user\": user, \"orders\": orders, \"prefs\": prefs}\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/user/1\"\n#     #\n#     #   WITHOUT gather (sequential):\n#     #     fetch_user   в”Җв”Җ1sв”Җв”Җв–¶\n#     #     fetch_orders        в”Җв”Җ1sв”Җв”Җв–¶\n#     #     fetch_prefs                в”Җв”Җ1sв”Җв”Җв–¶\n#     #     Total: 3 seconds\n#     #\n#     #   WITH gather (parallel):\n#     #     fetch_user   в”Җв”Җ1sв”Җв”Җв–¶\n#     #     fetch_orders в”Җв”Җ1sв”Җв”Җв–¶  вҶҗ all start at same time\n#     #     fetch_prefs  в”Җв”Җ1sв”Җв”Җв–¶\n#     #     Total: 1 second (max of individual times)\n#     #\n#     #   Results returned in INPUT order (not finish order):\n#     #     user вҶ’ {\"id\": 1}, orders вҶ’ [{\"order\": 1}], prefs вҶ’ {\"theme\": \"dark\"}\n#\n# в”Җв”Җ asyncio.create_task() вҖ” Fire and forget в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   asyncio.create_task(send_email(user))\n#   Starts background work. Endpoint returns immediately.\n#   Task runs in background. WARNING: lost on server shutdown.\n#   Use for: logging, notifications, non-critical side effects.\n#\n#   BEGINNER EXAMPLE вҖ” create_task():\n#\n#     async def send_notification(user_id: int, msg: str):\n#         await asyncio.sleep(2)       # simulate slow email\n#         print(f\"Notified user {user_id}: {msg}\")\n#\n#     @app.post(\"/order\")\n#     async def create_order():\n#         order = {\"id\": 99, \"status\": \"created\"}\n#         asyncio.create_task(send_notification(1, \"Order created\"))\n#         return order                  # вҶҗ returns IMMEDIATELY, email sends in background\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/order\"\n#     #     вҶ’ {\"id\": 99, \"status\": \"created\"}  (instant response)\n#     #     вҶ’ 2 seconds later: \"Notified user 1: Order created\" (in server logs)\n#     #\n#     #   Timeline:\n#     #     create_order() в”Җв”Җreturnsв”Җв”Җв–¶ client gets response\n#     #     send_notification() в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ2sв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв–¶ prints in background\n#\n# в”Җв”Җ asyncio.wait_for() вҖ” Timeout в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   result = await asyncio.wait_for(slow_query(), timeout=2.0)\n#   Raises asyncio.TimeoutError if not done in time. Cancels the task.\n#\n#   BEGINNER EXAMPLE вҖ” wait_for() timeout:\n#\n#     async def slow_query():\n#         await asyncio.sleep(5)       # takes 5 seconds\n#         return {\"data\": \"result\"}\n#\n#     @app.get(\"/query\")\n#     async def get_query():\n#         try:\n#             result = await asyncio.wait_for(slow_query(), timeout=2.0)\n#             return result\n#         except asyncio.TimeoutError:\n#             raise HTTPException(504, \"Query took too long\")\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/query\"\n#     #\n#     #   Timeline:\n#     #     slow_query() starts в”Җв”Җ2sв”Җв”Җв–¶ TIMEOUT! вҶ’ 504 \"Query took too long\"\n#     #                                 (cancelled at 2s, never reaches 5s)\n#     #\n#     #   If query finishes in < 2s вҶ’ normal response\n#     #   If query takes > 2s вҶ’ TimeoutError вҶ’ task cancelled\n#\n# в”Җв”Җ asyncio.Semaphore(N) вҖ” Limit concurrency в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   sem = asyncio.Semaphore(3)        вҶ’ max 3 concurrent\n#   async with sem:                   вҶ’ acquire slot (blocks if all N taken)\n#       await do_work()               вҶ’ work runs with slot held\n#   Use for: rate-limiting API calls, DB connection limits.\n#\n#   BEGINNER EXAMPLE вҖ” Semaphore:\n#\n#     sem = asyncio.Semaphore(3)   # max 3 concurrent API calls\n#\n#     async def call_api(id):\n#         async with sem:            # вҶҗ waits if 3 already running\n#             await asyncio.sleep(1) # simulate API call\n#             return {\"id\": id}\n#\n#     @app.get(\"/batch\")\n#     async def batch():\n#         results = await asyncio.gather(*[call_api(i) for i in range(10)])\n#         return results\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/batch\"\n#     #\n#     #   10 tasks but Semaphore(3) вҶ’ only 3 run at a time:\n#     #     Time 0s: tasks 0,1,2 start  в”Ӯ tasks 3-9 wait\n#     #     Time 1s: tasks 0,1,2 done   в”Ӯ tasks 3,4,5 start\n#     #     Time 2s: tasks 3,4,5 done   в”Ӯ tasks 6,7,8 start\n#     #     Time 3s: tasks 6,7,8 done   в”Ӯ task 9 starts\n#     #     Time 4s: task 9 done        в”Ӯ total ~4s (not 10s, not 1s)\n#\n# в”Җв”Җ asyncio.Lock() вҖ” Mutual exclusion в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   lock = asyncio.Lock()\n#   async with lock:                  вҶ’ only ONE task at a time\n#       counter += 1                  вҶ’ safe from race conditions\n#   Semaphore(1) == Lock(). Use Lock when exactly-one is the intent.\n#\n#   BEGINNER EXAMPLE вҖ” Lock:\n#\n#     counter = {\"value\": 0}\n#     lock = asyncio.Lock()\n#\n#     @app.post(\"/increment\")\n#     async def increment():\n#         async with lock:                 # вҶҗ only ONE request at a time\n#             counter[\"value\"] += 1        # safe вҖ” no race condition\n#         return counter\n#\n#     # Without lock: 2 requests at same time could both read 0, both write 1\n#     # With lock: request A holds lock вҶ’ B waits вҶ’ A writes 1 вҶ’ B reads 1, writes 2\n#\n# в”Җв”Җ asyncio.Event() вҖ” Signal between tasks в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   event = asyncio.Event()\n#   await event.wait()                вҶ’ blocks until event.set() is called\n#   event.set()                       вҶ’ unblocks all waiters\n#   event.clear()                     вҶ’ reset to unset state\n#   Use for: \"wait until database is ready\", \"wait until config loaded\"\n#\n#   BEGINNER EXAMPLE вҖ” Event:\n#\n#     db_ready = asyncio.Event()\n#\n#     async def init_db():\n#         await asyncio.sleep(2)       # simulate slow DB connect\n#         db_ready.set()               # вҶҗ signal \"ready!\"\n#\n#     @app.get(\"/data\")\n#     async def get_data():\n#         await db_ready.wait()        # вҶҗ blocks until db_ready.set() is called\n#         return {\"status\": \"db is ready\"}\n#\n#     # Flow:\n#     #   Server starts вҶ’ init_db() begins (2s)\n#     #   curl /data at 0s вҶ’ waits... waits...\n#     #   At 2s: db_ready.set() вҶ’ all waiters unblocked вҶ’ response returned\n#\n# в”Җв”Җ asyncio.Queue() вҖ” Producer/consumer в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   q = asyncio.Queue()\n#   await q.put(item)                 вҶ’ producer adds work\n#   item = await q.get()              вҶ’ consumer takes work (blocks if empty)\n#   q.task_done()                     вҶ’ mark item as processed\n#   Use for: job processing, work distribution, buffering.\n#\n#   BEGINNER EXAMPLE вҖ” Queue:\n#\n#     job_queue = asyncio.Queue()\n#\n#     @app.post(\"/job\")\n#     async def submit_job():\n#         await job_queue.put({\"task\": \"process\", \"id\": 1})  # producer\n#         return {\"queued\": True, \"pending\": job_queue.qsize()}\n#\n#     async def worker():\n#         while True:\n#             job = await job_queue.get()    # blocks until job available\n#             print(f\"Processing: {job}\")\n#             job_queue.task_done()\n#\n#     # curl -X POST \"http://localhost:8000/job\"\n#     #   вҶ’ {\"queued\": true, \"pending\": 1}\n#     #   вҶ’ worker picks up job from queue and processes it\n#\n# в”Җв”Җ asyncio.shield() вҖ” Protect from cancellation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   await asyncio.shield(critical_save(data))\n#   Even if outer task is cancelled, shielded task keeps running.\n#   Use for: payments, database commits, anything that MUST finish.\n#\n#   BEGINNER EXAMPLE вҖ” shield:\n#\n#     async def save_payment(id):\n#         await asyncio.sleep(3)        # slow but MUST complete\n#         return {\"id\": id, \"saved\": True}\n#\n#     @app.post(\"/pay/{id}\")\n#     async def pay(id: int):\n#         try:\n#             return await asyncio.wait_for(asyncio.shield(save_payment(id)), timeout=1)\n#         except asyncio.TimeoutError:\n#             return {\"msg\": \"Timed out, but payment still processing\"}\n#\n#     # curl -X POST \"http://localhost:8000/pay/1\"\n#     #   вҶ’ timeout after 1s вҶ’ {\"msg\": \"Timed out, but payment still processing\"}\n#     #   вҶ’ BUT save_payment keeps running in background (shield protects it)\n#     #   Without shield: timeout would CANCEL save_payment вҶ’ payment lost!\n#\n# в”Җв”Җ asyncio.to_thread() вҖ” Run sync code in async context в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   result = await asyncio.to_thread(heavy_cpu_function, arg1, arg2)\n#   Runs sync function in thread pool, doesn't block event loop.\n#   Use for: CPU-heavy work, libraries that don't support async.\n#\n#   BEGINNER EXAMPLE вҖ” to_thread:\n#\n#     def heavy_cpu_work(n):           # sync function вҖ” can't use await\n#         return sum(range(n))         # CPU-intensive calculation\n#\n#     @app.get(\"/compute/{n}\")\n#     async def compute(n: int):\n#         result = await asyncio.to_thread(heavy_cpu_work, n)\n#         return {\"sum\": result}\n#\n#     # curl \"http://localhost:8000/compute/1000000\"\n#     #   вҶ’ {\"sum\": 499999500000}\n#     #\n#     #   Without to_thread: heavy_cpu_work BLOCKS event loop вҶ’ other requests wait\n#     #   With to_thread: runs in thread pool вҶ’ event loop stays free for other requests\n#\n# в”Җв”Җ asyncio.as_completed() вҖ” Process fastest first в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   for done in asyncio.as_completed(tasks):\n#       result = await done            вҶ’ get result in FINISH ORDER (not input order)\n#   vs gather: returns in input order. as_completed: returns as each finishes.\n#\n#   BEGINNER EXAMPLE вҖ” as_completed:\n#\n#     async def fetch(id, delay):\n#         await asyncio.sleep(delay)\n#         return {\"id\": id, \"delay\": delay}\n#\n#     @app.get(\"/race\")\n#     async def race():\n#         tasks = [fetch(1, 2.0), fetch(2, 0.5), fetch(3, 1.0)]\n#         results = []\n#         for done in asyncio.as_completed(tasks):\n#             r = await done\n#             results.append(r)\n#         return results\n#\n#     # curl \"http://localhost:8000/race\"\n#     #\n#     #   gather would return: [id=1, id=2, id=3]  вҶҗ input order\n#     #   as_completed returns: [id=2, id=3, id=1]  вҶҗ finish order (fastest first)\n#     #\n#     #   Timeline:\n#     #     0.5s: id=2 finishes first  вҶ’ results[0]\n#     #     1.0s: id=3 finishes second вҶ’ results[1]\n#     #     2.0s: id=1 finishes last   вҶ’ results[2]\n#\n# в”Җв”Җ async for вҖ” Async iteration в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   async def fetch_pages():\n#       yield page                     вҶ’ async generator (yields data over time)\n#   async for page in fetch_pages():\n#       process(page)                  вҶ’ processes each page as it arrives\n#   Use for: paginated APIs, streaming data, chunked file reads.\n#\n#   BEGINNER EXAMPLE вҖ” async for:\n#\n#     async def fetch_pages():\n#         for page_num in range(1, 4):\n#             await asyncio.sleep(0.5)     # simulate API delay\n#             yield [f\"item_{page_num}_1\", f\"item_{page_num}_2\"]\n#\n#     @app.get(\"/pages\")\n#     async def get_all_pages():\n#         all_items = []\n#         async for page in fetch_pages():  # вҶҗ processes each page as it arrives\n#             all_items.extend(page)\n#         return {\"items\": all_items}\n#\n#     # curl \"http://localhost:8000/pages\"\n#     #   вҶ’ page 1 arrives at 0.5s вҶ’ page 2 at 1.0s вҶ’ page 3 at 1.5s\n#     #   вҶ’ {\"items\": [\"item_1_1\",\"item_1_2\",\"item_2_1\",...]}\n#\n# в”Җв”Җ async with вҖ” Async context manager в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   async with httpx.AsyncClient() as client:\n#       response = await client.get(url)\n#   __aenter__ = async setup, __aexit__ = async cleanup\n#   Use for: connections, sessions, resources needing async open/close.\n#\n#   BEGINNER EXAMPLE вҖ” async with:\n#\n#     @app.get(\"/external\")\n#     async def call_external():\n#         async with httpx.AsyncClient() as client:    # вҶҗ opens connection\n#             resp = await client.get(\"https://api.example.com/data\")\n#             return resp.json()\n#         # вҶҗ connection auto-closed here (even if error occurs)\n#\n#     # curl \"http://localhost:8000/external\"\n#     #   async with opens client вҶ’ makes request вҶ’ returns data вҶ’ closes client\n#     #   Same as try/finally but cleaner вҖ” cleanup guaranteed\n#\n# в”Җв”Җ Retry pattern в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   for i in range(retries):\n#       try: return await func()\n#       except: await asyncio.sleep(delay * i)  вҶ’ exponential backoff\n#   Use for: unreliable external APIs, transient network errors.\n#\n#   BEGINNER EXAMPLE вҖ” Retry:\n#\n#     async def retry_async(func, retries=3, delay=0.5):\n#         for i in range(1, retries + 1):\n#             try:\n#                 return await func()\n#             except Exception as e:\n#                 if i == retries: raise      # last attempt вҖ” give up\n#                 await asyncio.sleep(delay * i)  # wait longer each time\n#\n#     @app.get(\"/api-call\")\n#     async def get_api():\n#         return await retry_async(unreliable_api, retries=3, delay=0.5)\n#\n#     # curl \"http://localhost:8000/api-call\"\n#     #\n#     #   Attempt 1: fails вҶ’ wait 0.5s\n#     #   Attempt 2: fails вҶ’ wait 1.0s (exponential backoff)\n#     #   Attempt 3: succeeds вҶ’ return result\n#     #   OR Attempt 3: fails вҶ’ raise exception (503)\n#\n# в”Җв”Җ httpx.AsyncClient вҖ” Async HTTP client в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   async with httpx.AsyncClient() as client:\n#       resp = await client.get(url)\n#   NEVER use requests.get() in async def вҖ” it blocks the event loop.\n#   httpx is the async-native replacement for requests.\n#\n#   BEGINNER EXAMPLE вҖ” httpx:\n#\n#     # BAD вҖ” blocks event loop:\n#     #   import requests\n#     #   resp = requests.get(\"https://api.com/data\")  вҶҗ BLOCKS all other requests!\n#     #\n#     # GOOD вҖ” non-blocking:\n#     #   async with httpx.AsyncClient() as client:\n#     #       resp = await client.get(\"https://api.com/data\")  вҶҗ yields control\n#     #\n#     # curl \"http://localhost:8000/external\"\n#     #   вҶ’ httpx makes async HTTP call вҶ’ event loop handles other requests meanwhile\n#\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ"}, "crud.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  FastAPI CRUD вҖ” Raw Dict Patterns (No Pydantic)\n#  Run: uvicorn 1.CRUD:app --reload\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\nfrom fastapi import Body, Cookie, FastAPI, File, Form, Header, HTTPException, Path, Query, UploadFile, status\nfrom fastapi.responses import JSONResponse\nfrom typing import List, Optional\n\napp = FastAPI()\nshipment_data = {\n    1: {\"id\": 1, \"content\": \"Shipment 1 content\", \"weight\": 10, \"status\": \"In Transit\"},\n    2: {\"id\": 2, \"content\": \"Shipment 2 content\", \"weight\": 20, \"status\": \"Delivered\"},\n    3: {\"id\": 3, \"content\": \"Shipment 3 content\", \"weight\": 15, \"status\": \"Pending\"},\n}\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘              BEGINNER                            в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Path Parameter в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipment/{id}\")\ndef get_by_path(id: int):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    return shipment_data[id]\n# curl http://localhost:8000/shipment/1\n\n# в”Җв”Җ 2. Query Parameter в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipment\")\ndef get_by_query(id: int):  # auto-read from ?id=1\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    return shipment_data[id]\n# curl http://localhost:8000/shipment?id=1\n\n# в”Җв”Җ 3. Request Body (raw dict) вҖ” CREATE в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.post(\"/shipment\", status_code=status.HTTP_201_CREATED)\ndef create_shipment(data: dict = Body()):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\n        \"id\": new_id, \"content\": data[\"content\"],\n        \"weight\": data[\"weight\"], \"status\": data.get(\"status\", \"Pending\"),\n    }\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment -H \"Content-Type: application/json\" -d '{\"content\":\"New\",\"weight\":30}'\n\n# в”Җв”Җ 4. CREATE via Query Params в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.post(\"/shipment/query\", status_code=status.HTTP_201_CREATED)\ndef create_via_query(\n    content: str = Query(...), weight: float = Query(...),\n    shipment_status: str = Query(\"Pending\"),\n):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": content, \"weight\": weight, \"status\": shipment_status}\n    return shipment_data[new_id]\n# curl -X POST \"http://localhost:8000/shipment/query?content=New&weight=30\"\n\n# в”Җв”Җ 5. UPDATE (PUT) вҖ” path + body в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.put(\"/shipment/{id}\")\ndef update_shipment(id: int, data: dict = Body()):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    for key in (\"content\", \"weight\", \"status\"):\n        if key in data:\n            shipment_data[id][key] = data[key]\n    return shipment_data[id]\n# curl -X PUT http://localhost:8000/shipment/1 -H \"Content-Type: application/json\" -d '{\"status\":\"Delivered\"}'\n\n# в”Җв”Җ 6. DELETE вҖ” path parameter в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.delete(\"/shipment/{id}\")\ndef delete_by_path(id: int):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    return {\"message\": \"Deleted\", \"shipment\": shipment_data.pop(id)}\n# curl -X DELETE http://localhost:8000/shipment/1\n\n# в”Җв”Җ 7. DELETE вҖ” query parameter в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.delete(\"/shipment\")\ndef delete_by_query(id: int = Query(...)):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    return {\"message\": \"Deleted\", \"shipment\": shipment_data.pop(id)}\n# curl -X DELETE \"http://localhost:8000/shipment?id=2\"\n\n# в”Җв”Җ 8. Multiple Path Parameters в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/warehouse/{warehouse_id}/shipment/{shipment_id}\")\ndef get_by_multiple_path(warehouse_id: str, shipment_id: int):\n    return {\"warehouse\": warehouse_id, \"shipment\": shipment_data.get(shipment_id, \"Not found\")}\n# curl http://localhost:8000/warehouse/NYC/shipment/1\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘            INTERMEDIATE                          в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 9. Path with Validation (Path()) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipment/validated/{id}\")\ndef get_by_path_validated(id: int = Path(gt=0, description=\"Must be > 0\")):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    return shipment_data[id]\n# curl http://localhost:8000/shipment/validated/0  -> 422\n\n# в”Җв”Җ 10. Query with Validation (Query()) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipments\")\ndef get_filtered(\n    status: Optional[str] = Query(None), limit: int = Query(10, ge=1, le=100),\n    offset: int = Query(0, ge=0),\n):\n    results = list(shipment_data.values())\n    if status:\n        results = [s for s in results if s[\"status\"] == status]\n    return results[offset:offset + limit]\n# curl \"http://localhost:8000/shipments?status=Pending&limit=5\"\n\n# в”Җв”Җ 11. PATCH вҖ” path + query + body combined в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.patch(\"/shipment/{id}\")\ndef patch_shipment(id: int, notify: bool = Query(False), data: dict = Body()):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    for key in (\"content\", \"weight\", \"status\"):\n        if key in data:\n            shipment_data[id][key] = data[key]\n    return {\"shipment\": shipment_data[id], \"notified\": notify}\n# curl -X PATCH \"http://localhost:8000/shipment/1?notify=true\" -H \"Content-Type: application/json\" -d '{\"status\":\"Delivered\"}'\n\n# в”Җв”Җ 12. Path + Query вҖ” field selection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipment/{id}/details\")\ndef get_with_field_filter(id: int, fields: List[str] = Query(None)):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    shipment = shipment_data[id]\n    return {k: v for k, v in shipment.items() if k in fields} if fields else shipment\n# curl \"http://localhost:8000/shipment/1/details?fields=content&fields=status\"\n\n# в”Җв”Җ 13. Required vs Optional vs Default query params в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipments/search\")\ndef search_shipments(\n    q: str = Query(..., min_length=1),                     # required\n    status_filter: Optional[str] = Query(None),            # optional (None)\n    sort_by: str = Query(\"id\"),                            # default value\n):\n    results = [s for s in shipment_data.values() if q.lower() in s[\"content\"].lower()]\n    if status_filter:\n        results = [s for s in results if s[\"status\"] == status_filter]\n    return {\"query\": q, \"sort\": sort_by, \"results\": results}\n# curl \"http://localhost:8000/shipments/search?q=Shipment&status_filter=Pending\"\n\n# в”Җв”Җ 14. Header Parameter в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipment/auth/{id}\")\ndef get_with_header(\n    id: int, x_token: str = Header(...),\n    x_request_id: Optional[str] = Header(None),\n):\n    if x_token != \"secret-token\":\n        raise HTTPException(status_code=401, detail=\"Invalid token\")\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    return {\"shipment\": shipment_data[id], \"request_id\": x_request_id}\n# curl http://localhost:8000/shipment/auth/1 -H \"X-Token: secret-token\"\n\n# в”Җв”Җ 15. Cookie Parameter в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipment/session/{id}\")\ndef get_with_cookie(id: int, session_id: Optional[str] = Cookie(None)):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    return {\"shipment\": shipment_data[id], \"session\": session_id}\n# curl http://localhost:8000/shipment/session/1 -b \"session_id=abc123\"\n\n# в”Җв”Җ 16. Form Data в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.post(\"/shipment/form\", status_code=status.HTTP_201_CREATED)\ndef create_via_form(content: str = Form(...), weight: float = Form(...), shipment_status: str = Form(\"Pending\")):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": content, \"weight\": weight, \"status\": shipment_status}\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/form -d \"content=FormShipment&weight=25\"\n\n# в”Җв”Җ 17. File Upload в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.post(\"/shipment/upload\")\nasync def upload_shipment_doc(shipment_id: int = Query(...), file: UploadFile = File(...)):\n    if shipment_id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    contents = await file.read()\n    return {\"shipment_id\": shipment_id, \"filename\": file.filename, \"size_bytes\": len(contents)}\n# curl -X POST \"http://localhost:8000/shipment/upload?shipment_id=1\" -F \"file=@doc.pdf\"\n\n# в”Җв”Җ 18. File + Form Data в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.post(\"/shipment/upload-with-data\")\nasync def upload_with_form(content: str = Form(...), weight: float = Form(...), file: UploadFile = File(...)):\n    file_contents = await file.read()\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": content, \"weight\": weight, \"status\": \"Pending\", \"attachment\": file.filename}\n    return {\"shipment\": shipment_data[new_id], \"file_size\": len(file_contents)}\n# curl -X POST http://localhost:8000/shipment/upload-with-data -F \"content=New\" -F \"weight=30\" -F \"file=@doc.pdf\"\n\n# в”Җв”Җ 19. Multiple File Upload в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.post(\"/shipment/upload-multiple\")\nasync def upload_multiple(shipment_id: int = Query(...), files: List[UploadFile] = File(...)):\n    if shipment_id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    file_info = [{\"filename\": f.filename, \"size\": len(await f.read())} for f in files]\n    return {\"shipment_id\": shipment_id, \"files\": file_info}\n# curl -X POST \"http://localhost:8000/shipment/upload-multiple?shipment_id=1\" -F \"files=@a.pdf\" -F \"files=@b.pdf\"\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘              ADVANCED                            в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 20. Body with embed=True в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Without embed: {\"content\":\"...\", \"weight\":30}\n# With embed:    {\"data\": {\"content\":\"...\", \"weight\":30}}\n@app.post(\"/shipment/embedded\", status_code=status.HTTP_201_CREATED)\ndef create_embedded(data: dict = Body(embed=True)):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": data[\"content\"], \"weight\": data[\"weight\"], \"status\": data.get(\"status\", \"Pending\")}\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/embedded -H \"Content-Type: application/json\" -d '{\"data\":{\"content\":\"Embedded\",\"weight\":40}}'\n\n# в”Җв”Җ 21. Multiple Body Parameters в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Body: {\"shipment\": {...}, \"metadata\": {...}} вҖ” auto-embedded by param name\n@app.post(\"/shipment/with-metadata\", status_code=status.HTTP_201_CREATED)\ndef create_with_metadata(shipment: dict = Body(...), metadata: dict = Body(...)):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\n        \"id\": new_id, \"content\": shipment[\"content\"], \"weight\": shipment[\"weight\"],\n        \"status\": shipment.get(\"status\", \"Pending\"), \"metadata\": metadata,\n    }\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/with-metadata -H \"Content-Type: application/json\" -d '{\"shipment\":{\"content\":\"New\",\"weight\":30},\"metadata\":{\"source\":\"API\"}}'\n\n# в”Җв”Җ 22. Custom Response вҖ” headers, cookies, status в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.post(\"/shipment/custom-response\", status_code=status.HTTP_201_CREATED)\ndef create_with_custom_response(data: dict = Body()):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": data[\"content\"], \"weight\": data[\"weight\"], \"status\": data.get(\"status\", \"Pending\")}\n    response = JSONResponse(content={\"shipment\": shipment_data[new_id]}, status_code=201)\n    response.set_cookie(key=\"last_shipment_id\", value=str(new_id))\n    response.headers[\"X-Shipment-ID\"] = str(new_id)\n    return response\n# curl -v -X POST http://localhost:8000/shipment/custom-response -H \"Content-Type: application/json\" -d '{\"content\":\"Custom\",\"weight\":20}'\n\n# в”Җв”Җ 23. Enum-like Path Parameter в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipment/status/{status_value}\")\ndef get_by_status_path(status_value: str):\n    results = [s for s in shipment_data.values() if s[\"status\"].lower() == status_value.lower()]\n    if not results:\n        raise HTTPException(status_code=404, detail=f\"No shipments with status '{status_value}'\")\n    return results\n# curl http://localhost:8000/shipment/status/pending\n\n# в”Җв”Җ 24. List Query Parameter вҖ” batch GET в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/shipments/batch\")\ndef get_batch(ids: List[int] = Query(...)):\n    return [shipment_data[id] for id in ids if id in shipment_data]\n# curl \"http://localhost:8000/shipments/batch?ids=1&ids=2&ids=3\"\n\n# в”Җв”Җ 25. Bulk DELETE with body в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.delete(\"/shipments/bulk\")\ndef delete_bulk(data: dict = Body()):\n    ids = data.get(\"ids\", [])\n    deleted, not_found = [], []\n    for id in ids:\n        (deleted if id in shipment_data else not_found).append(shipment_data.pop(id) if id in shipment_data else id)\n    return {\"deleted\": deleted, \"not_found\": not_found}\n# curl -X DELETE http://localhost:8000/shipments/bulk -H \"Content-Type: application/json\" -d '{\"ids\":[1,2,99]}'", "cheatSheet": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  CHEAT SHEET\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# SOURCE        | SYNTAX                          | EXAMPLE\n# --------------|--------------------------------|----------------------------\n# Path param    | def f(id: int)                 | /shipment/{id}\n# Path valid.   | id: int = Path(gt=0)           | /shipment/validated/{id}\n# Query param   | def f(id: int)                 | /shipment?id=1\n# Query valid.  | limit: int = Query(10, ge=1)   | ?limit=5\n# Query list    | ids: List[int] = Query(...)    | ?ids=1&ids=2\n# Body (dict)   | data: dict = Body()            | JSON body\n# Body embed    | data: dict = Body(embed=True)  | {\"data\": {...}}\n# Multi body    | a: dict = Body(), b: dict = Body() | {\"a\":{...},\"b\":{...}}\n# Header        | x_token: str = Header(...)     | -H \"X-Token: val\"\n# Cookie        | sid: str = Cookie(None)        | -b \"sid=abc\"\n# Form          | name: str = Form(...)          | -d \"name=val\"\n# File          | file: UploadFile = File(...)    | -F \"file=@f.pdf\"\n# Custom resp   | return JSONResponse(...)       | set cookies/headers\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#", "reference": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  PARAMETER DECLARATIONS вҖ” DETAILED REFERENCE\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n# в”Җв”Җ Body() вҖ” Reads from JSON request body в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   data: dict = Body()             вҶ’ optional, reads entire JSON body as dict\n#   data: dict = Body(...)          вҶ’ required (... = Ellipsis = no default allowed)\n#   data: dict = Body(embed=True)   вҶ’ expects {\"data\": {...}} вҖ” wraps value under param name\n#   a: dict = Body(), b: dict = Body()  вҶ’ multiple body params: {\"a\":{...},\"b\":{...}}\n#   Note: Body() is needed to tell FastAPI \"read from body\" explicitly.\n#         Without it, simple types (str, int) would be treated as query params.\n#\n#   BEGINNER EXAMPLE вҖ” Why Body() matters:\n#\n#     # в”Җв”Җ CASE 1: WITHOUT Body() в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#     @app.post(\"/test\")\n#     def test(name: str, data: dict):\n#         ...\n#     # name: str   вҶ’ simple type, no Body()  вҶ’ FastAPI reads from QUERY string\n#     # data: dict  вҶ’ complex type            вҶ’ FastAPI reads from JSON BODY\n#     #\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/test?name=abc\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"key\": \"val\"}'\n#     #\n#     #   URL:  /test?name=abc          вҶҗ name comes from here (query)\n#     #   Body: {\"key\": \"val\"}          вҶҗ data comes from here (entire body = data)\n#     #\n#     #   Inside function:\n#     #     name вҶ’ \"abc\"                вҶҗ from query string\n#     #     data вҶ’ {\"key\": \"val\"}       вҶҗ from JSON body\n#\n#     # в”Җв”Җ CASE 2: WITH Body() on all params в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#     @app.post(\"/test\")\n#     def test(name: str = Body(), data: dict = Body()):\n#         ...\n#     # name: str = Body()  вҶ’ Body() overrides вҶ’ reads from JSON BODY\n#     # data: dict = Body() вҶ’ Body() explicit  вҶ’ reads from JSON BODY\n#     #\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/test\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"name\": \"abc\", \"data\": {\"key\": \"val\"}}'\n#     #\n#     #   URL:  /test                   вҶҗ no query params needed\n#     #   Body: {                       вҶҗ BOTH params come from body\n#     #           \"name\": \"abc\",            вҶҗ name comes from here\n#     #           \"data\": {\"key\": \"val\"}    вҶҗ data comes from here\n#     #         }\n#     #\n#     #   Inside function:\n#     #     name вҶ’ \"abc\"                вҶҗ from body[\"name\"]\n#     #     data вҶ’ {\"key\": \"val\"}       вҶҗ from body[\"data\"]\n#\n#     # в”Җв”Җ CASE 3: Single Body param (no Body()) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#     @app.post(\"/shipment\")\n#     def create(data: dict = Body()):\n#         ...\n#     # Only ONE body param вҶ’ body IS the value directly (no wrapping)\n#     #\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/shipment\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"content\": \"Table\", \"weight\": 10}'\n#     #\n#     #   Body: {\"content\": \"Table\", \"weight\": 10}   вҶҗ entire body = data\n#     #\n#     #   Inside function:\n#     #     data вҶ’ {\"content\": \"Table\", \"weight\": 10}  вҶҗ body itself\n#\n#     # в”Җв”Җ CASE 4: Single Body param WITH embed=True в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#     @app.post(\"/shipment\")\n#     def create(data: dict = Body(embed=True)):\n#         ...\n#     # embed=True вҶ’ wraps under param name, even for single param\n#     #\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/shipment\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"data\": {\"content\": \"Table\", \"weight\": 10}}'\n#     #\n#     #   Body: {                                     вҶҗ wrapped under \"data\" key\n#     #           \"data\": {\"content\": \"Table\", \"weight\": 10}\n#     #         }\n#     #\n#     #   Inside function:\n#     #     data вҶ’ {\"content\": \"Table\", \"weight\": 10}  вҶҗ extracted from body[\"data\"]\n#\n#   RULES FastAPI uses (when you DON'T add Body/Query/Path/etc.):\n#     simple type (str, int, float, bool) вҶ’ Query param   (?key=val)\n#     complex type (dict, list, Pydantic) вҶ’ Body param    (JSON)\n#     name matches {name} in URL path    вҶ’ Path param     (/items/{name})\n#\n#   Body() OVERRIDES the default вҶ’ forces any type to be read from JSON body.\n#   Body(...) = required  |  Body() = optional  |  Body(\"default\") = has default\n#\n# в”Җв”Җ Query() вҖ” Reads from URL query string (?key=value) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   q: str = Query(...)                   вҶ’ required, no default\n#   q: str = Query(..., min_length=1)     вҶ’ required + string length validation\n#   status: str = Query(\"Pending\")        вҶ’ optional, defaults to \"Pending\"\n#   status: Optional[str] = Query(None)   вҶ’ optional, defaults to None\n#   limit: int = Query(10, ge=1, le=100)  вҶ’ default 10, must be between 1-100\n#   ids: List[int] = Query(...)           вҶ’ list param: ?ids=1&ids=2&ids=3\n#   Validators: ge (>=), le (<=), gt (>), lt (<), min_length, max_length\n#\n#   BEGINNER EXAMPLE вҖ” Query():\n#\n#     @app.get(\"/search\")\n#     def search(q: str = Query(..., min_length=1), limit: int = Query(10, ge=1, le=100)):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/search?q=table&limit=5\"\n#     #\n#     #   URL:  /search?q=table&limit=5\n#     #                  в”Ӯ        в”Ӯ\n#     #                  в–ј        в–ј\n#     #   Inside function:\n#     #     q     вҶ’ \"table\"     вҶҗ from ?q=table (required вҖ” omit вҶ’ 422)\n#     #     limit вҶ’ 5           вҶҗ from ?limit=5 (optional вҖ” omit вҶ’ default 10)\n#     #\n#     #   curl \"http://localhost:8000/search\"            вҶ’ 422! q is required (...)\n#     #   curl \"http://localhost:8000/search?q=&limit=5\" вҶ’ 422! min_length=1 fails\n#     #   curl \"http://localhost:8000/search?q=x&limit=200\" вҶ’ 422! le=100 fails\n#\n#     # List query param:\n#     @app.get(\"/filter\")\n#     def filter_items(ids: List[int] = Query(...)):\n#         ...\n#     #   curl \"http://localhost:8000/filter?ids=1&ids=2&ids=3\"\n#     #     ids вҶ’ [1, 2, 3]     вҶҗ repeated key = list\n#\n# в”Җв”Җ Path() вҖ” Reads from URL path (/items/{id}) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   id: int = Path(gt=0, description=\"Must be > 0\")\n#   Path params are always required (they're part of the URL).\n#   Use Path() to add validation (gt, ge, lt, le) and OpenAPI docs metadata.\n#\n#   BEGINNER EXAMPLE вҖ” Path():\n#\n#     @app.get(\"/shipment/{id}\")\n#     def get_shipment(id: int = Path(gt=0, le=10000)):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/shipment/42\"\n#     #\n#     #   URL:  /shipment/42\n#     #                   в”Ӯ\n#     #                   в–ј\n#     #   Inside function:\n#     #     id вҶ’ 42              вҶҗ from URL path segment (always required)\n#     #\n#     #   curl \"http://localhost:8000/shipment/0\"     вҶ’ 422! gt=0 fails (must be > 0)\n#     #   curl \"http://localhost:8000/shipment/abc\"   вҶ’ 422! not a valid int\n#     #   curl \"http://localhost:8000/shipment/\"      вҶ’ 404! path segment missing\n#\n# в”Җв”Җ Header() вҖ” Reads from HTTP headers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   x_token: str = Header(...)              вҶ’ required header\n#   x_request_id: Optional[str] = Header(None)  вҶ’ optional header\n#   FastAPI auto-converts: x_token вҶ’ \"X-Token\" (underscores вҶ’ hyphens)\n#\n#   BEGINNER EXAMPLE вҖ” Header():\n#\n#     @app.get(\"/secure\")\n#     def secure(x_token: str = Header(...), x_request_id: Optional[str] = Header(None)):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/secure\" \\\n#     #        -H \"X-Token: my-secret-123\" \\\n#     #        -H \"X-Request-Id: req-456\"\n#     #\n#     #   Headers:\n#     #     X-Token: my-secret-123       вҶҗ x_token reads this (underscore вҶ’ hyphen)\n#     #     X-Request-Id: req-456        вҶҗ x_request_id reads this\n#     #            в”Ӯ                в”Ӯ\n#     #            в–ј                в–ј\n#     #   Inside function:\n#     #     x_token      вҶ’ \"my-secret-123\"  вҶҗ required вҖ” omit вҶ’ 422\n#     #     x_request_id вҶ’ \"req-456\"        вҶҗ optional вҖ” omit вҶ’ None\n#     #\n#     #   curl \"http://localhost:8000/secure\"  вҶ’ 422! X-Token header missing\n#     #   NOTE: Python uses _ but HTTP headers use - (auto-converted by FastAPI)\n#\n# в”Җв”Җ Cookie() вҖ” Reads from cookies в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   session_id: Optional[str] = Cookie(None)  вҶ’ optional cookie\n#   Reads from the Cookie header, matches by parameter name.\n#\n#   BEGINNER EXAMPLE вҖ” Cookie():\n#\n#     @app.get(\"/profile\")\n#     def profile(session_id: Optional[str] = Cookie(None)):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/profile\" -b \"session_id=abc123\"\n#     #\n#     #   Cookie header: session_id=abc123\n#     #                            в”Ӯ\n#     #                            в–ј\n#     #   Inside function:\n#     #     session_id вҶ’ \"abc123\"   вҶҗ from cookie (optional вҖ” no cookie вҶ’ None)\n#     #\n#     #   curl \"http://localhost:8000/profile\"  вҶ’ session_id = None (optional)\n#     #   -b flag = --cookie = send cookie header\n#\n# в”Җв”Җ Form() вҖ” Reads from form-encoded body (application/x-www-form-urlencoded) в”Җв”Җ\n#   content: str = Form(...)          вҶ’ required form field\n#   status: str = Form(\"Pending\")     вҶ’ optional with default\n#   Used for HTML form submissions or curl -d. Cannot mix with Body().\n#\n#   BEGINNER EXAMPLE вҖ” Form():\n#\n#     @app.post(\"/login\")\n#     def login(username: str = Form(...), password: str = Form(...)):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/login\" \\\n#     #        -d \"username=john&password=secret123\"\n#     #\n#     #   Form body: username=john&password=secret123\n#     #              в”Ӯ              в”Ӯ\n#     #              в–ј              в–ј\n#     #   Inside function:\n#     #     username вҶ’ \"john\"         вҶҗ from form field\n#     #     password вҶ’ \"secret123\"    вҶҗ from form field\n#     #\n#     #   Content-Type: application/x-www-form-urlencoded  (auto-set by curl -d)\n#     #   This is what HTML <form> sends by default\n#     #   CANNOT mix Form() with Body() in same endpoint!\n#\n# в”Җв”Җ File() вҖ” Reads uploaded files (multipart/form-data) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   file: UploadFile = File(...)              вҶ’ single file upload\n#   files: List[UploadFile] = File(...)       вҶ’ multiple file upload\n#   UploadFile provides: .filename, .content_type, .read(), .size\n#   Can mix with Form() but NOT with Body().\n#\n#   BEGINNER EXAMPLE вҖ” File():\n#\n#     @app.post(\"/upload\")\n#     def upload(file: UploadFile = File(...), description: str = Form(\"none\")):\n#         ...\n#\n#     # How to call (single file):\n#     #   curl -X POST \"http://localhost:8000/upload\" \\\n#     #        -F \"file=@report.pdf\" \\\n#     #        -F \"description=Q1 Report\"\n#     #\n#     #   Multipart body:\n#     #     file=@report.pdf            вҶҗ file upload\n#     #     description=Q1 Report       вҶҗ form field alongside file\n#     #        в”Ӯ             в”Ӯ\n#     #        в–ј             в–ј\n#     #   Inside function:\n#     #     file.filename     вҶ’ \"report.pdf\"\n#     #     file.content_type вҶ’ \"application/pdf\"\n#     #     file.size         вҶ’ 102400 (bytes)\n#     #     await file.read() вҶ’ b\"...\" (file bytes)\n#     #     description       вҶ’ \"Q1 Report\"\n#     #\n#     #   Multiple files:\n#     #   curl -X POST \"/upload-multi\" -F \"files=@a.pdf\" -F \"files=@b.pdf\"\n#     #     files вҶ’ [UploadFile(\"a.pdf\"), UploadFile(\"b.pdf\")]\n#     #   -F flag = --form = multipart/form-data\n#     #   CAN mix File() + Form()  |  CANNOT mix File() + Body()\n#\n# в”Җв”Җ Depends() вҖ” Dependency injection (see session.py) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   user: dict = Depends(get_current_user)    вҶ’ runs function, injects result\n#   db: Session = Depends(get_db)             вҶ’ DB session injection\n#   Runs BEFORE the route handler. If dependency raises, route is skipped.\n#   Can chain: dependencies can have their own Depends().\n#   Can also go on decorator: @app.get(\"/x\", dependencies=[Depends(verify)])\n#\n#   BEGINNER EXAMPLE вҖ” Depends():\n#\n#     # Step 1: Define a dependency function\n#     def pagination_params(page: int = Query(1, ge=1), size: int = Query(10, ge=1, le=100)):\n#         return {\"page\": page, \"size\": size, \"skip\": (page - 1) * size}\n#\n#     # Step 2: Use it in a route\n#     @app.get(\"/items\")\n#     def list_items(pagination: dict = Depends(pagination_params)):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/items?page=2&size=20\"\n#     #\n#     #   URL:  /items?page=2&size=20\n#     #                в”Ӯ        в”Ӯ\n#     #                в–ј        в–ј\n#     #   Depends() runs pagination_params(page=2, size=20) FIRST\n#     #     returns вҶ’ {\"page\": 2, \"size\": 20, \"skip\": 20}\n#     #                              в”Ӯ\n#     #                              в–ј\n#     #   Inside route function:\n#     #     pagination вҶ’ {\"page\": 2, \"size\": 20, \"skip\": 20}  вҶҗ injected result\n#     #\n#     #   curl \"http://localhost:8000/items\"  вҶ’ page=1, size=10 (defaults)\n#     #   The route itself has NO query params вҖ” Depends() handles them!\n#\n#     # Auth dependency (chain):\n#     #   @app.get(\"/profile\")\n#     #   def profile(user: dict = Depends(get_current_user)):\n#     #\n#     #   curl \"http://localhost:8000/profile\" -H \"Authorization: Bearer <token>\"\n#     #     Depends(get_current_user) вҶ’ extracts token вҶ’ verifies вҶ’ returns user dict\n#     #     If token invalid вҶ’ raises HTTPException(401) вҶ’ route NEVER runs\n#\n# в”Җв”Җ ... (Ellipsis) vs None vs value в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   = Query(...)          вҶ’ REQUIRED вҖ” request fails 422 without it\n#   = Query(None)         вҶ’ OPTIONAL вҖ” defaults to None\n#   = Query(\"default\")    вҶ’ OPTIONAL вҖ” defaults to \"default\"\n#   = Query()             вҶ’ OPTIONAL вҖ” same as Query(None) for most types\n#\n#   BEGINNER EXAMPLE вҖ” Ellipsis (...) vs None vs default:\n#\n#     @app.get(\"/demo\")\n#     def demo(\n#         a: str = Query(...),           # required\n#         b: str = Query(None),          # optional, default None\n#         c: str = Query(\"hello\"),       # optional, default \"hello\"\n#     ):\n#         ...\n#\n#     # curl \"http://localhost:8000/demo?a=foo\"\n#     #   a вҶ’ \"foo\"     вҶҗ provided\n#     #   b вҶ’ None      вҶҗ not provided вҶ’ default None\n#     #   c вҶ’ \"hello\"   вҶҗ not provided вҶ’ default \"hello\"\n#     #\n#     # curl \"http://localhost:8000/demo?a=foo&b=bar&c=world\"\n#     #   a вҶ’ \"foo\"     вҶҗ provided\n#     #   b вҶ’ \"bar\"     вҶҗ provided (overrides None)\n#     #   c вҶ’ \"world\"   вҶҗ provided (overrides \"hello\")\n#     #\n#     # curl \"http://localhost:8000/demo\"\n#     #   вҶ’ 422 ERROR! \"a\" is required (...) and not provided\n#     #\n#     # COMPARISON:\n#     #   ...       вҶ’ \"MUST send this\"    вҶ’ 422 if missing\n#     #   None      вҶ’ \"send if you want\"  вҶ’ None if missing\n#     #   \"default\" вҶ’ \"send if you want\"  вҶ’ \"default\" if missing\n#     #   ()        вҶ’ same as None        вҶ’ None if missing\n#\n# в”Җв”Җ Annotated[] style (modern, see routes.py) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   Old: id: int = Path(gt=0)\n#   New: id: Annotated[int, Path(gt=0)]\n#   Both are equivalent. Annotated separates type hint from FastAPI metadata,\n#   making it reusable and cleaner with type checkers. Recommended approach.\n#\n#   BEGINNER EXAMPLE вҖ” Annotated[] vs old style:\n#\n#     from typing import Annotated\n#\n#     # Old style (still works):\n#     @app.get(\"/old/{id}\")\n#     def old_style(id: int = Path(gt=0), q: str = Query(\"default\")):\n#         ...\n#\n#     # New style (recommended):\n#     @app.get(\"/new/{id}\")\n#     def new_style(id: Annotated[int, Path(gt=0)], q: Annotated[str, Query()] = \"default\"):\n#         ...\n#\n#     # Both called EXACTLY the same way:\n#     #   curl \"http://localhost:8000/old/42?q=test\"\n#     #   curl \"http://localhost:8000/new/42?q=test\"\n#     #     id вҶ’ 42, q вҶ’ \"test\"\n#     #\n#     # Reusable type aliases:\n#     #   PositiveInt = Annotated[int, Path(gt=0)]\n#     #   @app.get(\"/a/{id}\")\n#     #   def route_a(id: PositiveInt): ...    вҶҗ reuse same validation\n#     #   @app.get(\"/b/{id}\")\n#     #   def route_b(id: PositiveInt): ...    вҶҗ no duplication\n#\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ"}, "lifespan.py": {"content": "# Merged into session.py -- see sections 1-2 for lifespan patterns", "cheatSheet": "", "reference": ""}, "middleware-cors-caching.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# 4. MIDDLEWARE, CORS & CACHING\n#\n# Middleware = code that runs BEFORE and AFTER every request\n# Request -> MW1 -> MW2 -> Endpoint -> MW2 -> MW1 -> Response (onion model)\n# CORS = which websites can call your API from a browser\n# Caching = store responses to avoid recomputing\n# NOTE: Middleware functions MUST be async def; endpoints can be sync\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\nimport time, hashlib, json\nfrom fastapi import FastAPI, HTTPException, Request, Response\nfrom fastapi.middleware.cors import CORSMiddleware\nfrom fastapi.middleware.trustedhost import TrustedHostMiddleware\nfrom fastapi.middleware.gzip import GZipMiddleware\nfrom fastapi.responses import JSONResponse\n\napp = FastAPI()\nshipment_data = {\n    1: {\"id\": 1, \"content\": \"Shipment 1\", \"weight\": 10, \"status\": \"In Transit\"},\n    2: {\"id\": 2, \"content\": \"Shipment 2\", \"weight\": 20, \"status\": \"Delivered\"},\n    3: {\"id\": 3, \"content\": \"Shipment 3\", \"weight\": 15, \"status\": \"Pending\"},\n}\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘              BEGINNER                            в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. CORS вҖ” Allow Frontend to Call Your API в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Without CORS: browser blocks requests from different origins\n# allow_origins = which sites | allow_methods = which HTTP verbs\n# allow_headers = which headers | allow_credentials = cookies/auth\n\n# OPTION A: Specific origins (RECOMMENDED for prod)\napp.add_middleware(\n    CORSMiddleware,\n    allow_origins=[\"http://localhost:3000\", \"http://localhost:5173\", \"https://myapp.example.com\"],\n    allow_credentials=True,                                        # allow cookies/JWT\n    allow_methods=[\"GET\", \"POST\", \"PUT\", \"DELETE\", \"PATCH\"],\n    allow_headers=[\"*\"],\n)\n# OPTION B: allow_origins=[\"*\"], allow_credentials=False           вҖ” any site, dev/public APIs only\n# OPTION C: allow_origin_regex=r\"https://.*\\.example\\.com\"         вҖ” regex pattern matching\n\n@app.get(\"/cors/test\")\ndef cors_test():\n    return {\"message\": \"If CORS is set up, your frontend can call this\"}\n\n# в”Җв”Җ 2. GZip вҖ” Compress Responses в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Compresses responses > minimum_size bytes (60-90% smaller for JSON)\napp.add_middleware(GZipMiddleware, minimum_size=500)\n\n@app.get(\"/middleware/gzip-test\")\ndef gzip_test():\n    return {\"data\": [shipment_data[k] for k in shipment_data] * 50}\n# curl -H \"Accept-Encoding: gzip\" http://localhost:8000/middleware/gzip-test\n\n# в”Җв”Җ 3. TrustedHost вҖ” Block Unknown Hosts в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Prevents Host header attacks; non-matching Host -> 400\napp.add_middleware(\n    TrustedHostMiddleware,\n    allowed_hosts=[\"localhost\", \"127.0.0.1\", \"myapp.example.com\", \"*.example.com\"],\n)\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘            INTERMEDIATE                          в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 4. Custom Middleware вҖ” Process Time Header в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# request = incoming | call_next = calls next middleware/endpoint | response = result\n@app.middleware(\"http\")\nasync def add_process_time_header(request: Request, call_next):\n    start = time.time()\n    response = await call_next(request)\n    response.headers[\"X-Process-Time\"] = str(round(time.time() - start, 4))\n    return response  # curl -v ... -> X-Process-Time: 0.0012\n\n# в”Җв”Җ 5. Custom Middleware вҖ” Request Logging в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.middleware(\"http\")\nasync def log_requests(request: Request, call_next):\n    print(f\"-> {request.method} {request.url.path}\")\n    response = await call_next(request)\n    print(f\"<- {request.method} {request.url.path} -> {response.status_code}\")\n    return response\n\n# в”Җв”Җ 6. Custom Middleware вҖ” Block Paths в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Deny access to /admin/* without correct token\n@app.middleware(\"http\")\nasync def block_admin_routes(request: Request, call_next):\n    if request.url.path.startswith(\"/admin\"):\n        if request.headers.get(\"Authorization\", \"\") != \"Bearer admin-secret-token\":\n            return JSONResponse(status_code=403, content={\"detail\": \"Admin access denied\"})\n    return await call_next(request)\n\n@app.get(\"/admin/dashboard\")\ndef admin_dashboard():\n    return {\"message\": \"Welcome to admin dashboard\"}\n\n# в”Җв”Җ 7. Custom Middleware вҖ” Rate Limiting в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Track requests per IP, block if too many in window\nrequest_counts: dict[str, list[float]] = {}\nRATE_LIMIT = 10    # max requests\nRATE_WINDOW = 60.0 # per N seconds\n\n@app.middleware(\"http\")\nasync def rate_limiter(request: Request, call_next):\n    client_ip = request.client.host if request.client else \"unknown\"\n    now = time.time()\n    if client_ip not in request_counts:\n        request_counts[client_ip] = []\n    request_counts[client_ip] = [t for t in request_counts[client_ip] if now - t < RATE_WINDOW]\n    if len(request_counts[client_ip]) >= RATE_LIMIT:\n        return JSONResponse(status_code=429, content={\"detail\": \"Too many requests\"})\n    request_counts[client_ip].append(now)\n    response = await call_next(request)\n    response.headers[\"X-RateLimit-Remaining\"] = str(RATE_LIMIT - len(request_counts[client_ip]))\n    return response\n\n# в”Җв”Җ 8. Custom Middleware вҖ” Exception Handler в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Catch ALL unhandled exceptions -> clean JSON instead of ugly 500 HTML\n@app.middleware(\"http\")\nasync def catch_exceptions(request: Request, call_next):\n    try:\n        return await call_next(request)\n    except Exception as e:\n        return JSONResponse(status_code=500, content={\"detail\": \"Internal server error\", \"error\": str(e)})\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘              ADVANCED                            в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 9. Middleware Execution Order в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Middleware runs in REVERSE order of registration!\n# Added: A, B, C  ->  Execution: C -> B -> A -> endpoint -> A -> B -> C\n# Last added = outermost layer (runs first)\n\n@app.get(\"/middleware/order-test\")\ndef middleware_order_test():\n    return {\"message\": \"Check server logs to see middleware execution order\"}\n\n# в”Җв”Җ 10. In-Memory Cache (Server-Side) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Dict cache with TTL вҖ” fastest, but lost on restart\ncache_store: dict[str, dict] = {}\nCACHE_TTL = 30  # seconds\n\n@app.get(\"/cache/simple/{id}\")\ndef get_with_simple_cache(id: int):\n    cache_key, now = f\"shipment:{id}\", time.time()\n    if cache_key in cache_store:                                   # check cache\n        cached = cache_store[cache_key]\n        if now - cached[\"timestamp\"] < CACHE_TTL:\n            return {**cached[\"data\"], \"_cache\": \"HIT\", \"_age\": round(now - cached[\"timestamp\"], 1)}\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    result = shipment_data[id]\n    cache_store[cache_key] = {\"data\": result, \"timestamp\": now}    # store in cache\n    return {**result, \"_cache\": \"MISS\"}\n\n# в”Җв”Җ 11. Cache Invalidation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Delete cache when data changes (PUT/DELETE) to prevent stale data\n@app.put(\"/cache/shipment/{id}\")\ndef update_shipment_and_invalidate(id: int, status: str = \"Updated\"):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    shipment_data[id][\"status\"] = status\n    cache_store.pop(f\"shipment:{id}\", None)                        # invalidate\n    return {\"updated\": shipment_data[id], \"cache_invalidated\": True}\n\n@app.delete(\"/cache/clear\")\ndef clear_all_cache():\n    cache_store.clear()\n    return {\"message\": \"All cache cleared\"}\n\n# в”Җв”Җ 12. HTTP Cache Headers (Client-Side) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Cache-Control tells browsers/CDNs to cache; ETag = data fingerprint\n# Client-side caching (browser stores it) vs server-side (dict cache above)\n@app.get(\"/cache/headers/{id}\")\ndef get_with_cache_headers(id: int):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    data = shipment_data[id]\n    content = json.dumps(data, sort_keys=True)\n    etag = hashlib.md5(content.encode()).hexdigest()\n    return Response(\n        content=content, media_type=\"application/json\",\n        headers={\"Cache-Control\": \"public, max-age=60\", \"ETag\": f'\"{etag}\"'},\n    )\n\n# Cache-Control variants:\n# no-store                             -> never cache (real-time data, auth tokens)\n# private, max-age=300                 -> only browser caches, NOT CDN (user-specific)\n# public, max-age=60                   -> browser AND CDN can cache (public data)\n# public, max-age=31536000, immutable  -> content NEVER changes at this URL (versioned assets)\n\n# в”Җв”Җ 13. Conditional Caching вҖ” ETag + If-None-Match в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Client sends ETag back -> server checks if data changed\n# Unchanged -> 304 Not Modified (no body, saves bandwidth)\n# Changed -> 200 with new data + new ETag\n@app.get(\"/cache/conditional/{id}\")\ndef conditional_cache(id: int, request: Request):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    data = shipment_data[id]\n    content = json.dumps(data, sort_keys=True)\n    etag = hashlib.md5(content.encode()).hexdigest()\n    if request.headers.get(\"If-None-Match\", \"\") == f'\"{etag}\"':    # client already has this version\n        return Response(status_code=304)\n    return Response(\n        content=content, media_type=\"application/json\",\n        headers={\"ETag\": f'\"{etag}\"', \"Cache-Control\": \"public, max-age=60\"},\n    )\n# 1st call: curl -v /cache/conditional/1                          -> 200 + ETag\n# 2nd call: curl -v -H 'If-None-Match: \"<etag>\"' /cache/cond/1   -> 304 (no body)", "cheatSheet": "# в”Җв”Җ CHEAT SHEET в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# CORS:\n#   Specific origins (prod)   | allow_origins=[\"https://app.com\"]\n#   All origins (dev only)    | allow_origins=[\"*\"], allow_credentials=False\n#   Regex pattern             | allow_origin_regex=r\"https://.*\\.example\\.com\"\n#\n# BUILT-IN MIDDLEWARE:\n#   GZipMiddleware            | Compress responses > N bytes\n#   TrustedHostMiddleware     | Block unknown Host headers\n#\n# CUSTOM MIDDLEWARE PATTERN:\n#   @app.middleware(\"http\")\n#   async def mw(request: Request, call_next):\n#       response = await call_next(request)    # call next layer\n#       return response\n#\n# EXECUTION ORDER:\n#   Added A, B, C -> runs C -> B -> A -> endpoint -> A -> B -> C\n#\n# CACHING COMPARISON:\n#   In-memory dict            | Server-side, fast, lost on restart\n#   Cache-Control header      | Client-side, browser/CDN stores it\n#   ETag + If-None-Match      | Conditional: 304 if unchanged, saves bandwidth\n#\n# CACHE-CONTROL VALUES:\n#   no-store                  | Never cache (real-time, auth)\n#   private, max-age=N        | Browser only, no CDN (user data)\n#   public, max-age=N         | Browser + CDN (public data)\n#   immutable                 | Content never changes (versioned assets)\n#\n# RATE LIMITING:             Track timestamps per IP, prune old, reject if >= limit\n# EXCEPTION MIDDLEWARE:      try/except around call_next -> clean JSON 500\n#", "reference": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  MIDDLEWARE, CORS & CACHING вҖ” DETAILED REFERENCE\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n# в”Җв”Җ CORSMiddleware вҖ” Cross-Origin Resource Sharing в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   app.add_middleware(CORSMiddleware, allow_origins=[...], ...)\n#   allow_origins=[\"http://localhost:3000\"]   вҶ’ specific origins (RECOMMENDED for prod)\n#   allow_origins=[\"*\"]                       вҶ’ any site (dev/public APIs only)\n#   allow_origin_regex=r\"https://.*\\.example\\.com\"  вҶ’ regex pattern\n#   allow_credentials=True                    вҶ’ allow cookies/JWT in cross-origin requests\n#   allow_methods=[\"GET\",\"POST\",...]          вҶ’ which HTTP verbs are allowed\n#   allow_headers=[\"*\"]                       вҶ’ which request headers are allowed\n#   Without CORS: browser blocks requests from different origins (same-origin policy)\n#\n#   BEGINNER EXAMPLE вҖ” CORSMiddleware:\n#\n#     from fastapi.middleware.cors import CORSMiddleware\n#     app.add_middleware(\n#         CORSMiddleware,\n#         allow_origins=[\"http://localhost:3000\"],  # вҶҗ React dev server\n#         allow_credentials=True,\n#         allow_methods=[\"*\"],\n#         allow_headers=[\"*\"],\n#     )\n#\n#     # Problem CORS solves:\n#     #   React app at http://localhost:3000 calls API at http://localhost:8000\n#     #   Browser sees DIFFERENT origins (different ports) вҶ’ blocks the request!\n#     #\n#     #   With CORSMiddleware:\n#     #   Browser вҶ’ OPTIONS /api/items (preflight check)\n#     #         вҶҗ Access-Control-Allow-Origin: http://localhost:3000  вң“\n#     #   Browser вҶ’ GET /api/items (actual request, now allowed)\n#     #         вҶҗ data + CORS headers\n#     #\n#     #   allow_origins=[\"*\"]  вҶ’ any website can call your API (ok for public APIs)\n#     #   allow_origins=[\"http://localhost:3000\"] вҶ’ only React app can call (safer)\n#\n# в”Җв”Җ GZipMiddleware вҖ” Response compression в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   app.add_middleware(GZipMiddleware, minimum_size=500)\n#   Compresses responses > minimum_size bytes. 60-90% smaller for JSON.\n#   Client must send Accept-Encoding: gzip header.\n#\n#   BEGINNER EXAMPLE вҖ” GZipMiddleware:\n#\n#     from starlette.middleware.gzip import GZipMiddleware\n#     app.add_middleware(GZipMiddleware, minimum_size=500)\n#\n#     # curl -H \"Accept-Encoding: gzip\" \"http://localhost:8000/big-data\"\n#     #\n#     #   Without GZip:\n#     #     Server вҶ’ 10,000 bytes JSON вҶ’ Client\n#     #\n#     #   With GZip:\n#     #     Server вҶ’ compress вҶ’ 2,000 bytes вҶ’ Client вҶ’ decompress вҶ’ 10,000 bytes\n#     #     (60-90% smaller, faster over slow networks)\n#     #\n#     #   minimum_size=500 вҶ’ only compress responses > 500 bytes\n#     #   (small responses: compression overhead > savings)\n#\n# в”Җв”Җ TrustedHostMiddleware вҖ” Host header protection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   app.add_middleware(TrustedHostMiddleware, allowed_hosts=[\"myapp.com\", \"*.example.com\"])\n#   Requests with non-matching Host header вҶ’ 400 Bad Request.\n#   Prevents Host header injection attacks.\n#\n#   BEGINNER EXAMPLE вҖ” TrustedHostMiddleware:\n#\n#     from starlette.middleware.trustedhost import TrustedHostMiddleware\n#     app.add_middleware(TrustedHostMiddleware, allowed_hosts=[\"myapp.com\", \"*.myapp.com\"])\n#\n#     # curl -H \"Host: myapp.com\" \"http://localhost:8000/\"    вҶ’ вң“ 200 OK\n#     # curl -H \"Host: evil.com\"  \"http://localhost:8000/\"    вҶ’ вң— 400 Bad Request\n#     #\n#     # Prevents: attacker sends fake Host header to trick server\n#     # into generating links/redirects to evil.com\n#\n# в”Җв”Җ Custom middleware pattern в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   @app.middleware(\"http\")\n#   async def my_middleware(request: Request, call_next):\n#       # BEFORE: runs before endpoint\n#       response = await call_next(request)  вҶ’ calls next middleware/endpoint\n#       # AFTER: runs after endpoint\n#       return response\n#   Must be async def. Can modify request before, response after.\n#   Can short-circuit: return JSONResponse(...) without calling call_next.\n#\n#   BEGINNER EXAMPLE вҖ” Custom middleware:\n#\n#     import time\n#\n#     @app.middleware(\"http\")\n#     async def add_timing(request: Request, call_next):\n#         start = time.time()                    # BEFORE endpoint\n#         response = await call_next(request)    # run endpoint\n#         elapsed = time.time() - start          # AFTER endpoint\n#         response.headers[\"X-Process-Time\"] = str(elapsed)\n#         return response\n#\n#     # curl -v \"http://localhost:8000/any-route\"\n#     #\n#     #   Request arrives\n#     #     в”Ӯ\n#     #     в–ј BEFORE: start = time.time()\n#     #     в”Ӯ\n#     #     в–ј call_next(request) вҶ’ endpoint runs вҶ’ returns response\n#     #     в”Ӯ\n#     #     в–ј AFTER: calculate elapsed, add header\n#     #     в”Ӯ\n#     #   Response sent with X-Process-Time: 0.0023\n#     #\n#     #   Short-circuit (skip endpoint):\n#     #     if \"Authorization\" not in request.headers:\n#     #         return JSONResponse({\"error\": \"No auth\"}, status_code=401)\n#\n# в”Җв”Җ Middleware execution order в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   Registered: A, B, C вҶ’ Runs: C вҶ’ B вҶ’ A вҶ’ endpoint вҶ’ A вҶ’ B вҶ’ C\n#   Last added = outermost layer (runs first). Like an onion вҖ” wraps around.\n#\n#   BEGINNER EXAMPLE вҖ” Execution order:\n#\n#     # Register order:\n#     app.add_middleware(A)   # added first\n#     app.add_middleware(B)   # added second\n#     app.add_middleware(C)   # added last\n#\n#     # Execution order (REVERSED вҖ” like wrapping an onion):\n#     #   Request comes in:\n#     #     C (before) вҶ’ B (before) вҶ’ A (before) вҶ’ ENDPOINT\n#     #   Response goes out:\n#     #     A (after)  вҶ’ B (after)  вҶ’ C (after)  вҶ’ CLIENT\n#     #\n#     #   Visual:\n#     #     в”Ңв”Җв”Җв”Җ C в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ\n#     #     в”Ӯ в”Ңв”Җв”Җв”Җ B в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ   в”Ӯ\n#     #     в”Ӯ в”Ӯ в”Ңв”Җв”Җв”Җ A в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ   в”Ӯ   в”Ӯ\n#     #     в”Ӯ в”Ӯ в”Ӯ       ENDPOINT           в”Ӯ   в”Ӯ   в”Ӯ\n#     #     в”Ӯ в”Ӯ в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ   в”Ӯ   в”Ӯ\n#     #     в”Ӯ в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ   в”Ӯ\n#     #     в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ\n#     #   Last added (C) wraps outermost вҶ’ runs FIRST on request, LAST on response\n#\n# в”Җв”Җ request: Request вҖ” Available in middleware & routes в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   request.url.path          вҶ’ \"/api/items\"\n#   request.method            вҶ’ \"GET\", \"POST\", etc.\n#   request.headers           вҶ’ all HTTP headers\n#   request.client.host       вҶ’ client IP address\n#   request.cookies           вҶ’ all cookies\n#   request.query_params      вҶ’ URL query parameters\n#\n#   BEGINNER EXAMPLE вҖ” Request object:\n#\n#     from fastapi import Request\n#\n#     @app.get(\"/debug\")\n#     async def debug(request: Request):\n#         return {\n#             \"path\": request.url.path,            # вҶ’ \"/debug\"\n#             \"method\": request.method,             # вҶ’ \"GET\"\n#             \"user_agent\": request.headers.get(\"user-agent\"),\n#             \"client_ip\": request.client.host,     # вҶ’ \"127.0.0.1\"\n#             \"cookies\": dict(request.cookies),     # вҶ’ {\"session_id\": \"abc\"}\n#             \"query\": dict(request.query_params),  # вҶ’ {\"page\": \"1\"}\n#         }\n#\n#     # curl \"http://localhost:8000/debug?page=1\" -b \"session_id=abc\"\n#     #   вҶ’ {\"path\":\"/debug\",\"method\":\"GET\",\"client_ip\":\"127.0.0.1\",\n#     #      \"cookies\":{\"session_id\":\"abc\"},\"query\":{\"page\":\"1\"}}\n#\n# в”Җв”Җ In-memory cache (server-side) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   cache_store[key] = {\"data\": result, \"timestamp\": time.time()}\n#   Check: if now - cached[\"timestamp\"] < TTL вҶ’ return cached (HIT)\n#   Invalidate: cache_store.pop(key, None) on PUT/DELETE (prevent stale data)\n#   Pros: fastest. Cons: lost on restart, per-process (not shared across workers).\n#\n#   BEGINNER EXAMPLE вҖ” In-memory cache:\n#\n#     import time\n#     cache = {}\n#     TTL = 60  # seconds\n#\n#     @app.get(\"/items\")\n#     async def get_items():\n#         now = time.time()\n#         if \"items\" in cache and now - cache[\"items\"][\"ts\"] < TTL:\n#             return {\"data\": cache[\"items\"][\"data\"], \"source\": \"cache\"}  # HIT\n#         data = await fetch_items_from_db()          # MISS вҖ” query DB\n#         cache[\"items\"] = {\"data\": data, \"ts\": now}  # store in cache\n#         return {\"data\": data, \"source\": \"db\"}\n#\n#     @app.delete(\"/items/{id}\")\n#     async def delete_item(id: int):\n#         await db_delete(id)\n#         cache.pop(\"items\", None)   # вҶҗ invalidate cache (prevent stale data)\n#         return {\"deleted\": id}\n#\n#     # Flow:\n#     #   curl GET /items      вҶ’ MISS вҶ’ query DB вҶ’ cache result вҶ’ return\n#     #   curl GET /items      вҶ’ HIT  вҶ’ return from cache (fast!)\n#     #   ... 60 seconds pass ...\n#     #   curl GET /items      вҶ’ MISS вҶ’ cache expired вҶ’ query DB again\n#     #   curl DELETE /items/1 вҶ’ delete + invalidate cache вҶ’ next GET re-fetches\n#\n# в”Җв”Җ Cache-Control header (client-side) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   \"no-store\"                           вҶ’ never cache (real-time data, auth tokens)\n#   \"private, max-age=300\"               вҶ’ browser only, NOT CDN (user-specific data)\n#   \"public, max-age=60\"                 вҶ’ browser + CDN can cache (public data)\n#   \"public, max-age=31536000, immutable\"вҶ’ never changes at this URL (versioned assets)\n#   Tells browser/CDN to store the response вҖ” server not contacted until expiry.\n#\n#   BEGINNER EXAMPLE вҖ” Cache-Control:\n#\n#     from fastapi.responses import JSONResponse\n#\n#     @app.get(\"/public-data\")\n#     async def public():\n#         data = get_public_data()\n#         return JSONResponse(data, headers={\"Cache-Control\": \"public, max-age=60\"})\n#\n#     @app.get(\"/user-profile\")\n#     async def profile():\n#         data = get_user_data()\n#         return JSONResponse(data, headers={\"Cache-Control\": \"private, max-age=300\"})\n#\n#     @app.get(\"/stock-price\")\n#     async def stock():\n#         data = get_live_price()\n#         return JSONResponse(data, headers={\"Cache-Control\": \"no-store\"})\n#\n#     # curl -v \"http://localhost:8000/public-data\"\n#     #   вҶҗ Cache-Control: public, max-age=60\n#     #\n#     #   What happens:\n#     #     \"no-store\"         вҶ’ browser NEVER caches (stock prices, auth tokens)\n#     #     \"private, 300\"     вҶ’ browser caches 5min, CDN does NOT (user-specific)\n#     #     \"public, 60\"       вҶ’ browser AND CDN cache 60s (shared public data)\n#     #     \"immutable\"        вҶ’ never changes at this URL (app.abc123.js)\n#     #\n#     #   Flow with \"public, max-age=60\":\n#     #     Request 1: Browser вҶ’ Server вҶ’ 200 + data (stored in browser cache)\n#     #     Request 2 (within 60s): Browser вҶ’ cache HIT вҶ’ no server contact!\n#     #     Request 3 (after 60s): Browser вҶ’ Server вҶ’ fresh 200\n#\n# в”Җв”Җ ETag + If-None-Match (conditional caching) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   Server: response with ETag: \"abc123\" (content fingerprint, usually MD5 hash)\n#   Client: next request with If-None-Match: \"abc123\"\n#   Server: data unchanged вҶ’ 304 Not Modified (no body, saves bandwidth)\n#   Server: data changed вҶ’ 200 with new data + new ETag\n#   Combines with Cache-Control for optimal caching strategy.\n#\n#   BEGINNER EXAMPLE вҖ” ETag:\n#\n#     import hashlib, json\n#     from fastapi import Response\n#\n#     @app.get(\"/article/{id}\")\n#     async def get_article(id: int, request: Request):\n#         article = get_article_from_db(id)\n#         etag = hashlib.md5(json.dumps(article).encode()).hexdigest()\n#\n#         if request.headers.get(\"if-none-match\") == etag:\n#             return Response(status_code=304)       # not modified вҖ” no body\n#\n#         return JSONResponse(article, headers={\"ETag\": etag})\n#\n#     # Flow:\n#     #   1st request:\n#     #     curl \"http://localhost:8000/article/1\"\n#     #       вҶҗ 200 + {\"title\":\"...\"} + ETag: \"abc123\"\n#     #       (browser stores response + ETag)\n#     #\n#     #   2nd request (data UNCHANGED):\n#     #     curl -H \"If-None-Match: abc123\" \"http://localhost:8000/article/1\"\n#     #       вҶҗ 304 Not Modified (NO BODY вҖ” saves bandwidth!)\n#     #       (browser uses stored version)\n#     #\n#     #   3rd request (data CHANGED вҖ” article was edited):\n#     #     curl -H \"If-None-Match: abc123\" \"http://localhost:8000/article/1\"\n#     #       вҶҗ 200 + {\"title\":\"new...\"} + ETag: \"xyz789\"\n#     #       (browser replaces stored version)\n#\n# в”Җв”Җ Rate limiting pattern в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   Track request timestamps per client IP in a dict.\n#   Prune timestamps older than RATE_WINDOW seconds.\n#   If count >= RATE_LIMIT вҶ’ return 429 Too Many Requests.\n#   Add X-RateLimit-Remaining header for client awareness.\n#\n#   BEGINNER EXAMPLE вҖ” Rate limiting:\n#\n#     import time\n#     from collections import defaultdict\n#\n#     RATE_LIMIT = 5       # max requests\n#     RATE_WINDOW = 60     # per 60 seconds\n#     request_log = defaultdict(list)\n#\n#     @app.middleware(\"http\")\n#     async def rate_limit(request: Request, call_next):\n#         ip = request.client.host\n#         now = time.time()\n#         request_log[ip] = [t for t in request_log[ip] if now - t < RATE_WINDOW]\n#\n#         if len(request_log[ip]) >= RATE_LIMIT:\n#             return JSONResponse(\n#                 {\"error\": \"Too many requests\"}, status_code=429,\n#                 headers={\"X-RateLimit-Remaining\": \"0\"}\n#             )\n#\n#         request_log[ip].append(now)\n#         remaining = RATE_LIMIT - len(request_log[ip])\n#         response = await call_next(request)\n#         response.headers[\"X-RateLimit-Remaining\"] = str(remaining)\n#         return response\n#\n#     # curl \"http://localhost:8000/anything\"  вҶ’ 200 (X-RateLimit-Remaining: 4)\n#     # curl \"http://localhost:8000/anything\"  вҶ’ 200 (X-RateLimit-Remaining: 3)\n#     # ... 3 more ...\n#     # curl \"http://localhost:8000/anything\"  вҶ’ 429 \"Too many requests\"\n#     #\n#     # After 60 seconds: old timestamps pruned вҶ’ can make requests again\n#\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ"}, "pydantic.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  FastAPI + Pydantic вҖ” Typed Models, Validation, Nested Data\n#  Run: uvicorn \"2. pydantic-example\":app --reload\n#\n#  NOTE: See 1.CRUD.py for raw dict CRUD patterns (path/query/body/\n#  header/cookie/form/file). This file covers Pydantic-only features.\n#\n#  dict = Body()        vs   BaseModel (Pydantic)\n#  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ        в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  No validation             Auto-validates all fields\n#  KeyError at runtime       422 error with clear message\n#  No docs in Swagger        Full schema in Swagger UI\n#  data[\"key\"]               data.key (dot access)\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\nfrom enum import Enum\nfrom fastapi import Body, FastAPI, HTTPException, Path, Query, status\nfrom pydantic import BaseModel, Field, field_validator, model_validator\nfrom typing import List, Optional\n\napp = FastAPI()\nshipment_data = {\n    1: {\"id\": 1, \"content\": \"Shipment 1 content\", \"weight\": 10, \"status\": \"In Transit\"},\n    2: {\"id\": 2, \"content\": \"Shipment 2 content\", \"weight\": 20, \"status\": \"Delivered\"},\n    3: {\"id\": 3, \"content\": \"Shipment 3 content\", \"weight\": 15, \"status\": \"Pending\"},\n}\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘              BEGINNER                            в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Basic BaseModel вҖ” auto validation + Swagger docs в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentCreate(BaseModel):\n    content: str                       # required вҖ” no default\n    weight: float                      # required вҖ” no default\n    status: str = \"Pending\"            # optional вҖ” has default\n\n@app.post(\"/shipment/pydantic\", status_code=status.HTTP_201_CREATED)\ndef create_with_pydantic(data: ShipmentCreate):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": data.content, \"weight\": data.weight, \"status\": data.status}\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/pydantic -H \"Content-Type: application/json\" -d '{\"content\":\"New\",\"weight\":30}'\n# Missing field -> 422: {\"detail\":[{\"loc\":[\"body\",\"weight\"],\"msg\":\"Field required\"}]}\n# Wrong type   -> 422: {\"detail\":[{\"loc\":[\"body\",\"weight\"],\"msg\":\"Input should be a valid number\"}]}\n\n# в”Җв”Җ 2. Field() Constraints вҖ” like Query()/Path() but for body в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentCreateValidated(BaseModel):\n    content: str = Field(min_length=3, max_length=200, description=\"3-200 chars\", examples=[\"Electronics from warehouse A\"])\n    weight: float = Field(gt=0, le=10000, description=\"Weight in kg (>0, max 10000)\", examples=[25.5])\n    status: str = Field(default=\"Pending\", examples=[\"Pending\", \"In Transit\", \"Delivered\"])\n\n@app.post(\"/shipment/pydantic-validated\", status_code=status.HTTP_201_CREATED)\ndef create_with_field_validation(data: ShipmentCreateValidated):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": data.content, \"weight\": data.weight, \"status\": data.status}\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/pydantic-validated -H \"Content-Type: application/json\" -d '{\"content\":\"Electronics\",\"weight\":25.5}'\n# content=\"AB\" -> 422: \"String should have at least 3 characters\"\n# weight=-5    -> 422: \"Input should be greater than 0\"\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘            INTERMEDIATE                          в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 3. Optional Fields вҖ” for PATCH/partial update в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentUpdate(BaseModel):\n    content: Optional[str] = None      # can be missing\n    weight: Optional[float] = None\n    status: Optional[str] = None\n\n@app.put(\"/shipment/pydantic/{id}\")\ndef update_with_pydantic(id: int, data: ShipmentUpdate):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    if data.content is not None:\n        shipment_data[id][\"content\"] = data.content\n    if data.weight is not None:\n        shipment_data[id][\"weight\"] = data.weight\n    if data.status is not None:\n        shipment_data[id][\"status\"] = data.status\n    return shipment_data[id]\n# curl -X PUT http://localhost:8000/shipment/pydantic/1 -H \"Content-Type: application/json\" -d '{\"status\":\"Delivered\"}'\n# Empty body {} -> nothing changes, returns current state\n\n# в”Җв”Җ 4. Enum Validation вҖ” restrict to allowed values в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentStatus(str, Enum):\n    PENDING = \"Pending\"\n    IN_TRANSIT = \"In Transit\"\n    DELIVERED = \"Delivered\"\n    CANCELLED = \"Cancelled\"\n\nclass ShipmentCreateWithEnum(BaseModel):\n    content: str\n    weight: float = Field(gt=0)\n    status: ShipmentStatus = ShipmentStatus.PENDING  # only 4 values allowed\n\n@app.post(\"/shipment/pydantic-enum\", status_code=status.HTTP_201_CREATED)\ndef create_with_enum(data: ShipmentCreateWithEnum):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": data.content, \"weight\": data.weight, \"status\": data.status.value}\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/pydantic-enum -H \"Content-Type: application/json\" -d '{\"content\":\"Test\",\"weight\":10,\"status\":\"In Transit\"}'\n# status=\"Lost\" -> 422: \"Input should be 'Pending', 'In Transit', 'Delivered' or 'Cancelled'\"\n\n# в”Җв”Җ 5. field_validator вҖ” custom validation logic в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentCreateCustomValidation(BaseModel):\n    content: str\n    weight: float\n    status: str = \"Pending\"\n\n    @field_validator(\"content\")\n    @classmethod\n    def content_not_empty(cls, v: str) -> str:\n        if v.strip() == \"\":\n            raise ValueError(\"Content cannot be empty or whitespace\")\n        return v.strip()  # auto-trim\n\n    @field_validator(\"weight\")\n    @classmethod\n    def weight_positive(cls, v: float) -> float:\n        if v <= 0:\n            raise ValueError(\"Weight must be > 0\")\n        if v > 50000:\n            raise ValueError(\"Weight cannot exceed 50000 kg\")\n        return round(v, 2)  # auto-round\n\n    @field_validator(\"status\")\n    @classmethod\n    def status_valid(cls, v: str) -> str:\n        allowed = [\"Pending\", \"In Transit\", \"Delivered\", \"Cancelled\"]\n        if v not in allowed:\n            raise ValueError(f\"Status must be one of: {allowed}\")\n        return v\n\n@app.post(\"/shipment/pydantic-custom\", status_code=status.HTTP_201_CREATED)\ndef create_with_custom_validation(data: ShipmentCreateCustomValidation):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\"id\": new_id, \"content\": data.content, \"weight\": data.weight, \"status\": data.status}\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/pydantic-custom -H \"Content-Type: application/json\" -d '{\"content\":\"  Electronics  \",\"weight\":25.666}'\n# -> content=\"Electronics\" (trimmed), weight=25.67 (rounded)\n# content=\"   \" -> 422: \"Content cannot be empty or whitespace\"\n\n# в”Җв”Җ 6. model_validator вҖ” cross-field validation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentCreateCrossField(BaseModel):\n    content: str\n    weight: float = Field(gt=0)\n    max_weight: float = Field(gt=0)\n    status: str = \"Pending\"\n\n    @model_validator(mode=\"after\")\n    def weight_must_not_exceed_max(self):\n        if self.weight > self.max_weight:\n            raise ValueError(f\"weight ({self.weight}) cannot exceed max_weight ({self.max_weight})\")\n        return self\n\n@app.post(\"/shipment/pydantic-cross\", status_code=status.HTTP_201_CREATED)\ndef create_with_cross_validation(data: ShipmentCreateCrossField):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\n        \"id\": new_id, \"content\": data.content, \"weight\": data.weight,\n        \"max_weight\": data.max_weight, \"status\": data.status,\n    }\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/pydantic-cross -H \"Content-Type: application/json\" -d '{\"content\":\"Test\",\"weight\":20,\"max_weight\":50}'\n# weight=100, max_weight=50 -> 422: \"weight (100.0) cannot exceed max_weight (50.0)\"\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘              ADVANCED                            в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 7. Nested Models вҖ” structured data в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Address(BaseModel):\n    street: str\n    city: str\n    country: str = \"US\"\n    zip_code: Optional[str] = None\n\nclass Dimensions(BaseModel):\n    length: float = Field(gt=0)\n    width: float = Field(gt=0)\n    height: float = Field(gt=0)\n\nclass ShipmentCreateNested(BaseModel):\n    content: str\n    weight: float = Field(gt=0)\n    origin: Address                           # required nested\n    destination: Address                      # required nested\n    dimensions: Optional[Dimensions] = None   # optional nested\n\n@app.post(\"/shipment/pydantic-nested\", status_code=status.HTTP_201_CREATED)\ndef create_with_nested(data: ShipmentCreateNested):\n    new_id = max(shipment_data.keys()) + 1\n    shipment_data[new_id] = {\n        \"id\": new_id, \"content\": data.content, \"weight\": data.weight,\n        \"origin\": data.origin.model_dump(),\n        \"destination\": data.destination.model_dump(),\n        \"dimensions\": data.dimensions.model_dump() if data.dimensions else None,\n        \"status\": \"Pending\",\n    }\n    return shipment_data[new_id]\n# curl -X POST http://localhost:8000/shipment/pydantic-nested -H \"Content-Type: application/json\" -d '{\"content\":\"Electronics\",\"weight\":25,\"origin\":{\"street\":\"123 Main\",\"city\":\"NYC\"},\"destination\":{\"street\":\"456 Oak\",\"city\":\"London\",\"country\":\"UK\"}}'\n# Missing nested field -> 422: origin.city \"Field required\"\n\n# в”Җв”Җ 8. List[Model] вҖ” batch create в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentItem(BaseModel):\n    content: str\n    weight: float = Field(gt=0)\n    status: str = \"Pending\"\n\n@app.post(\"/shipment/pydantic-batch\", status_code=status.HTTP_201_CREATED)\ndef create_batch(items: List[ShipmentItem]):\n    created = []\n    for item in items:\n        new_id = max(shipment_data.keys()) + 1\n        shipment_data[new_id] = {\"id\": new_id, \"content\": item.content, \"weight\": item.weight, \"status\": item.status}\n        created.append(shipment_data[new_id])\n    return {\"created\": len(created), \"shipments\": created}\n# curl -X POST http://localhost:8000/shipment/pydantic-batch -H \"Content-Type: application/json\" -d '[{\"content\":\"A\",\"weight\":10},{\"content\":\"B\",\"weight\":20}]'\n# One bad item fails entire batch: weight=-5 -> 422\n\n# в”Җв”Җ 9. response_model вҖ” control output shape в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentResponse(BaseModel):\n    id: int\n    content: str\n    weight: float\n    status: str\n\n@app.get(\"/shipment/pydantic-response/{id}\", response_model=ShipmentResponse)\ndef get_with_response_model(id: int):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    return shipment_data[id]  # extra fields stripped by response_model\n# curl http://localhost:8000/shipment/pydantic-response/1\n\n# в”Җв”Җ 10. PATH + QUERY + BODY all together в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ShipmentPatch(BaseModel):\n    content: Optional[str] = None\n    weight: Optional[float] = Field(None, gt=0)\n    status: Optional[str] = None\n\n@app.patch(\"/shipment/pydantic/{id}\")\ndef patch_with_pydantic(\n    id: int,                                                          # path\n    dry_run: bool = Query(False, description=\"Preview without saving\"),  # query\n    data: ShipmentPatch = Body(),                                     # body\n):\n    if id not in shipment_data:\n        raise HTTPException(status_code=404, detail=\"Not found\")\n    changes = {}\n    if data.content is not None:\n        changes[\"content\"] = data.content\n    if data.weight is not None:\n        changes[\"weight\"] = data.weight\n    if data.status is not None:\n        changes[\"status\"] = data.status\n    if not dry_run:\n        shipment_data[id].update(changes)\n    return {\"shipment\": shipment_data[id], \"changes_applied\": not dry_run, \"changes\": changes}\n# curl -X PATCH \"http://localhost:8000/shipment/pydantic/1\" -H \"Content-Type: application/json\" -d '{\"status\":\"Delivered\",\"weight\":50}'\n# curl -X PATCH \"http://localhost:8000/shipment/pydantic/1?dry_run=true\" -H \"Content-Type: application/json\" -d '{\"status\":\"Cancelled\"}'", "cheatSheet": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  CHEAT SHEET\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# FEATURE              | SYNTAX                                  | EFFECT\n# ---------------------|----------------------------------------|---------------------------\n# BaseModel            | class M(BaseModel): name: str          | Auto-validate + Swagger\n# Field() constraints  | Field(gt=0, max_length=200)            | Range/length checks\n# Optional field       | name: Optional[str] = None             | Can be missing (PATCH)\n# Default value        | status: str = \"Pending\"                | Fallback if omitted\n# Enum validation      | class S(str, Enum): A=\"a\"              | Restrict allowed values\n# field_validator      | @field_validator(\"name\")                | Custom per-field logic\n# model_validator      | @model_validator(mode=\"after\")          | Cross-field checks\n# Nested model         | address: Address                       | Deep validation\n# List[Model]          | items: List[Item]                      | Batch with per-item checks\n# response_model       | @app.get(..., response_model=M)        | Filter output fields\n# model_dump()         | data.model_dump()                      | Model -> dict\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#", "reference": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  PYDANTIC & FASTAPI DECLARATIONS вҖ” DETAILED REFERENCE\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n# в”Җв”Җ BaseModel вҖ” The core Pydantic model в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   class ShipmentCreate(BaseModel):\n#       content: str                   вҶ’ required, no default вҖ” request fails 422 without it\n#       weight: float                  вҶ’ required, auto-validates type (string \"abc\" вҶ’ 422)\n#       status: str = \"Pending\"        вҶ’ optional, uses default if omitted\n#   Usage: def create(data: ShipmentCreate)  вҶ’ FastAPI auto-reads from JSON body\n#   vs dict = Body(): BaseModel gives validation, dot access (data.content), Swagger schema\n#\n#   BEGINNER EXAMPLE вҖ” BaseModel:\n#\n#     class ShipmentCreate(BaseModel):\n#         content: str                     # required\n#         weight: float                    # required\n#         status: str = \"Pending\"          # optional, default \"Pending\"\n#\n#     @app.post(\"/shipment\")\n#     def create(data: ShipmentCreate):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/shipment\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"content\": \"Table\", \"weight\": 25.5}'\n#     #\n#     #   Body: {\"content\": \"Table\", \"weight\": 25.5}\n#     #          в”Ӯ                    в”Ӯ\n#     #          в–ј                    в–ј\n#     #   Inside function:\n#     #     data.content вҶ’ \"Table\"       вҶҗ from body (required)\n#     #     data.weight  вҶ’ 25.5          вҶҗ from body (required)\n#     #     data.status  вҶ’ \"Pending\"     вҶҗ NOT sent вҶ’ uses default\n#     #\n#     #   curl ... -d '{\"content\": \"Table\"}'           вҶ’ 422! weight is required\n#     #   curl ... -d '{\"content\": \"Table\", \"weight\": \"abc\"}'  вҶ’ 422! float expected\n#     #\n#     # vs dict = Body():\n#     #   BaseModel: data.content (dot access), auto-validation, Swagger schema\n#     #   dict:      data[\"content\"] (bracket access), no validation, no schema\n#\n# в”Җв”Җ Field() вҖ” Validation constraints for model fields в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   content: str = Field(min_length=3, max_length=200)   вҶ’ string length limits\n#   weight: float = Field(gt=0, le=10000)                вҶ’ numeric range (gt/ge/lt/le)\n#   status: str = Field(default=\"Pending\")               вҶ’ default value\n#   Field(description=\"...\", examples=[\"...\"])            вҶ’ OpenAPI docs metadata\n#   Field() is to BaseModel what Query()/Path() is to route parameters\n#\n#   BEGINNER EXAMPLE вҖ” Field():\n#\n#     class Item(BaseModel):\n#         content: str = Field(min_length=3, max_length=200)\n#         weight: float = Field(gt=0, le=10000)\n#\n#     @app.post(\"/item\")\n#     def create(data: Item):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/item\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"content\": \"Wooden Table\", \"weight\": 25.0}'\n#     #\n#     #   Body: {\"content\": \"Wooden Table\", \"weight\": 25.0}\n#     #          в”Ӯ                           в”Ӯ\n#     #          в–ј                           в–ј\n#     #   Inside function:\n#     #     data.content вҶ’ \"Wooden Table\"   вҶҗ valid (3-200 chars)\n#     #     data.weight  вҶ’ 25.0             вҶҗ valid (0 < 25 <= 10000)\n#     #\n#     #   curl ... -d '{\"content\": \"AB\", \"weight\": 5}'   вҶ’ 422! min_length=3 fails\n#     #   curl ... -d '{\"content\": \"OK\", \"weight\": -1}'  вҶ’ 422! gt=0 fails\n#     #   curl ... -d '{\"content\": \"OK\", \"weight\": 99999}' вҶ’ 422! le=10000 fails\n#\n# в”Җв”Җ Optional fields вҖ” For PATCH/partial updates в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   content: Optional[str] = None     вҶ’ field can be missing from request body\n#   Check with: if data.content is not None вҶ’ only update fields that were sent\n#   Use model_dump(exclude_unset=True) to get only fields explicitly provided\n#\n#   BEGINNER EXAMPLE вҖ” Optional fields (PATCH):\n#\n#     class ShipmentPatch(BaseModel):\n#         content: Optional[str] = None\n#         weight: Optional[float] = None\n#         status: Optional[str] = None\n#\n#     @app.patch(\"/shipment/{id}\")\n#     def update(id: int, data: ShipmentPatch):\n#         ...\n#\n#     # How to call (send only what changed):\n#     #   curl -X PATCH \"http://localhost:8000/shipment/1\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"status\": \"Delivered\"}'\n#     #\n#     #   Body: {\"status\": \"Delivered\"}     вҶҗ only status sent\n#     #          в”Ӯ\n#     #          в–ј\n#     #   Inside function:\n#     #     data.content вҶ’ None          вҶҗ not sent вҶ’ None (skip update)\n#     #     data.weight  вҶ’ None          вҶҗ not sent вҶ’ None (skip update)\n#     #     data.status  вҶ’ \"Delivered\"   вҶҗ sent вҶ’ update this field\n#     #\n#     #   curl ... -d '{}'    вҶ’ all fields None вҶ’ no changes (valid request)\n#     #   curl ... -d '{\"weight\": 50, \"content\": \"New\"}' вҶ’ updates 2 fields\n#\n# в”Җв”Җ Enum вҖ” Restrict to allowed values в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   class Status(str, Enum):          вҶ’ must inherit BOTH str and Enum\n#       PENDING = \"Pending\"\n#   Invalid value вҶ’ 422: \"Input should be 'Pending', 'In Transit', ...\"\n#   Access: data.status.value вҶ’ \"Pending\" (string), data.status вҶ’ Status.PENDING (enum)\n#\n#   BEGINNER EXAMPLE вҖ” Enum validation:\n#\n#     class Status(str, Enum):\n#         PENDING = \"Pending\"\n#         TRANSIT = \"In Transit\"\n#         DELIVERED = \"Delivered\"\n#\n#     class Shipment(BaseModel):\n#         content: str\n#         status: Status = Status.PENDING\n#\n#     @app.post(\"/shipment\")\n#     def create(data: Shipment):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/shipment\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"content\": \"Table\", \"status\": \"Delivered\"}'\n#     #\n#     #   Inside function:\n#     #     data.status       вҶ’ Status.DELIVERED   вҶҗ enum member\n#     #     data.status.value вҶ’ \"Delivered\"         вҶҗ string value\n#     #\n#     #   curl ... -d '{\"content\": \"Table\", \"status\": \"Lost\"}'\n#     #     вҶ’ 422! \"Input should be 'Pending', 'In Transit' or 'Delivered'\"\n#\n# в”Җв”Җ @field_validator вҖ” Custom per-field logic в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   @field_validator(\"content\")\n#   @classmethod\n#   def validate_content(cls, v: str) -> str:\n#       if not v.strip(): raise ValueError(\"Cannot be empty\")\n#       return v.strip()              вҶ’ can transform the value (trim, round, etc.)\n#   Runs after type validation. Raise ValueError for custom error messages.\n#\n#   BEGINNER EXAMPLE вҖ” @field_validator:\n#\n#     class Item(BaseModel):\n#         content: str\n#         weight: float\n#\n#         @field_validator(\"content\")\n#         @classmethod\n#         def validate_content(cls, v):\n#             if not v.strip(): raise ValueError(\"Cannot be empty/whitespace\")\n#             return v.strip().title()       # transforms: \"  wooden table  \" вҶ’ \"Wooden Table\"\n#\n#     # How to call:\n#     #   curl ... -d '{\"content\": \"  wooden table  \", \"weight\": 10}'\n#     #     data.content вҶ’ \"Wooden Table\"    вҶҗ stripped + title-cased by validator\n#     #\n#     #   curl ... -d '{\"content\": \"   \", \"weight\": 10}'\n#     #     вҶ’ 422! \"Cannot be empty/whitespace\" (custom error message)\n#\n# в”Җв”Җ @model_validator вҖ” Cross-field validation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   @model_validator(mode=\"after\")    вҶ’ runs after all field validators\n#   def check_fields(self):           вҶ’ has access to all fields via self.field_name\n#       if self.weight > self.max_weight: raise ValueError(...)\n#       return self                   вҶ’ must return self\n#   mode=\"before\" runs on raw dict before field parsing\n#\n#   BEGINNER EXAMPLE вҖ” @model_validator:\n#\n#     class DateRange(BaseModel):\n#         start_date: str\n#         end_date: str\n#\n#         @model_validator(mode=\"after\")\n#         def check_dates(self):\n#             if self.end_date < self.start_date:\n#                 raise ValueError(\"end_date must be after start_date\")\n#             return self\n#\n#     # How to call:\n#     #   curl ... -d '{\"start_date\": \"2024-01-01\", \"end_date\": \"2024-06-01\"}'\n#     #     вҶ’ valid (end > start)\n#     #\n#     #   curl ... -d '{\"start_date\": \"2024-06-01\", \"end_date\": \"2024-01-01\"}'\n#     #     вҶ’ 422! \"end_date must be after start_date\"\n#     #     (cross-field check вҖ” needs BOTH fields, so model_validator not field_validator)\n#\n# в”Җв”Җ Nested models вҖ” Deep structured validation в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   class Address(BaseModel):\n#       street: str; city: str\n#   class Shipment(BaseModel):\n#       origin: Address               вҶ’ required nested object\n#       dims: Optional[Dims] = None   вҶ’ optional nested object\n#   Validates recursively: missing origin.city вҶ’ 422 with path [\"body\",\"origin\",\"city\"]\n#   Convert to dict: data.origin.model_dump()\n#\n#   BEGINNER EXAMPLE вҖ” Nested models:\n#\n#     class Address(BaseModel):\n#         street: str\n#         city: str\n#         country: str = \"US\"\n#\n#     class Shipment(BaseModel):\n#         content: str\n#         origin: Address                  # required nested\n#         destination: Optional[Address] = None  # optional nested\n#\n#     @app.post(\"/shipment\")\n#     def create(data: Shipment):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/shipment\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\n#     #              \"content\": \"Electronics\",\n#     #              \"origin\": {\"street\": \"123 Main\", \"city\": \"NYC\"},\n#     #              \"destination\": {\"street\": \"456 Oak\", \"city\": \"London\", \"country\": \"UK\"}\n#     #            }'\n#     #\n#     #   Body structure:\n#     #     {\n#     #       \"content\": \"Electronics\",      вҶҗ data.content\n#     #       \"origin\": {                    вҶҗ data.origin (Address model)\n#     #         \"street\": \"123 Main\",            вҶҗ data.origin.street\n#     #         \"city\": \"NYC\"                    вҶҗ data.origin.city\n#     #                                          вҶҗ data.origin.country вҶ’ \"US\" (default)\n#     #       },\n#     #       \"destination\": {               вҶҗ data.destination (optional Address)\n#     #         \"street\": \"456 Oak\",\n#     #         \"city\": \"London\",\n#     #         \"country\": \"UK\"                  вҶҗ overrides default \"US\"\n#     #       }\n#     #     }\n#     #\n#     #   curl ... -d '{\"content\": \"X\", \"origin\": {\"street\": \"A\"}}'\n#     #     вҶ’ 422! origin.city is required вҖ” error path: [\"body\",\"origin\",\"city\"]\n#\n# в”Җв”Җ List[Model] вҖ” Batch operations в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   def create_batch(items: List[ShipmentItem]):\n#   Request body: [{\"content\":\"A\",\"weight\":10}, {\"content\":\"B\",\"weight\":20}]\n#   Each item validated individually. One bad item вҶ’ entire batch fails 422.\n#\n#   BEGINNER EXAMPLE вҖ” List[Model]:\n#\n#     class Item(BaseModel):\n#         content: str\n#         weight: float = Field(gt=0)\n#\n#     @app.post(\"/batch\")\n#     def create_batch(items: List[Item]):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/batch\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '[\n#     #              {\"content\": \"Table\", \"weight\": 25},\n#     #              {\"content\": \"Chair\", \"weight\": 10}\n#     #            ]'\n#     #\n#     #   Body: [ {...}, {...} ]       вҶҗ JSON array (NOT object!)\n#     #          в”Ӯ        в”Ӯ\n#     #          в–ј        в–ј\n#     #   Inside function:\n#     #     items[0].content вҶ’ \"Table\"     вҶҗ first item\n#     #     items[0].weight  вҶ’ 25\n#     #     items[1].content вҶ’ \"Chair\"     вҶҗ second item\n#     #     items[1].weight  вҶ’ 10\n#     #     len(items)       вҶ’ 2\n#     #\n#     #   curl ... -d '[{\"content\": \"A\", \"weight\": 5}, {\"content\": \"B\", \"weight\": -1}]'\n#     #     вҶ’ 422! items[1].weight must be > 0 вҖ” ONE bad item fails ENTIRE batch\n#\n# в”Җв”Җ response_model вҖ” Control output shape в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   @app.get(\"/item/{id}\", response_model=ItemResponse)\n#   Strips fields not in ItemResponse from the response (e.g., hides internal fields)\n#   Also generates response schema in Swagger docs\n#\n#   BEGINNER EXAMPLE вҖ” response_model:\n#\n#     class ShipmentResponse(BaseModel):\n#         id: int\n#         content: str\n#         status: str\n#         # NOTE: \"weight\" and \"internal_notes\" are NOT here вҖ” hidden from response\n#\n#     @app.get(\"/shipment/{id}\", response_model=ShipmentResponse)\n#     def get_shipment(id: int):\n#         return {\"id\": 1, \"content\": \"Table\", \"status\": \"Delivered\",\n#                 \"weight\": 25, \"internal_notes\": \"fragile\"}\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/shipment/1\"\n#     #\n#     #   What function returns (internal):\n#     #     {\"id\": 1, \"content\": \"Table\", \"status\": \"Delivered\",\n#     #      \"weight\": 25, \"internal_notes\": \"fragile\"}\n#     #\n#     #   What client receives (filtered by response_model):\n#     #     {\"id\": 1, \"content\": \"Table\", \"status\": \"Delivered\"}\n#     #      вҶ‘         вҶ‘                  вҶ‘\n#     #      in model   in model           in model\n#     #                     weight вҶ’ STRIPPED (not in ShipmentResponse)\n#     #                     internal_notes вҶ’ STRIPPED (not in ShipmentResponse)\n#\n# в”Җв”Җ model_dump() вҖ” Convert model to dict в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   data.model_dump()                 вҶ’ all fields as dict\n#   data.model_dump(exclude_unset=True)  вҶ’ only fields explicitly set (for PATCH)\n#   data.model_dump(exclude={\"password\"}) вҶ’ exclude specific fields\n#\n#   BEGINNER EXAMPLE вҖ” model_dump():\n#\n#     class Item(BaseModel):\n#         content: str\n#         weight: float\n#         status: str = \"Pending\"\n#\n#     data = Item(content=\"Table\", weight=25)\n#\n#     # data.model_dump()\n#     #   вҶ’ {\"content\": \"Table\", \"weight\": 25.0, \"status\": \"Pending\"}\n#     #      вҶҗ ALL fields including defaults\n#     #\n#     # data.model_dump(exclude_unset=True)\n#     #   вҶ’ {\"content\": \"Table\", \"weight\": 25.0}\n#     #      вҶҗ only fields EXPLICITLY SET (status was default, so excluded)\n#     #      вҶҗ useful for PATCH: only update what user actually sent\n#     #\n#     # data.model_dump(exclude={\"weight\"})\n#     #   вҶ’ {\"content\": \"Table\", \"status\": \"Pending\"}\n#     #      вҶҗ weight explicitly excluded\n#\n# в”Җв”Җ Body() + Query() + Path() with Pydantic в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   def patch(id: int, dry_run: bool = Query(False), data: Model = Body()):\n#   id вҶ’ from URL path (auto-detected)\n#   dry_run вҶ’ from query string (?dry_run=true)\n#   data вҶ’ from JSON body (Pydantic model)\n#   FastAPI can combine all three in one endpoint\n#\n#   BEGINNER EXAMPLE вҖ” Path + Query + Body combined:\n#\n#     @app.patch(\"/shipment/{id}\")\n#     def update(id: int, dry_run: bool = Query(False), data: ShipmentPatch = Body()):\n#         ...\n#\n#     # How to call:\n#     #   curl -X PATCH \"http://localhost:8000/shipment/42?dry_run=true\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"status\": \"Delivered\", \"weight\": 50}'\n#     #\n#     #   URL:  /shipment/42?dry_run=true\n#     #                   в”Ӯ         в”Ӯ\n#     #                   в–ј         в–ј\n#     #     id      вҶ’ 42        вҶҗ from URL path (auto: matches {id})\n#     #     dry_run вҶ’ True      вҶҗ from query string (?dry_run=true)\n#     #\n#     #   Body: {\"status\": \"Delivered\", \"weight\": 50}\n#     #          в”Ӯ                      в”Ӯ\n#     #          в–ј                      в–ј\n#     #     data.status вҶ’ \"Delivered\"   вҶҗ from JSON body\n#     #     data.weight вҶ’ 50            вҶҗ from JSON body\n#     #\n#     #   3 sources in 1 endpoint:\n#     #     Path  вҶ’ /shipment/{id}          вҶ’ id\n#     #     Query вҶ’ ?dry_run=true           вҶ’ dry_run\n#     #     Body  вҶ’ {\"status\": \"Delivered\"} вҶ’ data (Pydantic model)\n#\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ"}, "routes.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# FastAPI Routes вҖ” Condensed Reference\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# Run:  uv run uvicorn routes:app --reload\n# Docs: http://localhost:8000/docs\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\nfrom enum import Enum\nfrom typing import Annotated\nfrom fastapi import (\n    FastAPI, APIRouter, HTTPException, Query, Path, Body,\n    Header, Cookie, Form, File, UploadFile, Request, Response, Depends, status,\n)\nfrom fastapi.responses import (\n    JSONResponse, HTMLResponse, PlainTextResponse, RedirectResponse, StreamingResponse,\n)\nfrom pydantic import BaseModel, Field\n\napp = FastAPI(title=\"FastAPI Routes вҖ” All Approaches\")\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                   BEGINNER                       в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. HTTP Methods в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# GET=read  POST=create  PUT=replace  PATCH=partial-update  DELETE=remove\n# HEAD/OPTIONS also exist вҖ” rarely hand-written (FastAPI auto-generates OPTIONS)\n@app.get(\"/items\")\nasync def get_items():\n    return [{\"id\": 1, \"name\": \"Laptop\"}, {\"id\": 2, \"name\": \"Phone\"}]\n\n@app.post(\"/items\", status_code=status.HTTP_201_CREATED)  # 201 for creation\nasync def create_item():\n    return {\"id\": 3, \"name\": \"Tablet\", \"created\": True}\n\n@app.put(\"/items/{item_id}\")  # replace entire resource\nasync def replace_item(item_id: int):\n    return {\"id\": item_id, \"replaced\": True}\n\n@app.patch(\"/items/{item_id}\")  # partial update\nasync def update_item(item_id: int):\n    return {\"id\": item_id, \"updated\": True}\n\n@app.delete(\"/items/{item_id}\", status_code=status.HTTP_204_NO_CONTENT)  # no body\nasync def delete_item(item_id: int):\n    return None\n\n# в”Җв”Җ 2. Path Parameters в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Values from URL path. Type hint = auto-validation. /users/abc -> 422 error\n@app.get(\"/users/{user_id}\")  # simple вҖ” /users/42 -> user_id=42\nasync def get_user(user_id: int):\n    return {\"user_id\": user_id}\n\n@app.get(\"/orgs/{org_name}/teams/{team_name}\")  # multiple params\nasync def get_team(org_name: str, team_name: str):\n    return {\"org\": org_name, \"team\": team_name}\n\n@app.get(\"/products/{product_id}\")  # Path() вҖ” validation + docs\nasync def get_product(\n    product_id: Annotated[int, Path(title=\"Product ID\", ge=1, le=10000)],\n):\n    return {\"product_id\": product_id}\n\nclass ModelName(str, Enum):  # Enum вҖ” fixed choices (/models/random -> 422)\n    GPT4O = \"gpt-4o\"; CLAUDE = \"claude-sonnet\"; GEMINI = \"gemini-pro\"\n\n@app.get(\"/models/{model_name}\")\nasync def get_model(model_name: ModelName):\n    return {\"model\": model_name, \"value\": model_name.value}\n\n@app.get(\"/files/{file_path:path}\")  # catch-all вҖ” captures slashes\nasync def get_file(file_path: str):  # /files/docs/reports/q1.pdf -> \"docs/reports/q1.pdf\"\n    return {\"file_path\": file_path}\n\n# в”Җв”Җ 3. Query Parameters в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# From ?key=value. Any param NOT in path -> query param automatically.\n@app.get(\"/search\")  # default = optional, no default = required. /search -> 422 (q required)\nasync def search(q: str, page: int = 1, limit: int = 10):\n    return {\"query\": q, \"page\": page, \"limit\": limit}\n\n@app.get(\"/articles\")  # None default = truly optional\nasync def list_articles(tag: str | None = None):\n    return {\"articles\": f\"filtered by {tag}\" if tag else \"all\"}\n\n@app.get(\"/events\")  # Query() вҖ” validation, description, alias for hyphenated names\nasync def list_events(\n    start: Annotated[str, Query(description=\"Start date YYYY-MM-DD\")],\n    end: Annotated[str, Query(description=\"End date YYYY-MM-DD\")],\n    max_results: Annotated[int, Query(alias=\"max-results\", ge=1, le=100)] = 10,\n):\n    return {\"start\": start, \"end\": end, \"max_results\": max_results}\n\n@app.get(\"/filter\")  # list param вҖ” /filter?status=active&status=pending\nasync def filter_items(status: Annotated[list[str], Query()] = [\"active\"]):\n    return {\"statuses\": status}\n\n# в”Җв”Җ 4. Request Body (Pydantic) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# POST/PUT/PATCH send JSON body. Pydantic model = auto-validate + docs.\nclass OrderCreate(BaseModel):\n    product: str = Field(min_length=1, max_length=100)\n    quantity: int = Field(ge=1, le=1000)\n    price: float = Field(gt=0)\n    notes: str | None = None\n\nclass OrderResponse(BaseModel):\n    id: int\n    product: str\n    quantity: int\n    price: float\n    total: float\n\n@app.post(\"/orders\", response_model=OrderResponse, status_code=201)\nasync def create_order(order: OrderCreate):  # body model; add path param for PUT /orders/{id}\n    return OrderResponse(id=1, **order.model_dump(exclude={\"notes\"}),\n                         total=order.quantity * order.price)\n\nclass OrderUpdate(BaseModel):  # partial update вҖ” all fields optional\n    product: str | None = None\n    quantity: int | None = Field(default=None, ge=1)\n    price: float | None = Field(default=None, gt=0)\n\n@app.patch(\"/orders/{order_id}\")\nasync def partial_update_order(order_id: int, updates: OrderUpdate):\n    return {\"id\": order_id, \"updated_fields\": updates.model_dump(exclude_unset=True)}\n\n@app.post(\"/shipping\")  # multiple body params вҖ” Body(embed=True) nests under keys\nasync def create_shipping(  # body: {\"order\": {...}, \"address\": \"123 Main\", \"priority\": true}\n    order: OrderCreate,\n    address: Annotated[str, Body(embed=True)],\n    priority: Annotated[bool, Body(embed=True)] = False,\n):\n    return {\"order\": order.product, \"address\": address, \"priority\": priority}\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                 INTERMEDIATE                     в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 5. Headers / Cookies / Form / File в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/headers\")  # header names auto-convert: \"X-Request-ID\" -> x_request_id\nasync def read_headers(\n    user_agent: Annotated[str, Header()],\n    x_request_id: Annotated[str | None, Header()] = None,\n):\n    return {\"user_agent\": user_agent, \"request_id\": x_request_id}\n\n@app.get(\"/cookies\")\nasync def read_cookies(session_token: Annotated[str | None, Cookie()] = None):\n    return {\"session_token\": session_token}\n\n@app.post(\"/login\")  # Form data (not JSON) вҖ” curl -d \"username=john&password=secret\"\nasync def login_form(username: Annotated[str, Form()], password: Annotated[str, Form()]):\n    return {\"username\": username, \"logged_in\": True}\n\n@app.post(\"/upload\")  # file upload вҖ” curl -F \"file=@photo.jpg\"\nasync def upload_file(file: UploadFile = File(...)):\n    contents = await file.read()\n    return {\"filename\": file.filename, \"size_bytes\": len(contents)}\n\n@app.post(\"/upload-many\")  # multiple files\nasync def upload_files(files: list[UploadFile] = File(...)):\n    return [{\"filename\": f.filename, \"size\": f.size} for f in files]\n\n# в”Җв”Җ 6. Response Types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Default=JSON | HTMLResponse | PlainTextResponse | RedirectResponse | StreamingResponse\n@app.get(\"/response/json\")  # default вҖ” just return dict or Pydantic model\nasync def json_response():\n    return {\"format\": \"json\", \"auto\": True}  # JSONResponse(...) for custom status/headers\n\n@app.get(\"/response/html\", response_class=HTMLResponse)  # or PlainTextResponse for plain text\nasync def html_response():\n    return \"<h1>Hello from FastAPI</h1>\"\n\n@app.get(\"/response/text\", response_class=PlainTextResponse)\nasync def text_response():\n    return \"Just plain text, no JSON\"\n\n@app.get(\"/response/redirect\")  # 302 redirect\nasync def redirect_response():\n    return RedirectResponse(url=\"/items\", status_code=302)\n\n@app.get(\"/response/stream\")  # streaming for large data / SSE\nasync def streaming_response():\n    async def generate():\n        for i in range(5): yield f\"chunk {i}\\n\"\n    return StreamingResponse(generate(), media_type=\"text/plain\")\n\n@app.get(\"/response/set-cookie\")  # set cookie + custom headers via Response param\nasync def set_cookie_response(response: Response):\n    response.set_cookie(key=\"theme\", value=\"dark\", max_age=3600, httponly=True)\n    response.headers[\"X-Process-Time\"] = \"0.5s\"\n    return {\"message\": \"Cookie + header set\"}\n\n# в”Җв”Җ 7. Dependency Injection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Depends() injects reusable logic. Runs BEFORE route; exception = route skipped.\n\nasync def pagination_params(page: int = 1, limit: int = Query(default=10, le=100)):  # 7a. function dep\n    return {\"page\": page, \"limit\": limit, \"offset\": (page - 1) * limit}\n\n@app.get(\"/posts\")  # reuse same dep across many routes (/posts, /comments, etc.)\nasync def list_posts(pagination: dict = Depends(pagination_params)):\n    return {\"posts\": [], **pagination}\n\nasync def verify_api_key(x_api_key: Annotated[str, Header()]):  # 7b. auth dep\n    if x_api_key != \"secret-key-123\":\n        raise HTTPException(status_code=403, detail=\"Invalid API key\")\n    return x_api_key\n\n@app.get(\"/admin/dashboard\")\nasync def admin_dashboard(api_key: str = Depends(verify_api_key)):\n    return {\"dashboard\": \"admin data\", \"authenticated_with\": api_key}\n\nclass DBSession:  # 7c. yield dep вҖ” setup + cleanup\n    def __init__(self): self.connected = True\n    def query(self, table: str): return [{\"id\": 1, \"table\": table}]\n\nasync def get_db():\n    db = DBSession()\n    try: yield db                  # route uses db\n    finally: db.connected = False  # cleanup after route\n\n@app.get(\"/db-demo\")\nasync def db_demo(db: DBSession = Depends(get_db)):\n    return db.query(\"shipments\")\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                   ADVANCED                       в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 8. APIRouter вҖ” Organize Routes в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Like Flask blueprints. Production: routers/users.py, routers/orders.py, main.py includes them.\ncustomer_router = APIRouter(prefix=\"/api/v1/customers\", tags=[\"Customers\"])\n\n@customer_router.get(\"/\")\nasync def list_customers():\n    return [{\"id\": 1, \"name\": \"Acme Corp\"}]\n\n@customer_router.get(\"/{customer_id}\")\nasync def get_customer(customer_id: int):\n    return {\"id\": customer_id, \"name\": \"Acme Corp\"}\n\n@customer_router.post(\"/\", status_code=201)\nasync def create_customer(name: str = Body(embed=True)):\n    return {\"id\": 3, \"name\": name}\n\nprotected_router = APIRouter(  # shared deps вҖ” every route requires API key\n    prefix=\"/api/v1/reports\", tags=[\"Reports\"],\n    dependencies=[Depends(verify_api_key)],\n)\n\n@protected_router.get(\"/sales\")\nasync def sales_report():\n    return {\"report\": \"sales\", \"total\": 50000}\n\napp.include_router(customer_router)\napp.include_router(protected_router)\n\n# в”Җв”Җ 9. Raw Request Access в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/raw-request\")\nasync def raw_request(request: Request):\n    return {\"method\": request.method, \"url\": str(request.url),\n            \"query_params\": dict(request.query_params), \"headers\": dict(request.headers),\n            \"client_ip\": request.client.host if request.client else None}\n\n# в”Җв”Җ 10. Error Handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.get(\"/fail/{error_code}\")  # HTTPException вҖ” standard errors\nasync def fail(error_code: int):\n    if error_code == 404:\n        raise HTTPException(status_code=404, detail=\"Resource not found\")\n    if error_code == 403:\n        raise HTTPException(status_code=403, detail=\"Forbidden\", headers={\"X-Error\": \"No\"})\n    return {\"status\": \"ok\"}\n\nclass ShipmentNotFoundError(Exception):  # custom exception + handler\n    def __init__(self, shipment_id: int): self.shipment_id = shipment_id\n\n@app.exception_handler(ShipmentNotFoundError)\nasync def shipment_not_found_handler(request: Request, exc: ShipmentNotFoundError):\n    return JSONResponse(status_code=404,\n                        content={\"error\": \"shipment_not_found\", \"id\": exc.shipment_id})\n\n@app.get(\"/shipments-demo/{shipment_id}\")\nasync def get_shipment_demo(shipment_id: int):\n    if shipment_id > 100: raise ShipmentNotFoundError(shipment_id)\n    return {\"id\": shipment_id, \"status\": \"delivered\"}\n\n# в”Җв”Җ 11. Async vs Sync в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# async def = I/O-bound (await db/http) on event loop | def = CPU-bound, auto-threadpool\n@app.get(\"/async-demo\")\nasync def async_route(): return {\"type\": \"async\", \"blocks_event_loop\": False}  # use await inside\n\n@app.get(\"/sync-demo\")\ndef sync_route(): return {\"type\": \"sync\", \"runs_in\": \"threadpool\"}  # no await needed\n\n# в”Җв”Җ 12. api_route вҖ” Multiple Methods в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@app.api_route(\"/multi\", methods=[\"GET\", \"POST\"])\nasync def multi_method(request: Request):\n    return {\"action\": \"reading\" if request.method == \"GET\" else \"creating\"}", "cheatSheet": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# CHEAT SHEET\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# SOURCE      | DETECTION               | EXAMPLE\n# ------------|-------------------------|------------------------------------\n# Path param  | {name} in URL           | /users/{id} -> id: int\n# Query param | not in path, simple type| ?page=2 -> page: int = 1\n# Body        | Pydantic model hint     | order: OrderCreate\n# Header      | Header()                | x_tok: Annotated[str, Header()]\n# Cookie      | Cookie()                | sess: Annotated[str, Cookie()]\n# Form        | Form()                  | user: Annotated[str, Form()]\n# File        | File() / UploadFile     | f: UploadFile = File(...)\n# Dependency  | Depends()               | db = Depends(get_db)\n# Raw request | Request type hint       | request: Request\n#\n# RESPONSE    | HOW                     | DEPS: async def()->no cleanup\n# JSON default| return dict/model       |        yield->cleanup in finally\n# Custom JSON | JSONResponse(...)       |        class->via yield wrapper\n# HTML        | response_class=HTML...  |\n# Redirect    | RedirectResponse(url=)  | ASYNC vs SYNC\n# Streaming   | StreamingResponse(gen)  | async def = I/O (await), event loop\n# Plain text  | response_class=Plain... | def = CPU-bound, auto-threadpool\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#", "reference": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  ROUTES & ANNOTATED STYLE вҖ” DETAILED REFERENCE\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n# в”Җв”Җ Annotated[] вҖ” Modern parameter declaration style в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   Old style:  id: int = Path(gt=0)\n#   New style:  id: Annotated[int, Path(gt=0)]\n#   Both are equivalent. Annotated separates type hint from metadata.\n#   Benefits: reusable (UserId = Annotated[int, Path(ge=1)]), cleaner with type checkers\n#   Requires: from typing import Annotated\n#\n#   BEGINNER EXAMPLE вҖ” Annotated[]:\n#\n#     # Old style:\n#     @app.get(\"/old/{id}\")\n#     def old(id: int = Path(gt=0), q: str = Query(\"default\")):\n#         ...\n#     # New style (same behavior):\n#     @app.get(\"/new/{id}\")\n#     def new(id: Annotated[int, Path(gt=0)], q: Annotated[str, Query()] = \"default\"):\n#         ...\n#\n#     # Both called the same way:\n#     #   curl \"http://localhost:8000/new/42?q=test\"\n#     #     id вҶ’ 42, q вҶ’ \"test\"\n#     #\n#     # Reusable alias:\n#     #   PositiveInt = Annotated[int, Path(gt=0)]\n#     #   def route_a(id: PositiveInt): ...   вҶҗ reuse across routes\n#\n# в”Җв”Җ Path() with Annotated в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   product_id: Annotated[int, Path(title=\"Product ID\", ge=1, le=10000)]\n#   title/description вҶ’ shown in Swagger docs\n#   ge/le/gt/lt вҶ’ numeric validation (ge=1 means >= 1)\n#\n#   BEGINNER EXAMPLE вҖ” Path() with Annotated:\n#\n#     @app.get(\"/product/{product_id}\")\n#     def get_product(product_id: Annotated[int, Path(title=\"Product ID\", ge=1, le=10000)]):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/product/42\"\n#     #\n#     #   URL:  /product/42\n#     #                  в”Ӯ\n#     #                  в–ј\n#     #   Inside function:\n#     #     product_id вҶ’ 42          вҶҗ from URL path, validated ge=1, le=10000\n#     #\n#     #   curl \"http://localhost:8000/product/0\"     вҶ’ 422! ge=1 fails\n#     #   curl \"http://localhost:8000/product/99999\" вҶ’ 422! le=10000 fails\n#\n# в”Җв”Җ Query() with Annotated в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   start: Annotated[str, Query(description=\"Start date YYYY-MM-DD\")]  вҶ’ required\n#   max_results: Annotated[int, Query(alias=\"max-results\", ge=1)] = 10 вҶ’ optional + alias\n#   status: Annotated[list[str], Query()] = [\"active\"]                 вҶ’ list query param\n#   alias=\"max-results\" вҶ’ accept hyphenated query param names (?max-results=5)\n#\n#   BEGINNER EXAMPLE вҖ” Query() with Annotated + alias:\n#\n#     @app.get(\"/search\")\n#     def search(\n#         q: Annotated[str, Query(description=\"Search term\")],\n#         max_results: Annotated[int, Query(alias=\"max-results\", ge=1)] = 10,\n#         status: Annotated[list[str], Query()] = [\"active\"],\n#     ):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/search?q=table&max-results=5&status=active&status=pending\"\n#     #\n#     #   URL:  /search?q=table&max-results=5&status=active&status=pending\n#     #                 в”Ӯ        в”Ӯ               в”Ӯ             в”Ӯ\n#     #                 в–ј        в–ј               в””в”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”ҳ\n#     #   Inside function:                              в–ј\n#     #     q           вҶ’ \"table\"          вҶҗ required\n#     #     max_results вҶ’ 5                вҶҗ alias \"max-results\" вҶ’ Python name max_results\n#     #     status      вҶ’ [\"active\", \"pending\"]  вҶҗ repeated key = list\n#     #\n#     #   curl \"http://localhost:8000/search?q=table\"\n#     #     max_results вҶ’ 10 (default)\n#     #     status вҶ’ [\"active\"] (default list)\n#     #   NOTE: alias lets you use hyphens in URLs (?max-results) while Python uses underscores\n#\n# в”Җв”Җ Body() with Annotated в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   address: Annotated[str, Body(embed=True)]\n#   priority: Annotated[bool, Body(embed=True)] = False\n#   embed=True вҶ’ wraps each param under its name: {\"address\":\"...\", \"priority\":true}\n#   Without embed, multiple Body params auto-embed by default\n#\n#   BEGINNER EXAMPLE вҖ” Body() with Annotated + embed:\n#\n#     @app.post(\"/order\")\n#     def create(\n#         address: Annotated[str, Body(embed=True)],\n#         priority: Annotated[bool, Body(embed=True)] = False,\n#     ):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/order\" \\\n#     #        -H \"Content-Type: application/json\" \\\n#     #        -d '{\"address\": \"123 Main St\", \"priority\": true}'\n#     #\n#     #   Body: {\"address\": \"123 Main St\", \"priority\": true}\n#     #          в”Ӯ                          в”Ӯ\n#     #          в–ј                          в–ј\n#     #   Inside function:\n#     #     address  вҶ’ \"123 Main St\"    вҶҗ from body[\"address\"]\n#     #     priority вҶ’ True             вҶҗ from body[\"priority\"]\n#     #\n#     #   curl ... -d '{\"address\": \"123 Main St\"}'\n#     #     priority вҶ’ False (default)\n#\n# в”Җв”Җ Header() with Annotated в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   user_agent: Annotated[str, Header()]        вҶ’ reads \"User-Agent\" header (auto-converts _ to -)\n#   x_request_id: Annotated[str | None, Header()] = None  вҶ’ optional header\n#\n#   BEGINNER EXAMPLE вҖ” Header() with Annotated:\n#\n#     @app.get(\"/info\")\n#     def info(\n#         user_agent: Annotated[str, Header()],\n#         x_request_id: Annotated[str | None, Header()] = None,\n#     ):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/info\" \\\n#     #        -H \"User-Agent: MyApp/1.0\" \\\n#     #        -H \"X-Request-Id: req-789\"\n#     #\n#     #   Headers:\n#     #     User-Agent: MyApp/1.0        вҶҗ user_agent (underscore вҶ’ hyphen auto-convert)\n#     #     X-Request-Id: req-789        вҶҗ x_request_id\n#     #          в”Ӯ              в”Ӯ\n#     #          в–ј              в–ј\n#     #   Inside function:\n#     #     user_agent   вҶ’ \"MyApp/1.0\"   вҶҗ from User-Agent header\n#     #     x_request_id вҶ’ \"req-789\"     вҶҗ from X-Request-Id header (optional)\n#\n# в”Җв”Җ Cookie() with Annotated в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   session_token: Annotated[str | None, Cookie()] = None  вҶ’ optional cookie\n#\n#   BEGINNER EXAMPLE вҖ” Cookie() with Annotated:\n#\n#     @app.get(\"/dashboard\")\n#     def dashboard(session_token: Annotated[str | None, Cookie()] = None):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/dashboard\" -b \"session_token=tok_abc123\"\n#     #\n#     #   Cookie: session_token=tok_abc123\n#     #                         в”Ӯ\n#     #                         в–ј\n#     #   Inside function:\n#     #     session_token вҶ’ \"tok_abc123\"   вҶҗ from cookie (optional вҖ” None if absent)\n#\n# в”Җв”Җ Form() with Annotated в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   username: Annotated[str, Form()]    вҶ’ reads from form-encoded body\n#   Used for HTML form submissions. Cannot mix with Body() in same endpoint.\n#\n#   BEGINNER EXAMPLE вҖ” Form() with Annotated:\n#\n#     @app.post(\"/login\")\n#     def login(\n#         username: Annotated[str, Form()],\n#         password: Annotated[str, Form()],\n#     ):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/login\" \\\n#     #        -d \"username=john&password=secret\"\n#     #\n#     #   Form body: username=john&password=secret\n#     #              в”Ӯ             в”Ӯ\n#     #              в–ј             в–ј\n#     #   Inside function:\n#     #     username вҶ’ \"john\"       вҶҗ from form field\n#     #     password вҶ’ \"secret\"     вҶҗ from form field\n#     #   Content-Type: application/x-www-form-urlencoded (auto-set)\n#\n# в”Җв”Җ File() / UploadFile в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   file: UploadFile = File(...)        вҶ’ single file upload (multipart/form-data)\n#   files: list[UploadFile] = File(...) вҶ’ multiple files\n#   UploadFile attrs: .filename, .content_type, .size, .read(), .seek()\n#\n#   BEGINNER EXAMPLE вҖ” File() upload:\n#\n#     @app.post(\"/upload\")\n#     def upload(file: UploadFile = File(...)):\n#         ...\n#\n#     # How to call:\n#     #   curl -X POST \"http://localhost:8000/upload\" -F \"file=@photo.jpg\"\n#     #\n#     #   Multipart: file=@photo.jpg\n#     #                    в”Ӯ\n#     #                    в–ј\n#     #   Inside function:\n#     #     file.filename     вҶ’ \"photo.jpg\"\n#     #     file.content_type вҶ’ \"image/jpeg\"\n#     #     await file.read() вҶ’ b\"\\xff\\xd8...\" (raw bytes)\n#     #\n#     #   Multiple files:\n#     #   curl -F \"files=@a.jpg\" -F \"files=@b.png\" \"http://localhost:8000/upload-multi\"\n#     #     files вҶ’ [UploadFile(\"a.jpg\"), UploadFile(\"b.png\")]\n#\n# в”Җв”Җ Depends() вҖ” Dependency injection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   pagination: dict = Depends(pagination_params)     вҶ’ function dependency (reusable params)\n#   api_key: str = Depends(verify_api_key)            вҶ’ auth guard (raises 403 if invalid)\n#   db: DBSession = Depends(get_db)                   вҶ’ yield dependency (setup + cleanup)\n#   dependencies=[Depends(verify_api_key)]            вҶ’ route-level deps (no return value needed)\n#   Yield deps: try: yield resource / finally: cleanup вҖ” runs cleanup after route finishes\n#\n#   BEGINNER EXAMPLE вҖ” Depends():\n#\n#     # Function dep (reusable params):\n#     def pagination(page: int = Query(1), size: int = Query(10)):\n#         return {\"page\": page, \"size\": size, \"skip\": (page-1)*size}\n#\n#     @app.get(\"/items\")\n#     def list_items(p: dict = Depends(pagination)):\n#         ...\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/items?page=2&size=20\"\n#     #\n#     #   Depends() runs pagination(page=2, size=20) FIRST\n#     #     вҶ’ returns {\"page\": 2, \"size\": 20, \"skip\": 20}\n#     #                              в”Ӯ\n#     #                              в–ј\n#     #     p вҶ’ {\"page\": 2, \"size\": 20, \"skip\": 20}\n#\n#     # Yield dep (setup + cleanup):\n#     async def get_db():\n#         db = DBSession()\n#         try: yield db            # вҶҗ route uses db\n#         finally: db.close()      # вҶҗ cleanup AFTER route finishes\n#\n#     # Auth guard:\n#     #   curl \"http://localhost:8000/admin\" -H \"X-Api-Key: secret-key-123\"\n#     #     вҶ’ Depends(verify_api_key) checks header вҶ’ valid вҶ’ route runs\n#     #   curl \"http://localhost:8000/admin\" -H \"X-Api-Key: wrong\"\n#     #     вҶ’ Depends raises HTTPException(403) вҶ’ route NEVER runs\n#\n# в”Җв”Җ APIRouter вҖ” Organize routes into modules в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   router = APIRouter(prefix=\"/api/v1/users\", tags=[\"Users\"])\n#   @router.get(\"/\") вҶ’ becomes /api/v1/users/\n#   app.include_router(router)         вҶ’ register with main app\n#   Like Flask blueprints. Use for: routers/users.py, routers/orders.py, etc.\n#   dependencies=[Depends(...)] on router вҶ’ applies to ALL routes in that router\n#\n#   BEGINNER EXAMPLE вҖ” APIRouter:\n#\n#     customer_router = APIRouter(prefix=\"/api/v1/customers\", tags=[\"Customers\"])\n#\n#     @customer_router.get(\"/\")\n#     def list_customers(): ...\n#\n#     @customer_router.get(\"/{id}\")\n#     def get_customer(id: int): ...\n#\n#     app.include_router(customer_router)\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/api/v1/customers/\"\n#     #     вҶ’ hits list_customers()    (prefix + \"/\" = /api/v1/customers/)\n#     #\n#     #   curl \"http://localhost:8000/api/v1/customers/42\"\n#     #     вҶ’ hits get_customer(id=42) (prefix + \"/{id}\" = /api/v1/customers/42)\n#     #\n#     #   Router with shared auth:\n#     #   protected = APIRouter(prefix=\"/admin\", dependencies=[Depends(verify_api_key)])\n#     #     вҶ’ EVERY route in this router requires API key вҖ” no need to add Depends per route\n#\n# в”Җв”Җ Response types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   return dict/model                  вҶ’ auto-JSONResponse (default)\n#   JSONResponse(content={}, status_code=201)  вҶ’ custom status/headers\n#   HTMLResponse(\"<h1>Hi</h1>\")        вҶ’ HTML content\n#   PlainTextResponse(\"text\")          вҶ’ plain text\n#   RedirectResponse(url=\"/other\", status_code=302) вҶ’ redirect\n#   StreamingResponse(generator, media_type=\"text/plain\") вҶ’ streaming/SSE\n#   response.set_cookie(key, value, httponly=True) вҶ’ set cookie via Response param\n#\n#   BEGINNER EXAMPLE вҖ” Response types:\n#\n#     # Default JSON:\n#     @app.get(\"/json\")\n#     def get_json(): return {\"msg\": \"hello\"}\n#     #   curl \"http://localhost:8000/json\"\n#     #     вҶ’ {\"msg\": \"hello\"}  (Content-Type: application/json вҖ” auto)\n#\n#     # Custom status:\n#     @app.post(\"/create\")\n#     def create(): return JSONResponse(content={\"id\": 1}, status_code=201)\n#     #   curl -X POST \"http://localhost:8000/create\"\n#     #     вҶ’ 201 Created, {\"id\": 1}\n#\n#     # HTML:\n#     @app.get(\"/page\", response_class=HTMLResponse)\n#     def page(): return \"<h1>Hello</h1>\"\n#     #   curl \"http://localhost:8000/page\"\n#     #     вҶ’ <h1>Hello</h1>  (Content-Type: text/html)\n#\n#     # Redirect:\n#     @app.get(\"/old\")\n#     def old(): return RedirectResponse(url=\"/new\", status_code=301)\n#     #   curl -L \"http://localhost:8000/old\"\n#     #     вҶ’ follows redirect to /new\n#\n# в”Җв”Җ Error handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   raise HTTPException(status_code=404, detail=\"Not found\")  вҶ’ standard error\n#   raise HTTPException(status_code=403, headers={\"X-Error\": \"No\"}) вҶ’ with custom headers\n#   @app.exception_handler(CustomError)   вҶ’ custom exception вҶ’ custom JSON response\n#   Custom exception class + handler вҶ’ clean API error format\n#\n#   BEGINNER EXAMPLE вҖ” Error handling:\n#\n#     # Standard HTTPException:\n#     @app.get(\"/item/{id}\")\n#     def get_item(id: int):\n#         if id > 100: raise HTTPException(status_code=404, detail=\"Not found\")\n#         return {\"id\": id}\n#\n#     #   curl \"http://localhost:8000/item/1\"    вҶ’ {\"id\": 1}\n#     #   curl \"http://localhost:8000/item/999\"  вҶ’ 404: {\"detail\": \"Not found\"}\n#\n#     # Custom exception + handler:\n#     class ItemNotFound(Exception):\n#         def __init__(self, item_id): self.item_id = item_id\n#\n#     @app.exception_handler(ItemNotFound)\n#     def handle(request, exc):\n#         return JSONResponse(status_code=404, content={\"error\": \"item_not_found\", \"id\": exc.item_id})\n#\n#     #   raise ItemNotFound(42) вҶ’ {\"error\": \"item_not_found\", \"id\": 42}\n#\n# в”Җв”Җ Enum path parameters в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   class ModelName(str, Enum):\n#       GPT4O = \"gpt-4o\"\n#   def route(model: ModelName):       вҶ’ invalid value вҶ’ 422 auto-error\n#\n#   BEGINNER EXAMPLE вҖ” Enum path:\n#\n#     class ModelName(str, Enum):\n#         GPT4O = \"gpt-4o\"\n#         CLAUDE = \"claude-3.5\"\n#\n#     @app.get(\"/models/{model}\")\n#     def get_model(model: ModelName):\n#         ...\n#\n#     #   curl \"http://localhost:8000/models/gpt-4o\"     вҶ’ model вҶ’ ModelName.GPT4O\n#     #   curl \"http://localhost:8000/models/invalid\"    вҶ’ 422! not a valid enum value\n#\n# в”Җв”Җ Catch-all path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   @app.get(\"/files/{file_path:path}\")\n#   вҶ’ captures slashes: /files/docs/reports/q1.pdf вҶ’ file_path=\"docs/reports/q1.pdf\"\n#\n#   BEGINNER EXAMPLE вҖ” Catch-all :path:\n#\n#     @app.get(\"/files/{file_path:path}\")\n#     def get_file(file_path: str):\n#         ...\n#\n#     #   curl \"http://localhost:8000/files/docs/reports/q1.pdf\"\n#     #\n#     #   URL:  /files/docs/reports/q1.pdf\n#     #                в”Ӯ\n#     #                в–ј\n#     #     file_path вҶ’ \"docs/reports/q1.pdf\"  вҶҗ captures everything including slashes\n#     #   Normal {param} would stop at first / вҖ” :path captures the full nested path\n#\n# в”Җв”Җ api_route вҖ” Multiple HTTP methods on same path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   @app.api_route(\"/multi\", methods=[\"GET\", \"POST\"])\n#   вҶ’ request.method to distinguish: \"GET\" vs \"POST\"\n#\n#   BEGINNER EXAMPLE вҖ” api_route:\n#\n#     @app.api_route(\"/resource\", methods=[\"GET\", \"POST\"])\n#     async def resource(request: Request):\n#         if request.method == \"GET\": return {\"action\": \"reading\"}\n#         else: return {\"action\": \"creating\"}\n#\n#     #   curl \"http://localhost:8000/resource\"            вҶ’ {\"action\": \"reading\"}\n#     #   curl -X POST \"http://localhost:8000/resource\"    вҶ’ {\"action\": \"creating\"}\n#     #   Same path, different behavior based on HTTP method\n#\n# в”Җв”Җ Raw Request access в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   request: Request                   вҶ’ full access to method, url, headers, cookies, client IP\n#   dict(request.query_params)         вҶ’ all query params as dict\n#   dict(request.headers)              вҶ’ all headers as dict\n#   request.client.host                вҶ’ client IP address\n#\n#   BEGINNER EXAMPLE вҖ” Raw Request:\n#\n#     @app.get(\"/debug\")\n#     async def debug(request: Request):\n#         return {\n#             \"method\": request.method,\n#             \"url\": str(request.url),\n#             \"headers\": dict(request.headers),\n#             \"client_ip\": request.client.host,\n#         }\n#\n#     #   curl \"http://localhost:8000/debug?foo=bar\" -H \"X-Custom: hello\"\n#     #\n#     #   Inside function:\n#     #     request.method           вҶ’ \"GET\"\n#     #     request.url              вҶ’ \"http://localhost:8000/debug?foo=bar\"\n#     #     request.query_params     вҶ’ {\"foo\": \"bar\"}\n#     #     request.headers[\"x-custom\"] вҶ’ \"hello\"\n#     #     request.client.host      вҶ’ \"127.0.0.1\"\n#\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ"}, "session.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# FastAPI Sessions & Lifespan вҖ” Cookie, Redis, JWT\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# Deps: fastapi, uvicorn, httpx, PyJWT, redis, itsdangerous\n#\n# Run: uvicorn session:app --reload\n\nimport uuid, json\nfrom datetime import datetime, timedelta, timezone\nfrom contextlib import asynccontextmanager\nimport httpx, jwt, redis.asyncio as redis\nfrom fastapi import FastAPI, HTTPException, Request, Response, Depends\nfrom fastapi.security import HTTPBearer, HTTPAuthorizationCredentials\nfrom starlette.middleware.sessions import SessionMiddleware\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘               BEGINNER                           в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Lifespan вҖ” Startup & Shutdown в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# @asynccontextmanager turns an async generator into a context manager:\n#   before yield = startup, after yield = shutdown.\n# Replaces the old @app.on_event(\"startup\") / @app.on_event(\"shutdown\").\n# Equivalent to writing __aenter__ / __aexit__ on a class.\n@asynccontextmanager\nasync def lifespan(app: FastAPI):\n    # STARTUP: create shared resources once\n    print(\"Starting up...\")\n    app.state.http_client = httpx.AsyncClient(timeout=30)  # connection-pooled client\n    app.state.redis = redis.Redis(host=\"localhost\", port=6379, decode_responses=True)\n    app.state.shipments = {\n        1: {\"id\": 1, \"content\": \"Wooden Table\", \"weight\": 10, \"status\": \"In Transit\"},\n        2: {\"id\": 2, \"content\": \"Steel Chair\", \"weight\": 20, \"status\": \"Delivered\"},\n        3: {\"id\": 3, \"content\": \"Glass Vase\", \"weight\": 5, \"status\": \"Pending\"},\n    }\n    print(f\"Loaded {len(app.state.shipments)} shipments\")\n    yield  # server is live, handling requests\n    # SHUTDOWN: clean up resources\n    print(\"Shutting down...\")\n    await app.state.http_client.aclose()\n    await app.state.redis.aclose()\n    print(\"All connections closed\")\n\napp = FastAPI(title=\"Shipment Tracker API\", lifespan=lifespan)\napp.add_middleware(SessionMiddleware, secret_key=\"super-secret-key-change-in-prod\")\nJWT_SECRET = \"jwt-secret-key-change-in-prod\"\nsecurity = HTTPBearer()\nSESSION_TTL = 3600  # 1 hour\n\n# в”Җв”Җ 2. Shared State via app.state в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# app.state persists across requests for the app's lifetime.\n# Set in lifespan, accessed in routes via app.state.X or request.app.state.X.\n@app.get(\"/shipments\")\nasync def list_shipments():\n    return list(app.state.shipments.values())  # reads from lifespan-loaded data\n\n@app.get(\"/shipments/{shipment_id}\")\nasync def get_shipment(shipment_id: int):\n    shipment = app.state.shipments.get(shipment_id)\n    if not shipment:\n        raise HTTPException(status_code=404, detail=\"Shipment not found\")\n    return shipment\n\n@app.get(\"/external\")\nasync def call_external():\n    resp = await app.state.http_client.get(\"https://jsonplaceholder.typicode.com/todos/1\")\n    return resp.json()  # uses shared httpx client from lifespan\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘             INTERMEDIATE                         в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 3. Cookie-Based Sessions (SessionMiddleware) в”Җв”Җ\n# Starlette stores session data in a signed cookie (client-side).\n# Needs: app.add_middleware(SessionMiddleware, secret_key=...)\n# Data lives in request.session dict. Auto-set on response.\n@app.get(\"/cookie/login\")\nasync def cookie_login(request: Request):\n    request.session[\"user\"] = \"john@reuters.com\"  # stored in signed cookie\n    request.session[\"role\"] = \"editor\"\n    return {\"message\": \"Logged in via cookie session\"}\n\n@app.get(\"/cookie/profile\")\nasync def cookie_profile(request: Request):\n    user = request.session.get(\"user\")\n    if not user:\n        return {\"message\": \"Not logged in\"}\n    return {\"user\": user, \"role\": request.session.get(\"role\")}\n\n@app.get(\"/cookie/logout\")\nasync def cookie_logout(request: Request):\n    request.session.clear()  # removes all session data\n    return {\"message\": \"Logged out\"}\n\n# в”Җв”Җ 4. Redis Server-Side Sessions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Session ID in cookie, actual data in Redis. Server-controlled expiry.\n# Uses app.state.redis from lifespan.\n@app.get(\"/redis/login\")\nasync def redis_login(request: Request, response: Response):\n    session_id = str(uuid.uuid4())\n    session_data = {\"user\": \"john@reuters.com\", \"role\": \"editor\"}\n    await request.app.state.redis.setex(  # SET with EXpiry\n        f\"session:{session_id}\", SESSION_TTL, json.dumps(session_data),\n    )\n    response.set_cookie(key=\"session_id\", value=session_id, httponly=True)\n    return {\"message\": \"Logged in via Redis session\", \"session_id\": session_id}\n\n@app.get(\"/redis/profile\")\nasync def redis_profile(request: Request):\n    session_id = request.cookies.get(\"session_id\")\n    if not session_id:\n        return {\"message\": \"Not logged in\"}\n    data = await request.app.state.redis.get(f\"session:{session_id}\")\n    if not data:\n        return {\"message\": \"Session expired\"}\n    return json.loads(data)\n\n@app.get(\"/redis/logout\")\nasync def redis_logout(request: Request, response: Response):\n    session_id = request.cookies.get(\"session_id\")\n    if session_id:\n        await request.app.state.redis.delete(f\"session:{session_id}\")\n    response.delete_cookie(\"session_id\")\n    return {\"message\": \"Logged out\"}\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘               ADVANCED                           в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 5. JWT Token-Based Sessions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Stateless: token carries all session data, signed with secret.\n# No server storage needed. Client sends token in Authorization header.\n@app.post(\"/jwt/login\")\nasync def jwt_login():\n    payload = {\n        \"user\": \"john@reuters.com\", \"role\": \"editor\",\n        \"exp\": datetime.now(timezone.utc) + timedelta(hours=1),\n    }\n    token = jwt.encode(payload, JWT_SECRET, algorithm=\"HS256\")\n    return {\"message\": \"Logged in via JWT\", \"token\": token}\n\nasync def get_current_user(credentials: HTTPAuthorizationCredentials = Depends(security)):\n    try:\n        return jwt.decode(credentials.credentials, JWT_SECRET, algorithms=[\"HS256\"])\n    except jwt.ExpiredSignatureError:\n        raise HTTPException(status_code=401, detail=\"Token expired\")\n    except jwt.InvalidTokenError:\n        raise HTTPException(status_code=401, detail=\"Invalid token\")\n\n@app.get(\"/jwt/profile\")\nasync def jwt_profile(user: dict = Depends(get_current_user)):\n    return {\"user\": user[\"user\"], \"role\": user[\"role\"]}\n\n# в”Җв”Җ 6. Comparison: Cookie vs Redis vs JWT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#\n# в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ\n# | Aspect       | Cookie           | Redis            | JWT              |\n# в”ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Ө\n# | Storage      | Client (cookie)  | Server (Redis)   | Client (token)   |\n# | Size limit   | ~4KB per cookie  | Unlimited        | ~8KB practical   |\n# | Scalability  | Stateless        | Needs shared DB  | Stateless        |\n# | Revocation   | Clear cookie     | Delete key       | Can't revoke*    |\n# | Security     | Signed, not enc  | Server-only data | Signed, not enc  |\n# | Server load  | None             | Redis lookup/req | None (decode)    |\n# | Best for     | Simple apps      | Production apps  | APIs / SPAs      |\n# в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ\n# * JWT revocation requires a blocklist (adds server state)\n#\n# Pick cookie for prototypes, Redis for production web apps,\n# JWT for stateless APIs and microservices.", "cheatSheet": "# в”Җв”Җ CHEAT SHEET в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# LIFESPAN\n#   @asynccontextmanager + yield       startup/shutdown lifecycle\n#   app.state.X = resource             share across requests\n#   FastAPI(lifespan=lifespan)          attach to app\n#\n# COOKIE SESSION\n#   SessionMiddleware(secret_key=...)   enable cookie sessions\n#   request.session[\"key\"] = val        write session\n#   request.session.get(\"key\")          read session\n#   request.session.clear()             destroy session\n#\n# REDIS SESSION\n#   redis.setex(key, ttl, data)         store with expiry\n#   redis.get(key)                      retrieve\n#   redis.delete(key)                   remove\n#   response.set_cookie(httponly=True)   secure session cookie\n#\n# JWT SESSION\n#   jwt.encode(payload, secret, alg)    create token\n#   jwt.decode(token, secret, algs)     verify + decode\n#   Depends(HTTPBearer())               extract from header\n#   \"exp\" claim                         auto-expiry\n#", "reference": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  SESSIONS & AUTH DECLARATIONS вҖ” DETAILED REFERENCE\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n# в”Җв”Җ Lifespan вҖ” App startup/shutdown lifecycle в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   @asynccontextmanager\n#   async def lifespan(app: FastAPI):\n#       app.state.db = connect()       вҶ’ before yield = STARTUP (create resources)\n#       yield                          вҶ’ server is live, handling requests\n#       app.state.db.close()           вҶ’ after yield = SHUTDOWN (cleanup)\n#   FastAPI(lifespan=lifespan)         вҶ’ attach to app\n#   Replaces old @app.on_event(\"startup\") / @app.on_event(\"shutdown\")\n#\n#   BEGINNER EXAMPLE вҖ” Lifespan:\n#\n#     @asynccontextmanager\n#     async def lifespan(app: FastAPI):\n#         # STARTUP вҖ” runs once before first request\n#         app.state.http_client = httpx.AsyncClient(timeout=30)\n#         app.state.db = await connect_db()\n#         print(\"Ready!\")\n#         yield                              # вҶҗ server is live here\n#         # SHUTDOWN вҖ” runs when server stops (Ctrl+C)\n#         await app.state.http_client.aclose()\n#         await app.state.db.close()\n#\n#     app = FastAPI(lifespan=lifespan)       # вҶҗ attach to app\n#\n#     # Flow:\n#     #   uvicorn session:app --reload\n#     #     в”Ӯ\n#     #     в–ј\n#     #   STARTUP: create http_client, connect DB\n#     #     в”Ӯ\n#     #     в–ј\n#     #   yield вҶ’ server handles requests (uses app.state.http_client, app.state.db)\n#     #     в”Ӯ\n#     #     в–ј  (Ctrl+C or server stops)\n#     #   SHUTDOWN: close http_client, close DB\n#\n# в”Җв”Җ app.state вҖ” Share resources across requests в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   app.state.http_client = httpx.AsyncClient()   вҶ’ set in lifespan startup\n#   Access in routes: app.state.X or request.app.state.X\n#   Persists for app's entire lifetime. Use for: DB pools, HTTP clients, caches.\n#\n#   BEGINNER EXAMPLE вҖ” app.state:\n#\n#     # Set in lifespan startup:\n#     app.state.shipments = {1: {\"id\": 1, \"content\": \"Table\"}}\n#\n#     # Access in any route:\n#     @app.get(\"/shipments\")\n#     async def list_shipments():\n#         return list(app.state.shipments.values())\n#\n#     # How to call:\n#     #   curl \"http://localhost:8000/shipments\"\n#     #     вҶ’ [{\"id\": 1, \"content\": \"Table\"}]\n#     #\n#     #   app.state is shared across ALL requests for the app's lifetime\n#     #   Set once in startup вҶ’ use everywhere вҶ’ cleanup in shutdown\n#\n# в”Җв”Җ SessionMiddleware вҖ” Cookie-based sessions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   app.add_middleware(SessionMiddleware, secret_key=\"...\")\n#   request.session[\"user\"] = \"john\"   вҶ’ WRITE вҖ” stored in signed cookie (client-side)\n#   request.session.get(\"user\")        вҶ’ READ вҖ” auto-parsed from cookie\n#   request.session.clear()            вҶ’ DESTROY вҖ” removes all session data\n#   Data limit: ~4KB (cookie size limit). Signed but NOT encrypted.\n#\n#   BEGINNER EXAMPLE вҖ” Cookie sessions:\n#\n#     app.add_middleware(SessionMiddleware, secret_key=\"my-secret\")\n#\n#     @app.get(\"/cookie/login\")\n#     async def login(request: Request):\n#         request.session[\"user\"] = \"john@reuters.com\"\n#         return {\"message\": \"Logged in\"}\n#\n#     @app.get(\"/cookie/profile\")\n#     async def profile(request: Request):\n#         user = request.session.get(\"user\")\n#         return {\"user\": user}   # None if not logged in\n#\n#     # How to call:\n#     #   Step 1 вҖ” Login (sets cookie):\n#     #   curl -c cookies.txt \"http://localhost:8000/cookie/login\"\n#     #     вҶ’ response sets Set-Cookie header with signed session data\n#     #     вҶ’ cookies.txt stores: session=eyJhb...  (signed, base64-encoded)\n#     #\n#     #   Step 2 вҖ” Access profile (sends cookie back):\n#     #   curl -b cookies.txt \"http://localhost:8000/cookie/profile\"\n#     #     вҶ’ browser/curl sends cookie вҶ’ FastAPI decodes вҶ’ request.session populated\n#     #     вҶ’ {\"user\": \"john@reuters.com\"}\n#     #\n#     #   Without cookie:\n#     #   curl \"http://localhost:8000/cookie/profile\"\n#     #     вҶ’ {\"user\": null}   (no session cookie = empty session)\n#     #\n#     #   -c cookies.txt = save cookies to file\n#     #   -b cookies.txt = send cookies from file\n#\n# в”Җв”Җ Redis sessions вҖ” Server-side storage в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   Session ID in cookie, actual data in Redis (server-controlled).\n#   redis.setex(key, ttl, data)        вҶ’ store with expiry (auto-delete after TTL)\n#   redis.get(key)                     вҶ’ retrieve (returns None if expired)\n#   redis.delete(key)                  вҶ’ explicit removal (logout)\n#   response.set_cookie(httponly=True)  вҶ’ httponly prevents JS access (XSS protection)\n#\n#   BEGINNER EXAMPLE вҖ” Redis sessions:\n#\n#     @app.get(\"/redis/login\")\n#     async def login(request: Request, response: Response):\n#         session_id = str(uuid.uuid4())        # generate unique ID\n#         data = {\"user\": \"john@reuters.com\"}\n#         await redis.setex(f\"session:{session_id}\", 3600, json.dumps(data))\n#         response.set_cookie(key=\"session_id\", value=session_id, httponly=True)\n#         return {\"message\": \"Logged in\"}\n#\n#     @app.get(\"/redis/profile\")\n#     async def profile(request: Request):\n#         session_id = request.cookies.get(\"session_id\")\n#         data = await redis.get(f\"session:{session_id}\")\n#         return json.loads(data) if data else {\"message\": \"Not logged in\"}\n#\n#     # How to call:\n#     #   Step 1 вҖ” Login:\n#     #   curl -c cookies.txt \"http://localhost:8000/redis/login\"\n#     #     вҶ’ generates session_id (e.g., \"a1b2c3d4-...\")\n#     #     вҶ’ stores {\"user\": \"john\"} in Redis with key \"session:a1b2c3d4-...\"\n#     #     вҶ’ sets cookie: session_id=a1b2c3d4-... (httponly вҖ” JS can't read it)\n#     #\n#     #   Step 2 вҖ” Profile:\n#     #   curl -b cookies.txt \"http://localhost:8000/redis/profile\"\n#     #     Cookie: session_id=a1b2c3d4-...\n#     #                        в”Ӯ\n#     #                        в–ј\n#     #     Redis lookup: GET \"session:a1b2c3d4-...\"\n#     #                        в”Ӯ\n#     #                        в–ј\n#     #     вҶ’ {\"user\": \"john@reuters.com\"}\n#     #\n#     #   vs Cookie session:\n#     #     Cookie: data IN the cookie (client-side, ~4KB limit)\n#     #     Redis:  only session_id in cookie, data in Redis (unlimited, server-controlled)\n#\n# в”Җв”Җ JWT вҖ” Stateless token-based auth в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   jwt.encode(payload, secret, algorithm=\"HS256\")  вҶ’ create token (includes \"exp\" for expiry)\n#   jwt.decode(token, secret, algorithms=[\"HS256\"]) вҶ’ verify signature + decode payload\n#   Raises: jwt.ExpiredSignatureError (token too old), jwt.InvalidTokenError (tampered/invalid)\n#   Stateless: no server storage needed. Client sends in Authorization: Bearer <token> header.\n#\n#   BEGINNER EXAMPLE вҖ” JWT auth:\n#\n#     @app.post(\"/jwt/login\")\n#     async def login():\n#         payload = {\"user\": \"john\", \"role\": \"editor\",\n#                    \"exp\": datetime.now(timezone.utc) + timedelta(hours=1)}\n#         token = jwt.encode(payload, \"secret\", algorithm=\"HS256\")\n#         return {\"token\": token}\n#\n#     @app.get(\"/jwt/profile\")\n#     async def profile(user: dict = Depends(get_current_user)):\n#         return {\"user\": user[\"user\"]}\n#\n#     # How to call:\n#     #   Step 1 вҖ” Login (get token):\n#     #   curl -X POST \"http://localhost:8000/jwt/login\"\n#     #     вҶ’ {\"token\": \"eyJhbGciOiJIUzI1NiJ9.eyJ1c2VyIjoiam9obi...\"}\n#     #\n#     #   Step 2 вҖ” Access protected route (send token):\n#     #   curl \"http://localhost:8000/jwt/profile\" \\\n#     #        -H \"Authorization: Bearer eyJhbGciOiJIUzI1NiJ9...\"\n#     #\n#     #   Header: Authorization: Bearer eyJhbGci...\n#     #                                 в”Ӯ\n#     #                                 в–ј\n#     #   Depends(get_current_user):\n#     #     HTTPBearer() extracts token from header\n#     #       вҶ’ jwt.decode(token, secret) вҶ’ {\"user\": \"john\", \"role\": \"editor\"}\n#     #                                       в”Ӯ\n#     #                                       в–ј\n#     #     user вҶ’ {\"user\": \"john\", \"role\": \"editor\"}\n#     #\n#     #   Bad token:  curl ... -H \"Authorization: Bearer invalid\"\n#     #     вҶ’ 401! jwt.InvalidTokenError\n#     #   Expired:    вҶ’ 401! jwt.ExpiredSignatureError\n#     #   No header:  вҶ’ 403! HTTPBearer finds no Authorization header\n#\n# в”Җв”Җ Depends() вҖ” Dependency injection for auth в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   security = HTTPBearer()\n#   async def get_current_user(credentials: HTTPAuthorizationCredentials = Depends(security)):\n#       вҶ’ HTTPBearer() extracts token from \"Authorization: Bearer <token>\" header\n#       вҶ’ credentials.credentials = the raw token string\n#       вҶ’ Depends(security) runs HTTPBearer BEFORE your function\n#   @app.get(\"/protected\")\n#   async def route(user: dict = Depends(get_current_user)):\n#       вҶ’ Depends(get_current_user) runs auth check BEFORE route\n#       вҶ’ If it raises HTTPException, route is skipped (401/403 returned)\n#       вҶ’ Chaining: route depends on get_current_user, which depends on HTTPBearer()\n#\n#   BEGINNER EXAMPLE вҖ” Depends() chain for auth:\n#\n#     security = HTTPBearer()\n#\n#     # Dependency 1: extract token from header\n#     # Dependency 2: decode and verify token\n#     async def get_current_user(cred: HTTPAuthorizationCredentials = Depends(security)):\n#         return jwt.decode(cred.credentials, \"secret\", algorithms=[\"HS256\"])\n#\n#     @app.get(\"/profile\")\n#     async def profile(user: dict = Depends(get_current_user)):\n#         return user\n#\n#     # How the chain works:\n#     #   curl \"http://localhost:8000/profile\" -H \"Authorization: Bearer <token>\"\n#     #\n#     #   Request arrives\n#     #     в”Ӯ\n#     #     в–ј\n#     #   Depends(get_current_user) runs FIRST\n#     #     в”Ӯ\n#     #     в”ңв”Җв”Җ Depends(security) runs FIRST (inside get_current_user)\n#     #     в”Ӯ     вҶ’ HTTPBearer() extracts \"Bearer <token>\" from header\n#     #     в”Ӯ     вҶ’ cred.credentials = \"<token>\" (raw token string)\n#     #     в”Ӯ\n#     #     в”ңв”Җв”Җ jwt.decode(token) вҶ’ {\"user\": \"john\", \"role\": \"editor\"}\n#     #     в”Ӯ\n#     #     в–ј\n#     #   profile() runs with user = {\"user\": \"john\", \"role\": \"editor\"}\n#     #\n#     #   If ANY dependency fails вҶ’ HTTPException вҶ’ route NEVER runs\n#\n# в”Җв”Җ Request & Response objects в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   request: Request                   вҶ’ access to headers, cookies, session, URL, client IP\n#   request.cookies.get(\"session_id\")  вҶ’ read a specific cookie\n#   request.headers.get(\"Authorization\") вҶ’ read a header\n#   response: Response                 вҶ’ set cookies, headers on outgoing response\n#   response.set_cookie(key, value, httponly=True, max_age=3600)\n#   response.delete_cookie(\"session_id\") вҶ’ remove a cookie\n#\n#   BEGINNER EXAMPLE вҖ” Request & Response:\n#\n#     @app.get(\"/demo\")\n#     async def demo(request: Request, response: Response):\n#         # READ from request:\n#         session = request.cookies.get(\"session_id\")     # read cookie\n#         auth = request.headers.get(\"Authorization\")     # read header\n#         ip = request.client.host                        # client IP\n#\n#         # WRITE to response:\n#         response.set_cookie(\"visited\", \"true\", max_age=3600)   # set cookie\n#         response.headers[\"X-Custom\"] = \"hello\"                 # set header\n#         return {\"session\": session, \"ip\": ip}\n#\n#     # How to call:\n#     #   curl -v \"http://localhost:8000/demo\" \\\n#     #        -b \"session_id=abc\" \\\n#     #        -H \"Authorization: Bearer tok123\"\n#     #\n#     #   Request (what server reads):\n#     #     Cookie: session_id=abc          вҶ’ request.cookies.get(\"session_id\") вҶ’ \"abc\"\n#     #     Authorization: Bearer tok123    вҶ’ request.headers.get(\"Authorization\")\n#     #     Client IP: 127.0.0.1           вҶ’ request.client.host\n#     #\n#     #   Response (what client receives):\n#     #     Set-Cookie: visited=true; Max-Age=3600  вҶҗ response.set_cookie()\n#     #     X-Custom: hello                         вҶҗ response.headers[]\n#     #     Body: {\"session\": \"abc\", \"ip\": \"127.0.0.1\"}\n#\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ"}}, "python": {"annotations.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  PYTHON ANNOTATIONS & TYPE HINTS вҖ” Condensed Guide\n#  Annotations = metadata labels on variables/functions\n#  Python does NOT enforce them вҖ” they are HINTS only\n#  But frameworks (FastAPI, Pydantic, dataclasses) READ them at runtime\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\nfrom __future__ import annotations  # makes all annotations lazy strings (3.7+)\nimport typing, functools\nfrom typing import (\n    Optional, Union, Any, Callable, Literal, TypeAlias,\n    TypedDict, Annotated, TypeVar, Protocol, runtime_checkable,\n    Final, final, ClassVar, NamedTuple, NotRequired, Sized, get_type_hints,\n)\nfrom dataclasses import dataclass, field\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                  BEGINNER                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Basic Function Annotations в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# param: Type вҶ’ annotate parameter  |  -> Type вҶ’ annotate return\n# Stored in func.__annotations__  |  Python IGNORES them вҖ” no enforcement!\ndef greet(name: str) -> str:\n    return f\"Hello, {name}!\"\nprint(greet(\"Alice\"))   # Hello, Alice!\nprint(greet(123))       # Hello, 123!  вҖ” no error, annotations aren't enforced\nprint(greet.__annotations__)  # {'name': <class 'str'>, 'return': <class 'str'>}\n\ndef add(a: int, b: int) -> int:\n    return a + b\nprint(add(\"hello\", \" world\"))  # works fine вҖ” Python doesn't care\n\n# в”Җв”Җ 2. Variable Annotations (3.6+) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# variable: Type = value вҖ” just a label, no validation\nname: str = \"Alice\"\nage: int = 30\nprice: float = 9.99\nactive: bool = True\nwrong: int = \"this is a string\"  # no error! annotation is just a hint\nfuture_value: int  # declares \"will exist\" вҖ” but variable doesn't exist yet\n# print(future_value)  # NameError! annotation alone doesn't create it\n\n# в”Җв”Җ 3. Collection Type Annotations в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# 3.9+: list[int], dict[str, int], tuple[int, str], set[str]\n# 3.8:  List[int], Dict[str, int] (from typing вҖ” avoid in new code)\ndef sum_scores(scores: list[int]) -> int:        return sum(scores)\ndef get_config() -> dict[str, str]:              return {\"host\": \"localhost\", \"port\": \"8000\"}\ndef get_point() -> tuple[int, int]:              return (10, 20)\ndef group_scores() -> dict[str, list[int]]:      return {\"math\": [90, 85]}  # nested\nprint(sum_scores([10, 20, 30]))  # 60\nprint(get_point())               # (10, 20)\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘               INTERMEDIATE                       в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 4. Optional вҖ” value can be X or None в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Optional[str] == str | None (3.10+ pipe syntax)\ndef find_user(user_id: int) -> Optional[dict]:     # old style\n    return {1: {\"name\": \"Alice\"}}.get(user_id)\ndef find_item(item_id: int) -> dict | None:        # 3.10+ style (same thing)\n    return {1: {\"name\": \"Laptop\"}}.get(item_id)\ndef greet_user(name: str, title: Optional[str] = None) -> str:\n    return f\"Hello, {title + ' ' if title else ''}{name}!\"\nprint(find_user(1))    # {'name': 'Alice'}\nprint(find_user(99))   # None\n\n# в”Җв”Җ 5. Union вҖ” one of several types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Union[str, int] == str | int (3.10+)\ndef format_id(user_id: Union[str, int]) -> str:    # old style\n    return f\"USER-{user_id}\"\ndef flexible(value: str | int | float) -> str:     # 3.10+ style\n    return str(value)\nprint(format_id(42))     # USER-42\nprint(format_id(\"abc\"))  # USER-abc\n\n# в”Җв”Җ 6. Any вҖ” accept anything в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Use sparingly вҖ” defeats purpose of type hints\ndef log_value(value: Any) -> str:\n    return f\"Logged: {value} ({type(value).__name__})\"\nprint(log_value([1, 2]))  # Logged: [1, 2] (list)\n\n# в”Җв”Җ 7. Callable вҖ” functions as parameters в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Callable[[param_types], return_type]\ndef apply(func: Callable[[int, int], int], a: int, b: int) -> int:\n    return func(a, b)\nprint(apply(lambda x, y: x * y, 3, 5))  # 15\n\ndef run_task(task: Callable[[], str]) -> str:      return task()      # no-arg callable\ndef execute(func: Callable[..., Any]) -> Any:      return func()      # any-arg callable\n\n# Callback pattern\ndef fetch_data(url: str, on_success: Callable[[dict], None]) -> None:\n    on_success({\"url\": url, \"status\": 200})\nfetch_data(\"https://api.com\", on_success=lambda d: print(f\"  Got: {d}\"))\n\n# в”Җв”Җ 8. Literal вҖ” restrict to specific values в”Җв”Җв”Җв”Җв”Җв”Җ\n# Like an enum but simpler вҖ” type checkers enforce it\ndef set_color(color: Literal[\"red\", \"green\", \"blue\"]) -> str:\n    return f\"Color: {color}\"\ndef set_priority(level: Literal[1, 2, 3]) -> str:\n    return {1: \"High\", 2: \"Medium\", 3: \"Low\"}.get(level, \"Unknown\")\nprint(set_color(\"red\"))       # Color: red\nprint(set_color(\"purple\"))    # runs fine вҖ” but mypy flags it\nprint(set_priority(1))        # High\n\n# в”Җв”Җ 9. TypeAlias вҖ” name complex types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nUserRecord: TypeAlias = dict[str, list[tuple[int, str]]]\nJSON: TypeAlias = dict[str, Any]\nHeaders: TypeAlias = dict[str, str]\nCoordinates: TypeAlias = tuple[float, float]\n\ndef make_request(url: str, headers: Headers) -> JSON:\n    return {\"url\": url, \"headers\": headers}\ndef distance(p1: Coordinates, p2: Coordinates) -> float:\n    return ((p2[0]-p1[0])**2 + (p2[1]-p1[1])**2) ** 0.5\nprint(distance((0, 0), (3, 4)))  # 5.0\n\n# в”Җв”Җ 10. TypedDict вҖ” typed dictionary structure в”Җв”Җв”Җв”Җв”Җ\n# Regular dict[str, Any] doesn't specify which keys exist\nclass UserDict(TypedDict):\n    name: str\n    age: int\n    email: str\n\nclass Config(TypedDict, total=False):   # all keys optional\n    host: str\n    port: int\n\nclass APIResponse(TypedDict):\n    status: int                         # required\n    data: dict                          # required\n    error: NotRequired[str]             # optional\n\ndef create_user() -> UserDict:\n    return {\"name\": \"Alice\", \"age\": 30, \"email\": \"alice@test.com\"}\nprint(create_user())  # {'name': 'Alice', 'age': 30, 'email': 'alice@test.com'}\n\n# в”Җв”Җ 11. Annotated вҖ” attach metadata to types в”Җв”Җв”Җв”Җв”Җв”Җ\n# Annotated[Type, metadata...] вҖ” Python ignores metadata, frameworks read it\n# THIS is how FastAPI reads validation rules\ndef create_item(\n    name: Annotated[str, \"Item name, max 100 chars\"],\n    price: Annotated[float, \"Price in USD, > 0\"],\n) -> dict:\n    return {\"name\": name, \"price\": price}\nprint(create_item(\"Laptop\", 999.99))  # {'name': 'Laptop', 'price': 999.99}\n\n# FastAPI usage (not runnable without FastAPI):\n# @app.get(\"/items\")\n# def get_items(\n#     q: Annotated[str, Query(min_length=3, max_length=50)],\n#     skip: Annotated[int, Query(ge=0)] = 0,\n#     limit: Annotated[int, Query(le=100)] = 10,\n# ): ...\n# FastAPI reads Query() from Annotated вҶ’ enforces validation + generates docs\n\n# Custom metadata class вҖ” access at runtime\nclass Range:\n    def __init__(self, min_val: int, max_val: int):\n        self.min_val, self.max_val = min_val, max_val\n    def __repr__(self): return f\"Range({self.min_val}, {self.max_val})\"\n\ndef set_volume(level: Annotated[int, Range(0, 100)]) -> str:\n    return f\"Volume: {level}\"\nhints = get_type_hints(set_volume, include_extras=True)\nprint(hints)  # {'level': typing.Annotated[int, Range(0, 100)], ...}\n\n# в”Җв”Җ 12. Class Annotations в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass User:\n    name: str\n    age: int\n    def __init__(self, name: str, age: int) -> None:\n        self.name, self.age = name, age\n    def greet(self) -> str:\n        return f\"Hi, I'm {self.name}, age {self.age}\"\nprint(User(\"Alice\", 30).greet())   # Hi, I'm Alice, age 30\nprint(User.__annotations__)        # {'name': <class 'str'>, 'age': <class 'int'>}\n\n# в”Җв”Җ 13. dataclass вҖ” annotations create real attributes в”Җв”Җ\n# @dataclass reads annotations вҶ’ auto-generates __init__, __repr__, __eq__\n@dataclass\nclass Product:\n    name: str                                       # required\n    price: float                                    # required\n    quantity: int = 0                               # optional with default\n    tags: list[str] = field(default_factory=list)   # mutable default\nprint(Product(\"Laptop\", 999.99, 5, [\"tech\"]))  # Product(name='Laptop', ...)\nprint(Product(\"Mouse\", 25.0))                   # Product(name='Mouse', price=25.0, ...)\n\n@dataclass(frozen=True)    # immutable вҖ” Point(3,4).x = 5 вҶ’ FrozenInstanceError\nclass Point:\n    x: float\n    y: float\n\n@dataclass\nclass Rectangle:\n    width: float\n    height: float\n    area: float = field(init=False)   # computed, not in __init__\n    def __post_init__(self) -> None:\n        self.area = self.width * self.height\nprint(Rectangle(5.0, 3.0))  # Rectangle(width=5.0, height=3.0, area=15.0)\n\n# в”Җв”Җ 14. NamedTuple with annotations в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Coordinate(NamedTuple):\n    x: float\n    y: float\n    label: str = \"origin\"\nc = Coordinate(3.0, 4.0, \"A\")\nprint(c.x, c.label)       # 3.0 A\nx, y, label = c           # unpack like a tuple вҖ” immutable (c.x = 10 вҶ’ error)\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                  ADVANCED                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 15. TypeVar вҖ” generic type placeholders в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# \"T\" = whatever type the caller passes вҖ” keeps input/output consistent\nT = TypeVar(\"T\")\ndef first(items: list[T]) -> T:    # type checker knows first([1,2]) returns int\n    return items[0]\nprint(first([1, 2, 3]))     # 1 (int вҶ’ int)\nprint(first([\"a\", \"b\"]))    # a (str вҶ’ str)\n\nNumber = TypeVar(\"Number\", int, float)     # constrained вҖ” only int or float\ndef double(n: Number) -> Number:\n    return n * 2\n\nS = TypeVar(\"S\", bound=Sized)              # bounded вҖ” must have __len__\ndef get_length(item: S) -> int:\n    return len(item)\nprint(double(5))           # 10\nprint(get_length(\"hello\")) # 5\n\n# в”Җв”Җ 16. Protocol вҖ” structural typing (duck typing) в”Җ\n# \"Any object with these methods works\" вҖ” no inheritance needed\n@runtime_checkable\nclass Printable(Protocol):\n    def to_string(self) -> str: ...\n\nclass UserP:\n    def __init__(self, n: str): self.name = n\n    def to_string(self) -> str: return f\"User({self.name})\"\n\nclass ProductP:\n    def __init__(self, n: str, p: float): self.name, self.price = n, p\n    def to_string(self) -> str: return f\"Product({self.name}, ${self.price})\"\n\ndef display(item: Printable) -> None:\n    print(item.to_string())\ndisplay(UserP(\"Alice\"))      # User(Alice) вҖ” matches Protocol, no inheritance\ndisplay(ProductP(\"Laptop\", 999))\nprint(isinstance(UserP(\"Bob\"), Printable))  # True (runtime_checkable)\n\n# в”Җв”Җ 17. Final вҖ” constants & non-overridable в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nMAX_RETRIES: Final[int] = 3\nAPI_URL: Final[str] = \"https://api.example.com\"\nPI: Final = 3.14159          # type inferred\n# MAX_RETRIES = 5  вҶ’ mypy error: Cannot assign to final name\n\nclass Base:\n    @final\n    def critical(self) -> str:  # subclass can't override\n        return \"Don't override me\"\n\n# в”Җв”Җ 18. ClassVar вҖ” class-level, not in __init__ в”Җв”Җв”Җв”Җ\n@dataclass\nclass Employee:\n    name: str\n    salary: float\n    company: ClassVar[str] = \"Reuters\"     # shared, NOT in __init__\n    count: ClassVar[int] = 0\n    def __post_init__(self) -> None:\n        Employee.count += 1\ne1, e2 = Employee(\"Alice\", 90000), Employee(\"Bob\", 85000)\nprint(f\"Company: {Employee.company}, Count: {Employee.count}\")  # Reuters, 2\n\n# в”Җв”Җ 19. get_type_hints() вҖ” runtime inspection в”Җв”Җв”Җв”Җв”Җ\n# Better than __annotations__ вҖ” resolves forward refs\ndef process(name: str, age: int, scores: list[float]) -> dict[str, Any]:\n    return {\"name\": name, \"age\": age, \"avg\": sum(scores) / len(scores)}\nhints = get_type_hints(process)\nprint(hints)  # {'name': str, 'age': int, 'scores': list[float], 'return': dict[str, Any]}\n\n# Auto-validate using annotations\ndef validate(func: Callable, **kwargs: Any) -> dict[str, bool]:\n    hints = get_type_hints(func)\n    return {k: isinstance(kwargs[k], v) for k, v in hints.items()\n            if k != \"return\" and k in kwargs}\nprint(validate(process, name=\"Alice\", age=30, scores=[90.0]))  # all True\nprint(validate(process, name=\"Alice\", age=\"thirty\"))           # age: False\n\n# в”Җв”Җ 20. Forward References в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Use \"ClassName\" string when type isn't defined yet\n# Or: from __future__ import annotations (top of file) вҖ” makes ALL lazy\nclass TreeNode:\n    def __init__(self, val: int, children: list[TreeNode] | None = None):\n        self.val, self.children = val, children or []\n    def __repr__(self) -> str:\n        return f\"Tree({self.val}{', ' + repr(self.children) if self.children else ''})\"\ntree = TreeNode(1, [TreeNode(2), TreeNode(3, [TreeNode(4)])])\nprint(tree)  # Tree(1, [Tree(2), Tree(3, [Tree(4)])])\n\n# в”Җв”Җ 21. Framework Usage Comparison в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Pure Python вҖ” annotations IGNORED, no enforcement\n# dataclass вҖ” annotations вҶ’ auto __init__, __repr__, __eq__\n# FastAPI вҖ” reads annotations for validation, conversion, docs generation\n# Pydantic вҖ” ENFORCES types + auto-converts at runtime\n\n# FastAPI (pseudocode):\n# @app.get(\"/items/{item_id}\")\n# def get_item(\n#     item_id: int,                              # path param, auto-convert\n#     skip: Annotated[int, Query(ge=0)] = 0,     # query param, validated\n# ): ...\n\ntry:\n    from pydantic import BaseModel, ValidationError\n    class UserModel(BaseModel):\n        name: str\n        age: int\n        active: bool = True\n    print(UserModel(name=\"Alice\", age=\"25\"))      # auto-converts \"25\" вҶ’ 25\n    try:\n        UserModel(name=\"X\", age=\"not a number\")\n    except ValidationError as e:\n        print(f\"  Pydantic caught {e.error_count()} error(s)\")\nexcept ImportError:\n    print(\"  (pydantic not installed)\")\n\n# в”Җв”Җ 22. mypy вҖ” Static Type Checking в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# pip install mypy && mypy file.py вҖ” catches bugs without running code\n# pyright is a faster alternative. IDEs (VSCode/PyCharm) check in real-time.\n\n# в”Җв”Җ 23. Decorator Preserving Annotations в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef logged(func: Callable[..., T]) -> Callable[..., T]:\n    @functools.wraps(func)\n    def wrapper(*args: Any, **kwargs: Any) -> T:\n        return func(*args, **kwargs)\n    return wrapper\n\n@logged\ndef compute(x: int, y: int) -> int:\n    return x + y\nprint(f\"Result: {compute(3, 5)}, name: {compute.__name__}\")  # 8, compute", "cheatSheet": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  CHEAT SHEET\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  SYNTAX:\n#    param: Type              annotate parameter\n#    -> Type                  annotate return value\n#    var: Type = value        annotate variable\n#    func.__annotations__    raw annotation dict\n#    get_type_hints(func)    resolved (handles forward refs)\n#\n#  BASIC TYPES:\n#    str, int, float, bool               primitives\n#    list[int], dict[str, Any]           collections (3.9+)\n#    tuple[int, str], set[str]           fixed tuple, set\n#    List[int], Dict[str, int]           old style (typing, 3.8)\n#\n#  TYPING MODULE:\n#    Optional[X]         X | None             value or None\n#    Union[X, Y]         X | Y  (3.10+)       one of several types\n#    Any                                       no restriction\n#    Literal[\"a\",\"b\"]                          specific values only\n#    Callable[[args], ret]                     function type\n#    TypeAlias            = complex_type       readable name\n#    TypedDict                                 dict with typed keys\n#    Annotated[X, meta]                        type + framework metadata\n#    TypeVar(\"T\")                              generic placeholder\n#    Protocol                                  structural/duck typing\n#    Final[X]                                  constant, don't reassign\n#    ClassVar[X]                               class-level, not instance\n#    NamedTuple                                typed immutable tuple\n#\n#  FORWARD REFS:\n#    \"ClassName\"                        use type before definition\n#    from __future__ import annotations auto-stringify all\n#\n#  WHO READS ANNOTATIONS:\n#    Pure Python  вҶ’ IGNORED (just labels)\n#    dataclass    вҶ’ creates __init__, __repr__, __eq__\n#    FastAPI      вҶ’ validates, converts, generates docs\n#    Pydantic     вҶ’ enforces types, auto-converts\n#    mypy/pyright вҶ’ static checking (no runtime)\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ", "reference": ""}, "data-types.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# PYTHON DATA TYPES вҖ” CONDENSED REFERENCE\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\nimport math, copy, re, weakref\nfrom enum import Enum, IntEnum, Flag, auto\nfrom typing import (List, Dict, Tuple, Set, Optional, Union,\n                    Any, Callable, Final, Literal, NamedTuple, TypedDict)\nfrom collections import namedtuple, OrderedDict, defaultdict, Counter, deque, ChainMap\nfrom dataclasses import dataclass, field\nfrom datetime import date, time, datetime, timedelta, timezone\nfrom decimal import Decimal, getcontext\nfrom fractions import Fraction\nfrom pathlib import Path\nfrom queue import Queue, LifoQueue, PriorityQueue\nfrom contextlib import contextmanager\nfrom functools import partial\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                   BEGINNER                       в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. int в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\na = 10; b = -5; c = 1_000_000       # underscores for readability\nd = 0b1010; e = 0o17; f = 0xFF      # binary=10, octal=15, hex=255\ng = int(\"42\"); h = int(\"1010\", 2)   # str->int, binary str->int=10\ni = int(3.9)                         # truncates toward zero => 3\nbig = 10**100                        # arbitrary precision, no overflow\nprint(f\"int: {a}, bin={d}, oct={e}, hex={f}\")  # 10, 10, 15, 255\nprint(f\"int(3.9)={i}, int(-3.9)={int(-3.9)}\") # 3, -3 (truncates, NOT rounds)\n# input: num = int(input(\"Enter integer: \"))\n\n# в”Җв”Җ 2. float в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# 64-bit IEEE 754 double precision (~15-17 significant digits)\na_f = 3.14; b_f = 3.14e2             # standard, scientific=314.0\nc_f = float(\"inf\"); d_f = float(\"nan\")\nprint(f\"float: {a_f}, sci={b_f}, inf={c_f}, nan={d_f}\")\nprint(f\"0.1 + 0.2 = {0.1 + 0.2}\")                     # 0.30000000000000004\nprint(f\"0.1+0.2 == 0.3 => {0.1 + 0.2 == 0.3}\")        # False  GOTCHA!\nprint(f\"math.isclose => {math.isclose(0.1 + 0.2, 0.3)}\")  # True  FIX\nprint(f\"isnan={math.isnan(d_f)}, isinf={math.isinf(c_f)}\")  # True, True\n# input: price = float(input(\"Enter price: \"))\n\n# в”Җв”Җ 3. complex в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nz = 3 + 4j                           #  same as complex(3, 4)\nprint(f\"complex: {z}, real={z.real}, imag={z.imag}\")  # 3.0, 4.0\nprint(f\"conjugate={z.conjugate()}, abs={abs(z)}\")     # (3-4j), 5.0\n# GOTCHA: complex(\"3+4j\") OK, complex(\"3 + 4j\") ValueError (no spaces!)\n\n# в”Җв”Җ 4. bool в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Subclass of int: True==1, False==0\nprint(f\"True+True={True+True}, True*10={True*10}\")  # 2, 10\nprint(f\"isinstance(True, int)={isinstance(True, int)}\")  # True\n# Falsy: False, None, 0, 0.0, 0j, '', [], (), {}, set(), frozenset()\n# Truthy: everything else\nprint(f\"bool('')={bool('')}, bool('x')={bool('x')}\")       # False, True\nprint(f\"bool([])={bool([])}, bool(None)={bool(None)}\")     # False, False\n# GOTCHA: bool(\"False\") => True (non-empty string!)\n# input: answer = input(\"y/n: \").strip().lower() in (\"yes\",\"y\",\"1\")\n\n# в”Җв”Җ 5. str в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Immutable sequence of Unicode characters\ns1 = 'single'; s2 = \"double\"\ns3 = \"\"\"triple\\nfor multiline\"\"\"\ns4 = str(42)                          # \"42\"\ns5 = r\"raw\\nstring\"                   # no escape processing\n\n# Key methods\nword = \"Hello, World!\"\nprint(f\"len={len(word)}, upper={word.upper()}, lower={word.lower()}\")\nprint(f\"strip='{'  hi  '.strip()}', replace={word.replace('World','Python')}\")\nprint(f\"split={'a,b,c'.split(',')}, join={'-'.join(['a','b','c'])}\")\nprint(f\"find={word.find('World')}, count={'banana'.count('a')}\")\nprint(f\"startswith={word.startswith('Hello')}, isdigit={'123'.isdigit()}\")\n\n# Indexing & slicing\ntext = \"Python\"\nprint(f\"[0]={text[0]}, [-1]={text[-1]}, [0:3]={text[0:3]}, [::-1]={text[::-1]}\")\n\n# Formatting\nname, age = \"Alice\", 30\nprint(f\"f-string: {name} is {age}\")           # f-string: Alice is 30\nprint(f\"{3.14159:.2f}, {1000000:,}, {255:08b}, {255:#x}\")  # 3.14, 1,000,000, 11111111, 0xff\n# IMMUTABLE: text[0] = 'p' => TypeError\n\n# в”Җв”Җ 6. NoneType в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nn = None\nprint(f\"None is None: {n is None}\")            # True (always use 'is', not ==)\nprint(f\"bool(None)={bool(None)}\")              # False\ndef no_return(): pass\nprint(f\"no return => {no_return()}\")           # None\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                 INTERMEDIATE                     в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 7. list в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Mutable, ordered, allows duplicates and mixed types\nl1 = [1, 2, 3]; l2 = list(\"hello\")   # ['h','e','l','l','o']\nl3 = list(range(5))                   # [0,1,2,3,4]\n# Indexing: l1[0]=1, l1[-1]=3, l1[1:3]=[2,3], l1[::-1]=[3,2,1]\n\nlst = [3, 1, 4, 1, 5]\nlst.append(9)                         # [3,1,4,1,5,9]\nlst.insert(0, 0)                      # [0,3,1,4,1,5,9]\nlst.extend([6, 7])                    # adds multiple to end\npopped = lst.pop()                    # remove & return last\nlst.remove(1)                         # remove first occurrence\nprint(f\"count={lst.count(1)}, index={lst.index(4)}\")\n\nlst2 = [3, 1, 4, 1, 5]\nlst2.sort()                           # in-place => [1,1,3,4,5]\nlst2.sort(reverse=True)               # descending\nnew_sorted = sorted([3, 1, 2])        # returns new list, original unchanged\n\n# Comprehension\nsquares = [x**2 for x in range(6)]    # [0,1,4,9,16,25]\nevens = [x for x in range(10) if x % 2 == 0]\n\n# Unpacking\nfirst, *rest = [1, 2, 3, 4]           # first=1, rest=[2,3,4]\n\n# Copying\nshallow = lst2.copy()                 # same as lst2[:]\ndeep = copy.deepcopy([[1,2],[3,4]])   # deep copy for nested\n# input: nums = list(map(int, input(\"numbers: \").split()))\n\n# в”Җв”Җ 8. tuple в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Immutable, ordered, hashable (if elements are hashable)\nt1 = (1, 2, 3); t2 = (1,)            # COMMA required for single element!\nt3 = tuple([1, 2, 3])\n# GOTCHA: (1) is int, (1,) is tuple\nprint(f\"single: {t2}, type={type(t2)}\")  # (1,), <class 'tuple'>\nprint(f\"NOT tuple: type((1))={type((1))}\")  # <class 'int'>\n\n# Only 2 methods: count() and index()\na_t, b_t, c_t = t1                   # unpacking\nx, y = 10, 20; x, y = y, x           # swap via tuple unpacking\n\n# Mutable objects INSIDE a tuple CAN change  GOTCHA\ntricky = ([1, 2], [3, 4])\ntricky[0].append(3)                   # ([1,2,3], [3,4]) вҖ” no error!\n\n#  list vs tuple: list=mutable,slower | tuple=immutable,hashable,faster\n\n# Named tuple\nPoint = namedtuple(\"Point\", [\"x\", \"y\"])\np = Point(3, 4)\nprint(f\"namedtuple: {p}, x={p.x}\")    # Point(x=3, y=4), x=3\n\n# в”Җв”Җ 9. range в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nr1 = range(5)                         # 0,1,2,3,4\nr2 = range(2, 8)                      # 2,3,4,5,6,7\nr3 = range(0, 10, 2)                  # 0,2,4,6,8\nr4 = range(10, 0, -1)                 # countdown 10..1\nprint(f\"range: {list(r3)}, len={len(r1)}, 5 in range(10)={5 in range(10)}\")\n\n# в”Җв”Җ 10. set в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Mutable, unordered, unique elements, elements must be hashable\ns1 = {1, 2, 3}; s2 = {1, 2, 2, 3}    # duplicates removed => {1,2,3}\ns3 = set(\"hello\")                     # {'h','e','l','o'}\ns4 = set()                            # empty set\n# GOTCHA: {} creates dict, NOT set! Use set() for empty set\n\ns = {1, 2, 3}\ns.add(4)                              # add single\ns.update([5, 6])                      # add multiple\ns.discard(6)                          # remove if present (no error)\ns.remove(5)                           # remove (KeyError if missing!)\n\n# Set operations\na_s, b_s = {1, 2, 3, 4}, {3, 4, 5, 6}\nprint(f\"union: {a_s | b_s}\")          # {1,2,3,4,5,6}\nprint(f\"intersect: {a_s & b_s}\")      # {3,4}\nprint(f\"diff: {a_s - b_s}\")           # {1,2}\nprint(f\"sym_diff: {a_s ^ b_s}\")       # {1,2,5,6}\nprint(f\"subset: {{1,2}} <= a_s = {({1,2}).issubset(a_s)}\")  # True\n\n# Set comprehension\neven_set = {x for x in range(10) if x % 2 == 0}\n\n# в”Җв”Җ 11. frozenset в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Immutable set вҖ” can be dict key or set element\nfs = frozenset([1, 2, 3])\n# fs.add(4)  # AttributeError!\nd_fs = {fs: \"value\"}                  # works because hashable\n#  set vs frozenset: set=mutable | frozenset=immutable,hashable\n\n# в”Җв”Җ 12. dict в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Mutable key-value mapping. Keys must be hashable. Insertion-ordered (3.7+)\nd1 = {\"name\": \"Alice\", \"age\": 30}\nd2 = dict(name=\"Alice\", age=30)       # keyword args\nd3 = dict(zip([\"x\",\"y\"], [1,2]))      # from zip\nd4 = {i: i**2 for i in range(5)}      # comprehension\n\n# Access\nprint(f\"d1['name']={d1['name']}\")      # Alice\nprint(f\"get={d1.get('missing','default')}\")  # default (no KeyError)\n# d1['missing']  => KeyError\n\n# Modify\nd1[\"email\"] = \"a@b.com\"               # add/update\nd1.update({\"age\": 31, \"city\": \"NYC\"}) # update multiple\nd1.setdefault(\"country\", \"US\")        # set only if missing\n\n# Remove\npopped_d = d1.pop(\"email\")            # remove & return\nlast = d1.popitem()                   # remove last inserted (3.7+)\n\n# Views & iteration\nprint(f\"keys={list(d1.keys())}, values={list(d1.values())}\")\nprint(f\"items={list(d1.items())}\")\nprint(f\"'name' in d1: {'name' in d1}\")  # checks KEYS, not values\n\n# Merge (3.9+)\nmerged = {\"a\": 1} | {\"a\": 2, \"b\": 3}  # {'a':2,'b':3} вҖ” right wins\n\n# в”Җв”Җ 13. bytes & bytearray в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# bytes: immutable, each element 0-255\nb1 = b\"hello\"                         # ASCII bytes literal\nb2 = bytes([72, 101])                 # from int list\nb3 = \"hello\".encode(\"utf-8\")          # str -> bytes\nb4 = b\"hello\".decode(\"utf-8\")         # bytes -> str\nprint(f\"b1[0]={b1[0]}, hex={b1.hex()}\")  # 104, 68656c6c6f\n\n# bytearray: mutable version of bytes\nba = bytearray(b\"hello\")\nba[0] = 72                            # modify in place => b'Hello'\nba.append(33)                         # append '!'\n\n# memoryview: zero-copy view into bytes/bytearray buffer\ndata = bytearray(b\"Hello World\")\nmv = memoryview(data)\nmv[6:11] = b\"Earth\"                   # modifies data in place\nmv.release()\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                   ADVANCED                       в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 14. Enum в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Color(Enum):\n    RED = 1; GREEN = 2; BLUE = 3\n\nclass Direction(Enum):\n    NORTH = auto(); SOUTH = auto()     # auto-assigned values\n\nclass Permission(IntEnum):             # comparable with ints\n    READ = 4; WRITE = 2; EXECUTE = 1\n\nclass FileFlag(Flag):\n    READ = auto(); WRITE = auto(); EXECUTE = auto()\n\nprint(f\"Color.RED: name={Color.RED.name}, value={Color.RED.value}\")\nprint(f\"Color(1)={Color(1)}, Color['RED']={Color['RED']}\")\ncombined = FileFlag.READ | FileFlag.WRITE\nprint(f\"flags: {combined}, READ in it: {FileFlag.READ in combined}\")  # True\n\n# в”Җв”Җ 15. Type Hints в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Not runtime types вҖ” static analysis only\nnumbers: list[int] = [1, 2, 3]        # 3.9+ built-in generics\nmapping: dict[str, int] = {\"a\": 1}\nmaybe: Optional[str] = None           # str or None\nflex: Union[int, str] = \"hello\"       # int or str\nanything: Any = [1, \"two\"]\nconstant: Final = 42                  # should not reassign\ndirection: Literal[\"n\", \"s\"] = \"n\"\n\ndef greet(name: str, times: int = 1) -> str:\n    return f\"Hello, {name}! \" * times\n\ndef apply(func: Callable[[int, int], int], a: int, b: int) -> int:\n    return func(a, b)\n\nprint(f\"greet: {greet('Bob', 2)}\")     # Hello, Bob! Hello, Bob!\nprint(f\"apply: {apply(lambda a,b: a+b, 3, 4)}\")  # 7\n\n# в”Җв”Җ 16. Collections Module в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# defaultdict вҖ” auto-creates missing keys with factory\ndd = defaultdict(int)\ndd[\"a\"] += 1; dd[\"b\"] += 5\nprint(f\"defaultdict: {dict(dd)}, missing={dd['x']}\")  # {'a':1,'b':5}, 0\n\ndd_list = defaultdict(list)\ndd_list[\"fruits\"].append(\"apple\")      # no KeyError!\n\n# Counter вҖ” count occurrences\ncnt = Counter(\"abracadabra\")\nprint(f\"Counter: {cnt.most_common(2)}\")  # [('a',5),('b',2)]\n\n# deque вҖ” double-ended queue, O(1) append/pop both ends\ndq = deque([1, 2, 3])\ndq.appendleft(0); dq.append(4)        # [0,1,2,3,4]\ndq.popleft()                          # remove from left\ndq.rotate(1)                          # rotate right\nbounded = deque(maxlen=3)             # auto-discards oldest when full\nfor i in range(5): bounded.append(i)\nprint(f\"bounded: {bounded}\")           # deque([2,3,4], maxlen=3)\n\n# OrderedDict вҖ” remembers insertion order (redundant since dict 3.7+, but has move_to_end)\nod = OrderedDict([(\"b\", 2), (\"a\", 1)])\nod.move_to_end(\"a\")                   # move to end\nod.move_to_end(\"b\", last=False)       # move to beginning\n\n# ChainMap вҖ” search multiple dicts as one\ndefaults = {\"color\": \"blue\", \"size\": \"M\"}\nprefs = {\"color\": \"red\"}\ncm = ChainMap(prefs, defaults)\nprint(f\"ChainMap: color={cm['color']}, size={cm['size']}\")  # red, M\n\n# в”Җв”Җ 17. dataclass в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n@dataclass\nclass Person:\n    name: str\n    age: int\n    hobbies: list = field(default_factory=list)  # GOTCHA: never use mutable default!\n    def greet(self): return f\"Hi, I'm {self.name}!\"\n\n@dataclass(frozen=True)                # immutable dataclass\nclass Coordinate:\n    x: float; y: float\n\np1 = Person(\"Alice\", 30, [\"reading\"])\np2 = Person(\"Alice\", 30, [\"reading\"])\nprint(f\"dataclass: {p1}, eq={p1 == p2}\")  # auto __eq__\n# coord.x = 3.0 => FrozenInstanceError (frozen=True)\n\n# typing.NamedTuple вҖ” typed immutable record\nclass Employee(NamedTuple):\n    name: str; department: str; salary: float = 50000.0\n\nemp = Employee(\"Bob\", \"Eng\", 75000.0)\nprint(f\"NamedTuple: {emp.name}, {emp[1]}\")  # Bob, Eng\n\n# TypedDict вҖ” type hints for dict (runtime is still plain dict)\nclass Movie(TypedDict):\n    title: str; year: int; rating: float\n\nmovie: Movie = {\"title\": \"Inception\", \"year\": 2010, \"rating\": 8.8}\nprint(f\"TypedDict type: {type(movie)}\")  # <class 'dict'>\n\n# в”Җв”Җ 18. Iterator & Generator в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Iterator protocol: __iter__() + __next__()\nit = iter([10, 20, 30])\nprint(f\"next: {next(it)}, {next(it)}, {next(it)}\")  # 10, 20, 30\n# next(it) => StopIteration\n\n# Custom iterator\nclass Countdown:\n    def __init__(self, start): self.start = start\n    def __iter__(self): return self\n    def __next__(self):\n        if self.start <= 0: raise StopIteration\n        self.start -= 1\n        return self.start + 1\n\nprint(f\"Countdown: {list(Countdown(3))}\")  # [3, 2, 1]\n\n# Generator вҖ” lazy iterator via yield\ndef fibonacci(n):\n    a, b = 0, 1\n    for _ in range(n):\n        yield a\n        a, b = b, a + b\n\nprint(f\"fib: {list(fibonacci(8))}\")    # [0,1,1,2,3,5,8,13]\n\n# Generator expression (lazy list comprehension)\ngen = (x**2 for x in range(5))\nprint(f\"genexpr: {list(gen)}\")         # [0,1,4,9,16]\n\n# Generator with send()\ndef accumulator():\n    total = 0\n    while True:\n        value = yield total\n        if value is None: break\n        total += value\n\nacc = accumulator()\nnext(acc)                              # prime the generator\nprint(f\"send: {acc.send(10)}, {acc.send(20)}\")  # 10, 30\n\n# в”Җв”Җ 19. Callable Types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef add(a, b): return a + b           # function\nmultiply = lambda a, b: a * b         # lambda\n\nclass Multiplier:                      # callable object (__call__)\n    def __init__(self, factor): self.factor = factor\n    def __call__(self, value): return value * self.factor\n\ndouble = Multiplier(2)\nprint(f\"callable obj: {double(5)}, callable={callable(double)}\")  # 10, True\n\n# Closure\ndef make_adder(n):\n    def adder(x): return x + n\n    return adder\nadd5 = make_adder(5)\nprint(f\"closure: {add5(10)}\")          # 15\n\n# Partial\nadd10 = partial(add, 10)\nprint(f\"partial: {add10(5)}\")          # 15\n\n# в”Җв”Җ 20. Context Manager в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass ManagedResource:\n    def __enter__(self):\n        print(\"  acquired\"); return self\n    def __exit__(self, *args):\n        print(\"  released\"); return False\n\n@contextmanager\ndef managed():\n    print(\"  setup\"); yield \"value\"; print(\"  teardown\")\n\nwith ManagedResource(): pass           # acquired -> released\nwith managed() as v: print(f\"  val={v}\")  # setup -> val=value -> teardown\n\n# в”Җв”Җ 21. Regex Match в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nmatch = re.search(r\"(\\d{4})-(\\d{2})-(\\d{2})\", \"Date: 2024-01-15!\")\nif match:\n    print(f\"match: {match.group()}, groups={match.groups()}, span={match.span()}\")\n    # 2024-01-15, ('2024','01','15'), (6,16)\n\n# в”Җв”Җ 22. datetime в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nd = date(2024, 1, 15); today = date.today()\nprint(f\"date: {d}, weekday={d.weekday()}\")  # 0=Monday\nprint(f\"strftime: {d.strftime('%B %d, %Y')}\")  # January 15, 2024\n\ndt = datetime(2024, 1, 15, 14, 30, 45)\nnow = datetime.now(); utc = datetime.now(timezone.utc)\nparsed = datetime.strptime(\"2024-01-15\", \"%Y-%m-%d\")\n\ndelta = timedelta(days=7, hours=3)\nprint(f\"delta: {delta}, total_sec={delta.total_seconds()}\")\nprint(f\"date+delta: {d + delta}\")      # 2024-01-22\n\n# в”Җв”Җ 23. Decimal & Fraction в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Decimal вҖ” exact decimal arithmetic (no float rounding)\nprint(f\"Decimal: {Decimal('0.1') + Decimal('0.2')}\")  # 0.3  (exact!)\nprint(f\"float:   {0.1 + 0.2}\")                        # 0.300...04  (inexact)\ngetcontext().prec = 50                 # set precision\n\n# Fraction вҖ” exact rational arithmetic\nf1 = Fraction(1, 3); f2 = Fraction(1, 6)\nprint(f\"Fraction: {f1}+{f2}={f1+f2}\")  # 1/3+1/6=1/2\nprint(f\"from str: {Fraction('7/3')}\")   # 7/3\nprint(f\"pi approx: {Fraction(3.14159).limit_denominator(100)}\")  # 311/99\n\n# в”Җв”Җ 24. Path в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\np = Path(\".\")\nprint(f\"cwd={Path.cwd()}, home={Path.home()}, exists={p.exists()}\")\np2 = Path(\"folder\") / \"sub\" / \"file.txt\"  # path joining with /\nprint(f\"parent={p2.parent}, stem={p2.stem}, suffix={p2.suffix}\")\n\n# в”Җв”Җ 25. Queue Types (Thread-safe) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nq = Queue(maxsize=3); q.put(\"a\"); q.put(\"b\")\nprint(f\"FIFO: {q.get()}\")             # a\n\nlq = LifoQueue(); lq.put(\"a\"); lq.put(\"b\")\nprint(f\"LIFO: {lq.get()}\")            # b (stack)\n\npq = PriorityQueue()\npq.put((2, \"med\")); pq.put((1, \"high\")); pq.put((3, \"low\"))\nprint(f\"Priority: {pq.get()}\")        # (1, 'high')\n\n# в”Җв”Җ 26. Special Types в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# type() вҖ” the type of types (metaclass)\nprint(f\"type(42)={type(42)}, type(int)={type(int)}, type(type)={type(type)}\")\nMyClass = type(\"MyClass\", (object,), {\"x\": 10})  # dynamic class creation\n\n# object вҖ” base class of everything\nprint(f\"isinstance(42, object)={isinstance(42, object)}\")  # True\n\n# Ellipsis вҖ” placeholder in stubs, NumPy slicing\nprint(f\"... is Ellipsis: {... is Ellipsis}\")  # True\n\n# weakref вҖ” reference that doesn't prevent GC\nclass MyObj:\n    def __init__(self, name): self.name = name\nobj = MyObj(\"test\"); weak = weakref.ref(obj)\nprint(f\"weakref alive: {weak().name}\")  # test\ndel obj\nprint(f\"weakref dead: {weak()}\")        # None\n\n# в”Җв”Җ 27. Type Checking Utilities в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# type() vs isinstance()\nprint(f\"type(42)==int: {type(42)==int}\")                   # True\nprint(f\"isinstance(True,int): {isinstance(True,int)}\")    # True  GOTCHA: bool IS int\nprint(f\"isinstance(42,(int,float)): {isinstance(42,(int,float))}\")  # tuple of types\n\n# issubclass()\nprint(f\"issubclass(bool,int): {issubclass(bool,int)}\")    # True\n\n# is vs ==\na_id = [1,2]; b_id = a_id; c_id = [1,2]\nprint(f\"a is b: {a_id is b_id}, a is c: {a_id is c_id}, a==c: {a_id==c_id}\")\n# True (same obj), False (diff obj), True (same value)", "cheatSheet": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# CHEAT SHEET\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\nprint()\nprint(\"=\" * 70)\nprint(\"PYTHON DATA TYPES CHEAT SHEET\")\nprint(\"=\" * 70)\nprint(f\"\"\"\n{'Type':<15} {'Mutable':<9} {'Ordered':<9} {'Hashable':<10} {'Literal Syntax'}\n{'-'*15} {'-'*9} {'-'*9} {'-'*10} {'-'*25}\n{'int':<15} {'No':<9} {'N/A':<9} {'Yes':<10} 42, 0xFF, 0b1010\n{'float':<15} {'No':<9} {'N/A':<9} {'Yes':<10} 3.14, 1e-3, float(\"inf\")\n{'complex':<15} {'No':<9} {'N/A':<9} {'Yes':<10} 3+4j\n{'bool':<15} {'No':<9} {'N/A':<9} {'Yes':<10} True, False\n{'str':<15} {'No':<9} {'Yes':<9} {'Yes':<10} \"hello\", f\"{{x}}\"\n{'bytes':<15} {'No':<9} {'Yes':<9} {'Yes':<10} b\"hello\"\n{'bytearray':<15} {'Yes':<9} {'Yes':<9} {'No':<10} bytearray(b\"hi\")\n{'list':<15} {'Yes':<9} {'Yes':<9} {'No':<10} [1, 2, 3]\n{'tuple':<15} {'No':<9} {'Yes':<9} {'Yes*':<10} (1, 2, 3)\n{'range':<15} {'No':<9} {'Yes':<9} {'Yes':<10} range(10)\n{'set':<15} {'Yes':<9} {'No':<9} {'No':<10} {{1, 2, 3}}\n{'frozenset':<15} {'No':<9} {'No':<9} {'Yes':<10} frozenset([1,2])\n{'dict':<15} {'Yes':<9} {'Yes**':<9} {'No':<10} {{\"a\": 1}}\n{'NoneType':<15} {'N/A':<9} {'N/A':<9} {'Yes':<10} None\n{'Decimal':<15} {'No':<9} {'N/A':<9} {'Yes':<10} Decimal(\"0.1\")\n{'Fraction':<15} {'No':<9} {'N/A':<9} {'Yes':<10} Fraction(1, 3)\n\n*  tuple hashable only if all elements hashable\n** dict insertion-ordered since Python 3.7\n\nKEY GOTCHAS:\n  {{}} is dict, NOT set        -> use set() for empty set\n  (1) is int, NOT tuple       -> use (1,) for single-element tuple\n  0.1+0.2 != 0.3              -> use math.isclose() or Decimal\n  bool(\"False\") is True       -> non-empty string is truthy\n  isinstance(True, int)=True  -> bool is subclass of int\n  mutable default args shared -> use field(default_factory=list)\n  list.sort() returns None    -> use sorted() for new list\n\"\"\")", "reference": ""}, "decorators.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  PYTHON DECORATORS вҖ” Condensed Guide\n#  @decorator is shortcut for: func = decorator(func)\n#  FastAPI's @app.get(\"/path\") is a decorator factory!\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\nimport time, functools\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                  BEGINNER                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Functions Are Objects в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef greet(): return \"Hello!\"\nmy_func = greet            # no parens = reference, not call\nprint(my_func())           # Hello!\n\ndef call_twice(func):\n    print(func())\n    print(func())\ncall_twice(greet)          # prints \"Hello!\" twice\n\n# в”Җв”Җ 2. Closures вҖ” Functions That Return Functions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef make_greeter(name):\n    def greeter():\n        return f\"Hello, {name}!\"   # \"remembers\" name from outer scope\n    return greeter\n\nprint(make_greeter(\"Alice\")())  # Hello, Alice!\nprint(make_greeter(\"Bob\")())    # Hello, Bob!\n\n# в”Җв”Җ 3. Simplest Decorator в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# @my_decorator is EXACTLY: say_hello = my_decorator(say_hello)\ndef my_decorator(func):\n    def wrapper():\n        print(\"BEFORE\")\n        result = func()\n        print(\"AFTER\")\n        return result\n    return wrapper\n\n@my_decorator\ndef say_hello():\n    print(\"Hello!\")\n    return \"done\"\nsay_hello()  # BEFORE -> Hello! -> AFTER\n\nprint(\"=\" * 50)\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘               INTERMEDIATE                       в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 4. Decorator with *args, **kwargs в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef log_call(func):\n    def wrapper(*args, **kwargs):\n        print(f\"Calling {func.__name__}({args}, {kwargs})\")\n        return func(*args, **kwargs)\n    return wrapper\n\n@log_call\ndef add(a, b): return a + b\nprint(add(3, 5))  # Calling add((3, 5), {}) -> 8\n\n# в”Җв”Җ 5. Decorator Factory (WITH Parameters) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# THREE nesting levels: outer(params) -> decorator(func) -> wrapper(*args)\n# THIS IS HOW @app.get(\"/path\") WORKS!\ndef repeat(times):\n    def decorator(func):\n        def wrapper(*args, **kwargs):\n            for _ in range(times):\n                result = func(*args, **kwargs)\n            return result\n        return wrapper\n    return decorator\n\n@repeat(times=3)\ndef say_hi(name): print(f\"Hi {name}!\")\nsay_hi(\"Alice\")  # prints \"Hi Alice!\" three times\n# Equivalent: say_hi = repeat(3)(say_hi)\n\n# в”Җв”Җ 6. functools.wraps вҖ” Preserve Metadata в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef bad_dec(func):                           # without wraps:\n    def wrapper(*a, **kw): return func(*a, **kw)\n    return wrapper\ndef good_dec(func):                          # with wraps:\n    @functools.wraps(func)\n    def wrapper(*a, **kw): return func(*a, **kw)\n    return wrapper\n\n@bad_dec\ndef func_bad(): \"\"\"My docstring\"\"\"\n@good_dec\ndef func_good(): \"\"\"My docstring\"\"\"\nprint(f\"Bad:  name={func_bad.__name__}, doc={func_bad.__doc__}\")    # wrapper, None\nprint(f\"Good: name={func_good.__name__}, doc={func_good.__doc__}\")  # func_good, My docstring\n\n# в”Җв”Җ 7. Stacking Decorators в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# @A / @B / def f  вүЎ  f = A(B(f))  вҖ” bottom-up wrap, top-down execute\ndef bold(f):\n    def w(*a, **kw): return f\"<b>{f(*a, **kw)}</b>\"\n    return w\ndef italic(f):\n    def w(*a, **kw): return f\"<i>{f(*a, **kw)}</i>\"\n    return w\n\n@bold     # outer\n@italic   # inner\ndef format_text(text): return text\nprint(format_text(\"Hello\"))  # <b><i>Hello</i></b>\n\n# в”Җв”Җ 8. Timer Decorator в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef timer(func):\n    @functools.wraps(func)\n    def wrapper(*args, **kwargs):\n        start = time.time()\n        result = func(*args, **kwargs)\n        print(f\"{func.__name__} took {time.time() - start:.4f}s\")\n        return result\n    return wrapper\n\n@timer\ndef slow_function():\n    time.sleep(0.5)\n    return \"done\"\nslow_function()  # slow_function took 0.50XXs\n\n# в”Җв”Җ 9. Retry Decorator в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef retry(max_attempts=3):\n    def decorator(func):\n        @functools.wraps(func)\n        def wrapper(*args, **kwargs):\n            for attempt in range(1, max_attempts + 1):\n                try: return func(*args, **kwargs)\n                except Exception as e:\n                    if attempt == max_attempts: raise\n                    print(f\"  Attempt {attempt} failed: {e}\")\n        return wrapper\n    return decorator\n\n_attempt = 0\n@retry(max_attempts=3)\ndef unreliable_api():\n    global _attempt; _attempt += 1\n    if _attempt < 3: raise ConnectionError(\"Server down\")\n    return \"Success!\"\n_attempt = 0\nprint(unreliable_api())  # fails twice, succeeds on third\n\n# в”Җв”Җ 10. Cache / Memoize в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef cache(func):\n    stored = {}\n    @functools.wraps(func)\n    def wrapper(*args):\n        if args not in stored: stored[args] = func(*args)\n        return stored[args]\n    return wrapper\n\n@cache\ndef expensive_multiply(a, b): return a * b\nprint(expensive_multiply(3, 4))  # computes -> 12\nprint(expensive_multiply(3, 4))  # cached   -> 12\n\n# в”Җв”Җ 11. Auth / Role Check в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ncurrent_user = {\"name\": \"Alice\", \"role\": \"admin\"}\ndef require_role(role):\n    def decorator(func):\n        @functools.wraps(func)\n        def wrapper(*args, **kwargs):\n            if current_user[\"role\"] != role:\n                return f\"ACCESS DENIED: need {role}, have {current_user['role']}\"\n            return func(*args, **kwargs)\n        return wrapper\n    return decorator\n\n@require_role(\"admin\")\ndef delete_data(): return \"All data deleted!\"\n@require_role(\"superadmin\")\ndef shutdown(): return \"Shutting down...\"\nprint(delete_data())  # All data deleted!\nprint(shutdown())     # ACCESS DENIED: need superadmin, have admin\nprint(\"=\" * 50)\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                  ADVANCED                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 12. Class-Based Decorator (no params) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass CountCalls:  # __call__ makes instances callable -> works as decorator\n    def __init__(self, func): self.func, self.count = func, 0\n    def __call__(self, *args, **kwargs):\n        self.count += 1\n        print(f\"{self.func.__name__} called {self.count} time(s)\")\n        return self.func(*args, **kwargs)\n\n@CountCalls  # say_wow = CountCalls(say_wow)\ndef say_wow(): return \"Wow!\"\nsay_wow(); say_wow()  # called 1 time(s) / called 2 time(s)\n\n# в”Җв”Җ 13. Class-Based Decorator WITH Parameters в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass RateLimit:\n    def __init__(self, max_calls):\n        self.max_calls = max_calls\n    def __call__(self, func):\n        call_count = {\"n\": 0}\n        def wrapper(*args, **kwargs):\n            call_count[\"n\"] += 1\n            if call_count[\"n\"] > self.max_calls:\n                return f\"RATE LIMITED! Max {self.max_calls} calls\"\n            return func(*args, **kwargs)\n        return wrapper\n\n@RateLimit(max_calls=2)\ndef get_secret(): return \"The secret is 42\"\nprint(get_secret())  # The secret is 42\nprint(get_secret())  # The secret is 42\nprint(get_secret())  # RATE LIMITED! Max 2 calls\n\n# в”Җв”Җ 14. Validation Decorator в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef validate_positive(func):\n    @functools.wraps(func)\n    def wrapper(*args, **kw):\n        for a in args:\n            if isinstance(a, (int, float)) and a < 0:\n                raise ValueError(f\"Negative not allowed: {a}\")\n        return func(*args, **kw)\n    return wrapper\n\n@validate_positive\ndef calculate_area(w, h): return w * h\nprint(calculate_area(5, 10))  # 50\ntry: calculate_area(-3, 10)\nexcept ValueError as e: print(f\"Error: {e}\")  # Negative not allowed: -3\n\n# в”Җв”Җ 15. FastAPI @app.get() Pattern вҖ” Full Simulation в”Җв”Җв”Җв”Җ\n# Class stores routes dict; .get()/.post() are decorator factories\nclass SimpleAPI:\n    def __init__(self):\n        self.routes = {\"GET\": {}, \"POST\": {}, \"PUT\": {}, \"DELETE\": {}}\n    def _register(self, method, path):\n        def decorator(func):\n            self.routes[method][path] = func\n            return func\n        return decorator\n    def get(self, path):    return self._register(\"GET\", path)\n    def post(self, path):   return self._register(\"POST\", path)\n    def put(self, path):    return self._register(\"PUT\", path)\n    def delete(self, path): return self._register(\"DELETE\", path)\n    def request(self, method, path, **kwargs):\n        m = method.upper()\n        if m in self.routes and path in self.routes[m]:\n            return self.routes[m][path](**kwargs)\n        return {\"error\": f\"{m} {path} not found\"}\n\napi = SimpleAPI()\n\n@api.get(\"/users\")\ndef list_users(): return [{\"id\": 1, \"name\": \"Alice\"}, {\"id\": 2, \"name\": \"Bob\"}]\n@api.post(\"/users\")\ndef create_user(name=\"Unknown\"): return {\"id\": 3, \"name\": name, \"created\": True}\n@api.delete(\"/users/1\")\ndef delete_user(): return {\"id\": 1, \"deleted\": True}\n\nprint(\"GET /users   ->\", api.request(\"GET\", \"/users\"))\nprint(\"POST /users  ->\", api.request(\"POST\", \"/users\", name=\"Charlie\"))\nprint(\"DELETE       ->\", api.request(\"DELETE\", \"/users/1\"))\nprint(\"GET /unknown ->\", api.request(\"GET\", \"/unknown\"))\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—", "cheatSheet": "# в•‘                 CHEAT SHEET                      в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n#\n# PATTERN                    STRUCTURE                          USE CASE\n# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Simple decorator           def dec(func):                     logging, timing\n#   @dec / def f               def wrapper(*a,**kw): ...\n#                              return wrapper\n#\n# Decorator factory          def factory(param):                auth, retry\n#   @factory(param)             def dec(func):\n#   def f                         def wrapper(*a,**kw): ...\n#                                 return wrapper\n#                               return dec\n#\n# Class decorator            class Dec:                         counting, state\n#   @Dec / def f               __init__(self, func)\n#                              __call__(self, *a, **kw)\n#\n# Class factory              class Dec:                         rate limiting\n#   @Dec(param)                __init__(self, param)\n#   def f                      __call__(self, func) -> wrapper\n#\n# @app.get(\"/path\")          class App:                         route registration\n#   (FastAPI)                   def get(self, path):\n#                                 def dec(func):\n#                                   routes[path] = func\n#                                 return dec\n#\n# KEY RULES:\n#   @A / @B / def f  ->  f = A(B(f))  ->  bottom-up wrap, top-down execute\n#   Always use @functools.wraps(func) to preserve __name__ and __doc__\n#   @decorator vs @decorator() вҖ” parens mean factory (extra nesting level)", "reference": ""}, "exception-handling.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  PYTHON EXCEPTION HANDLING вҖ” Complete Guide (Condensed)\n#\n#  Exception = runtime error that breaks normal flow\n#  Handling = catch it, deal with it, keep running\n#\n#  try/except vs if/else:\n#    if/else  вҶ’ check BEFORE doing   (LBYL: Look Before You Leap)\n#    try/except вҶ’ just DO it, catch failure  (EAFP: Easier to Ask Forgiveness)\n#    Python community prefers EAFP\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                  BEGINNER                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Basic try/except в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Without handling:  1/0  вҶ’  ZeroDivisionError  вҶ’  program CRASHES\n# With handling:     catch it, print message, program continues\ntry:\n    result = 10 / 0\nexcept ZeroDivisionError:\n    print(\"Cannot divide by zero\")       # this runs\nprint(\"Program continues\")               # still alive!\n\n# в”Җв”Җ 2. Catch specific vs generic в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# ALWAYS catch specific exceptions first вҖ” generic last\ntry:\n    x = int(\"abc\")\nexcept ValueError:                        # specific вҖ” catches int(\"abc\")\n    print(\"Not a number\")\nexcept Exception:                         # generic вҖ” catches everything else\n    print(\"Something else went wrong\")\n\n# в”Җв”Җ 3. Access the error message в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ntry:\n    [1, 2, 3][10]\nexcept IndexError as e:                   # \"as e\" captures the error object\n    print(f\"Error: {e}\")                  # \"list index out of range\"\n    print(f\"Type:  {type(e).__name__}\")   # \"IndexError\"\n\n# в”Җв”Җ 4. Multiple exceptions in one line в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ntry:\n    x = int(\"abc\")\nexcept (ValueError, TypeError) as e:     # catch either вҖ” same handler\n    print(f\"Bad input: {e}\")\n\n# vs separate handlers (different logic per error):\ntry:\n    data = {\"a\": 1}\n    print(data[\"b\"])\nexcept KeyError:\n    print(\"Key not found\")               # runs for missing dict key\nexcept TypeError:\n    print(\"Wrong type\")                   # runs for wrong type operation\n\n# в”Җв”Җ 5. try / except / else / finally в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# else = runs ONLY if no exception | finally = runs ALWAYS\ntry:\n    result = 10 / 2\nexcept ZeroDivisionError:\n    print(\"Error!\")                       # skipped (no error)\nelse:\n    print(f\"Result: {result}\")            # runs because no exception вҶ’ 5.0\nfinally:\n    print(\"Cleanup done\")                # ALWAYS runs вҖ” error or not\n\n# COMPARISON:\n# try:     code that MIGHT fail\n# except:  handle the failure\n# else:    runs if try SUCCEEDED (no exception) вҖ” put success logic here, not in try\n# finally: runs ALWAYS вҖ” cleanup (close files, connections, release locks)\n\n# в”Җв”Җ 6. Why use else? в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Without else вҖ” accidental catch:\ntry:\n    value = int(\"5\")\n    result = value / 0       # BUG! вҖ” ZeroDivisionError caught by wrong handler\nexcept (ValueError, ZeroDivisionError):\n    print(\"Parse error?\")    # misleading вҖ” it's actually a division error\n\n# With else вҖ” clean separation:\ntry:\n    value = int(\"5\")         # only THIS can raise ValueError\nexcept ValueError:\n    print(\"Parse error\")\nelse:\n    result = value / 2       # this is NOT inside try вҖ” its errors bubble up naturally\n    print(f\"Result: {result}\")\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘               INTERMEDIATE                       в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 7. raise вҖ” Throw your own exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef withdraw(amount):\n    if amount <= 0:\n        raise ValueError(\"Amount must be positive\")    # throw error\n    if amount > 1000:\n        raise ValueError(\"Cannot withdraw over 1000\")\n    return f\"Withdrew {amount}\"\n\ntry:\n    print(withdraw(-50))\nexcept ValueError as e:\n    print(f\"Failed: {e}\")     # Failed: Amount must be positive\n\n# в”Җв”Җ 8. re-raise вҖ” Catch, log, then re-throw в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Catch for logging but let it propagate up\ndef process_data(data):\n    try:\n        return int(data)\n    except ValueError:\n        print(f\"LOG: bad data '{data}'\")  # log it\n        raise                             # re-raise SAME exception (bare raise)\n\ntry:\n    process_data(\"abc\")\nexcept ValueError as e:\n    print(f\"Caller caught: {e}\")          # still reaches caller\n\n# raise vs raise e:\n#   raise     вҶ’ preserves original traceback (PREFERRED)\n#   raise e   вҶ’ resets traceback to this line (loses context)\n\n# в”Җв”Җ 9. raise from вҖ” Chain exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# \"The real cause was X, but I'm reporting Y\"\ndef connect_db():\n    try:\n        raise ConnectionError(\"DB timeout\")\n    except ConnectionError as e:\n        raise RuntimeError(\"Service unavailable\") from e  # chains original cause\n\ntry:\n    connect_db()\nexcept RuntimeError as e:\n    print(f\"Error: {e}\")                  # Service unavailable\n    print(f\"Cause: {e.__cause__}\")        # DB timeout\n\n# raise X from None вҶ’ suppress chain (hide original cause)\n\n# в”Җв”Җ 10. Custom exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Inherit from Exception (or a subclass). Use for domain-specific errors.\nclass InsufficientFundsError(Exception):\n    def __init__(self, balance, amount):\n        self.balance = balance\n        self.amount = amount\n        super().__init__(f\"Cannot withdraw {amount}, balance is {balance}\")\n\nclass AccountLockedError(Exception):\n    pass                                  # simplest custom exception вҖ” just a name\n\nclass BankError(Exception):              # base class for all bank errors\n    pass\nclass OverdraftError(BankError):         # hierarchy вҖ” catch BankError catches both\n    pass\nclass FraudError(BankError):\n    pass\n\ntry:\n    raise InsufficientFundsError(100, 500)\nexcept InsufficientFundsError as e:\n    print(f\"{e}\")                         # Cannot withdraw 500, balance is 100\n    print(f\"Short by: {e.amount - e.balance}\")  # 400 вҖ” access custom attrs\n\n# в”Җв”Җ 11. LBYL vs EAFP в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndata = {\"name\": \"Alice\", \"age\": 30}\n\n# LBYL (Look Before You Leap) вҖ” check first, then act\nif \"email\" in data:\n    email = data[\"email\"]\nelse:\n    email = \"N/A\"\n\n# EAFP (Easier to Ask Forgiveness) вҖ” just try it\ntry:\n    email = data[\"email\"]\nexcept KeyError:\n    email = \"N/A\"\n\n# COMPARISON:\n# LBYL:  if os.path.exists(f): open(f)   вҶ’ race condition! file could be deleted between check and open\n# EAFP:  try: open(f) except FileNotFoundError  вҶ’ atomic, no race condition\n# LBYL:  if x != 0: y = 10/x             вҶ’ safe for simple checks\n# EAFP:  try: y = 10/x except ZeroDivision  вҶ’ better when multiple things can fail\n# Python prefers EAFP. Java/C# prefer LBYL.\n\n# в”Җв”Җ 12. Common built-in exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nexamples = {\n    \"ValueError\":       lambda: int(\"abc\"),                # wrong value for type\n    \"TypeError\":        lambda: \"2\" + 2,                   # wrong type in operation\n    \"KeyError\":         lambda: {}[\"missing\"],              # dict key not found\n    \"IndexError\":       lambda: [1,2][10],                  # list index out of range\n    \"AttributeError\":   lambda: None.split(),               # object has no attribute\n    \"NameError\":        lambda: eval(\"undefined_var\"),       # variable not defined\n    \"FileNotFoundError\":lambda: open(\"nonexistent.txt\"),    # file not found\n    \"ZeroDivisionError\":lambda: 1/0,                       # division by zero\n    \"ImportError\":      lambda: __import__(\"nonexistent\"),  # module not found\n    \"StopIteration\":    lambda: next(iter([])),             # iterator exhausted\n    \"OverflowError\":    lambda: 10.0 ** 1000,              # number too large\n    \"RecursionError\":   None,                               # max recursion depth\n    \"PermissionError\":  None,                               # OS denies access\n    \"TimeoutError\":     None,                               # operation timed out\n    \"ConnectionError\":  None,                               # network connection failed\n    \"UnicodeDecodeError\": lambda: b'\\x80'.decode('utf-8'),  # invalid unicode\n}\n\nfor name, fn in examples.items():\n    if fn is None: continue\n    try:\n        fn()\n    except Exception as e:\n        print(f\"  {type(e).__name__:25s} вҶ’ {e}\")\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                  ADVANCED                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 13. Exception hierarchy в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# BaseException вҶ’ Exception вҶ’ ValueError, TypeError, ...\n# BaseException\n# в”ңв”Җв”Җ SystemExit            (sys.exit() вҖ” don't catch!)\n# в”ңв”Җв”Җ KeyboardInterrupt     (Ctrl+C вҖ” don't catch!)\n# в”ңв”Җв”Җ GeneratorExit         (generator closed вҖ” don't catch!)\n# в””в”Җв”Җ Exception             (all \"normal\" exceptions вҖ” CATCH THIS)\n#     в”ңв”Җв”Җ ValueError, TypeError, KeyError, IndexError, ...\n#     в”ңв”Җв”Җ OSError\n#     в”Ӯ   в”ңв”Җв”Җ FileNotFoundError, PermissionError, TimeoutError, ConnectionError\n#     в”Ӯ   в””в”Җв”Җ FileExistsError, IsADirectoryError\n#     в”ңв”Җв”Җ RuntimeError\n#     в”Ӯ   в””в”Җв”Җ RecursionError\n#     в”ңв”Җв”Җ LookupError\n#     в”Ӯ   в”ңв”Җв”Җ KeyError, IndexError\n#     в”ңв”Җв”Җ ArithmeticError\n#     в”Ӯ   в”ңв”Җв”Җ ZeroDivisionError, OverflowError, FloatingPointError\n#     в””в”Җв”Җ StopIteration, StopAsyncIteration\n#\n# RULE: catch Exception, NOT BaseException\n#   except Exception:         вҶ’ catches all normal errors (GOOD)\n#   except BaseException:     вҶ’ also catches Ctrl+C and sys.exit() (BAD)\n#   except:                   вҶ’ same as BaseException (BAD вҖ” never use bare except)\n\n# в”Җв”Җ 14. Context managers вҖ” auto-cleanup with exceptions в”Җв”Җ\n# try/finally vs with statement:\n\n# Manual (error-prone):\nf = None\ntry:\n    f = open(\"test_exc.txt\", \"w\")\n    f.write(\"data\")\nfinally:\n    if f: f.close()                       # must remember to close!\n\n# Context manager (automatic):\nwith open(\"test_exc.txt\", \"w\") as f:\n    f.write(\"data\")\n# f.close() called AUTOMATICALLY вҖ” even if exception occurs inside with block\n\n# COMPARISON:\n# try/finally:  you handle cleanup  вҶ’  easy to forget, verbose\n# with:         auto-cleanup        вҶ’  clean, safe, Pythonic\n# Common with:  open(), lock, db connection, http session, tempfile\n\n# в”Җв”Җ 15. Nested try blocks в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef fetch_and_parse(url_data):\n    try:                                  # outer: network layer\n        try:                              # inner: parsing layer\n            return int(url_data)\n        except ValueError:\n            print(\"  Parse failed, using default\")\n            return 0\n    except Exception as e:\n        print(f\"  Unexpected: {e}\")\n        return -1\n\nprint(fetch_and_parse(\"123\"))             # 123\nprint(fetch_and_parse(\"abc\"))             # Parse failed вҶ’ 0\n\n# Better pattern вҖ” separate into functions instead of nesting:\ndef parse_safe(data):\n    try: return int(data)\n    except ValueError: return 0\n\ndef fetch_and_parse_v2(data):\n    try: return parse_safe(data)\n    except Exception: return -1\n\n# в”Җв”Җ 16. Exception groups (Python 3.11+) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# ExceptionGroup = multiple exceptions at once (from parallel tasks)\n# except* = catch some types, let others propagate\ndef run_tasks():\n    errors = []\n    for i, val in enumerate([\"1\", \"abc\", \"3\", None]):\n        try:\n            int(val)\n        except (ValueError, TypeError) as e:\n            errors.append(e)\n    if errors:\n        raise ExceptionGroup(\"batch failed\", errors)\n\ntry:\n    run_tasks()\nexcept ExceptionGroup as eg:\n    print(f\"ExceptionGroup: {len(eg.exceptions)} errors\")\n    for e in eg.exceptions:\n        print(f\"  {type(e).__name__}: {e}\")\n\n# except* (3.11+) вҖ” catch specific types from group:\n# try:\n#     run_tasks()\n# except* ValueError as eg:       вҶ’ catches only ValueErrors from the group\n#     print(f\"{len(eg.exceptions)} ValueErrors\")\n# except* TypeError as eg:        вҶ’ catches only TypeErrors\n#     print(f\"{len(eg.exceptions)} TypeErrors\")\n\n# в”Җв”Җ 17. Warnings vs Exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nimport warnings\n\n# Exception:  STOPS execution  |  Warning:  CONTINUES execution\n# raise ValueError(\"bad\")     |  warnings.warn(\"careful\", UserWarning)\n\nwarnings.warn(\"Deprecated function\", DeprecationWarning)   # program continues\n# Control behavior:\n# warnings.filterwarnings(\"ignore\", category=DeprecationWarning)   вҶ’ suppress\n# warnings.filterwarnings(\"error\", category=DeprecationWarning)    вҶ’ turn into exception\n\n# в”Җв”Җ 18. Logging exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nimport logging, traceback\n\nlogging.basicConfig(level=logging.DEBUG)\n\ntry:\n    1 / 0\nexcept ZeroDivisionError:\n    logging.exception(\"Math error\")       # logs full traceback automatically\n    # vs logging.error(\"Math error\")      # logs message only вҖ” no traceback\n\n# Manual traceback capture:\ntry:\n    1 / 0\nexcept ZeroDivisionError:\n    tb = traceback.format_exc()           # full traceback as string\n    print(f\"Traceback:\\n{tb}\")\n\n# в”Җв”Җ 19. Decorator for exception handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nimport functools\n\ndef safe_call(default=None):\n    def decorator(func):\n        @functools.wraps(func)\n        def wrapper(*args, **kwargs):\n            try:\n                return func(*args, **kwargs)\n            except Exception as e:\n                print(f\"  {func.__name__} failed: {e}\")\n                return default\n        return wrapper\n    return decorator\n\n@safe_call(default=0)\ndef risky_divide(a, b): return a / b\n\nprint(risky_divide(10, 2))               # 5.0\nprint(risky_divide(10, 0))               # risky_divide failed вҶ’ 0\n\n# в”Җв”Җ 20. Retry decorator with specific exceptions в”Җв”Җв”Җ\ndef retry(exceptions=(Exception,), max_tries=3, delay=0):\n    import time\n    def decorator(func):\n        @functools.wraps(func)\n        def wrapper(*args, **kwargs):\n            for attempt in range(1, max_tries + 1):\n                try:\n                    return func(*args, **kwargs)\n                except exceptions as e:\n                    if attempt == max_tries:\n                        raise\n                    print(f\"  Retry {attempt}/{max_tries}: {e}\")\n                    if delay: time.sleep(delay)\n        return wrapper\n    return decorator\n\n_count = 0\n@retry(exceptions=(ConnectionError, TimeoutError), max_tries=3)\ndef call_api():\n    global _count; _count += 1\n    if _count < 3: raise ConnectionError(f\"Attempt {_count} failed\")\n    return \"API response\"\n\n_count = 0\nprint(call_api())                         # retries twice, succeeds third time\n\n# в”Җв”Җ 21. Context manager for exception handling в”Җв”Җв”Җв”Җв”Җв”Җ\nfrom contextlib import contextmanager, suppress\n\n# suppress вҖ” ignore specific exceptions:\nfrom collections import defaultdict\nd = {}\nwith suppress(KeyError):                  # silently ignores KeyError\n    val = d[\"missing\"]\n# equivalent to: try: d[\"missing\"] except KeyError: pass\n\n# Custom context manager:\n@contextmanager\ndef error_boundary(label):\n    try:\n        yield\n    except Exception as e:\n        print(f\"[{label}] Caught: {type(e).__name__}: {e}\")\n\nwith error_boundary(\"data-load\"):\n    int(\"not_a_number\")                   # caught and logged, program continues\n\n# в”Җв”Җ 22. Assertions вҖ” Debug-time checks в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# assert = \"this MUST be true, crash if not\"\n# Removed when running with python -O (optimized) вҖ” NEVER use for validation!\ndef divide(a, b):\n    assert b != 0, \"Divisor cannot be zero\"     # dev check вҖ” NOT for user input!\n    return a / b\n\ntry:\n    divide(10, 0)\nexcept AssertionError as e:\n    print(f\"Assertion: {e}\")              # Divisor cannot be zero\n\n# COMPARISON:\n# assert x > 0        вҶ’ debug check, removed with -O, for IMPOSSIBLE states\n# if x <= 0: raise    вҶ’ validation, always runs, for USER INPUT / API boundaries\n# Rule: if it could happen in production, use raise, not assert\n\n# в”Җв”Җ 23. sys.exc_info() вҖ” Low-level exception access в”Җ\nimport sys\ntry:\n    1 / 0\nexcept:\n    exc_type, exc_value, exc_tb = sys.exc_info()\n    print(f\"Type:  {exc_type.__name__}\")  # ZeroDivisionError\n    print(f\"Value: {exc_value}\")          # division by zero\n    print(f\"Line:  {exc_tb.tb_lineno}\")   # line number where error occurred\n\n# в”Җв”Җ 24. Exception in generators в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef safe_generator(items):\n    for item in items:\n        try:\n            yield int(item)               # yields valid, skips invalid\n        except (ValueError, TypeError):\n            print(f\"  Skipping invalid: {item}\")\n\nresults = list(safe_generator([\"1\", \"abc\", \"3\", None, \"5\"]))\nprint(f\"Valid items: {results}\")          # [1, 3, 5]\n\n# generator.throw() вҖ” inject exception into generator:\ndef gen():\n    while True:\n        try:\n            value = yield\n            print(f\"  Got: {value}\")\n        except ValueError:\n            print(\"  Received ValueError!\")\n\ng = gen(); next(g)                        # prime generator\ng.send(\"hello\")                           # Got: hello\ng.throw(ValueError, \"bad data\")           # Received ValueError!\n\n# в”Җв”Җ 25. Async exception handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nimport asyncio\n\nasync def async_divide(a, b):\n    await asyncio.sleep(0.01)             # simulate I/O\n    if b == 0: raise ZeroDivisionError(\"async division by zero\")\n    return a / b\n\nasync def main():\n    # Single async try/except вҖ” same as sync\n    try:\n        result = await async_divide(10, 0)\n    except ZeroDivisionError as e:\n        print(f\"Async error: {e}\")\n\n    # Gather with return_exceptions вҖ” parallel error handling\n    results = await asyncio.gather(\n        async_divide(10, 2), async_divide(10, 0), async_divide(6, 3),\n        return_exceptions=True,\n    )\n    for r in results:\n        if isinstance(r, Exception):\n            print(f\"  Failed: {r}\")       # Failed: async division by zero\n        else:\n            print(f\"  Result: {r}\")       # Result: 5.0, Result: 2.0\n\nasyncio.run(main())\n\n# в”Җв”Җ 26. Anti-patterns вҖ” What NOT to do в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\n# BAD: bare except (catches Ctrl+C, sys.exit!)\n# try: ...\n# except:                           вҶ’ catches EVERYTHING including KeyboardInterrupt\n#     pass                          вҶ’ silently swallows вҖ” impossible to debug\n\n# GOOD:\n# except Exception:                 вҶ’ catches all normal errors, not Ctrl+C/sys.exit\n\n# BAD: catch-all with pass (silent failure)\n# try: do_something()\n# except Exception: pass            вҶ’ error vanishes вҖ” no one knows it happened\n\n# GOOD: at minimum, log it\n# except Exception as e:\n#     logging.exception(f\"Failed: {e}\")\n\n# BAD: too broad try block\n# try:\n#     data = read_file()            # could fail\n#     parsed = parse(data)          # could fail\n#     result = calculate(parsed)    # could fail\n# except Exception: ...             # which one failed? can't tell!\n\n# GOOD: narrow try blocks\n# data = read_file()                # let it crash if file missing\n# try:\n#     parsed = parse(data)          # only catch parse errors\n# except ValueError: ...\n\n# BAD: using exceptions for flow control\n# try: d[\"key\"]                     # вҶ’ just use d.get(\"key\", default)\n# except KeyError: default\n\n# BAD: assert for validation\n# assert user_input > 0             # removed with -O flag!\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—", "cheatSheet": "# в•‘                 CHEAT SHEET                      в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n#\n# SYNTAX              в”Ӯ PURPOSE                        в”Ӯ EXAMPLE\n# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# try/except          в”Ӯ catch and handle error         в”Ӯ except ValueError as e:\n# try/except/else     в”Ӯ else = success path            в”Ӯ else: print(result)\n# try/except/finally  в”Ӯ finally = always cleanup       в”Ӯ finally: f.close()\n# except (A, B):      в”Ӯ catch multiple types           в”Ӯ except (Key, Index):\n# except Exception:   в”Ӯ catch all normal errors        в”Ӯ NOT BaseException!\n# as e                в”Ӯ capture error object           в”Ӯ e.args, str(e), type(e)\n# raise               в”Ӯ throw / re-raise exception     в”Ӯ raise ValueError(\"msg\")\n# raise X from Y      в”Ӯ chain exceptions               в”Ӯ raise New() from original\n# assert cond, msg    в”Ӯ debug check (removed with -O)  в”Ӯ assert x > 0, \"positive\"\n#\n# CUSTOM EXCEPTIONS:\n#   class MyError(Exception):              minimal вҖ” just a name\n#   class MyError(Exception):              with data:\n#       def __init__(self, detail):            super().__init__(f\"...\")\n#           self.detail = detail               self.detail = detail\n#   class Base(Exception): pass            hierarchy:\n#   class Sub1(Base): pass                   except Base catches Sub1 & Sub2\n#   class Sub2(Base): pass\n#\n# COMPARISON TABLE:\n# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”¬в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# bare except:        в”Ӯ catches EVERYTHING (Ctrl+C too) вҖ” NEVER use\n# except Exception:   в”Ӯ catches all normal errors вҖ” PREFERRED\n# except ValueError:  в”Ӯ catches specific error вҖ” MOST SPECIFIC\n# try/finally:        в”Ӯ manual cleanup вҖ” verbose, error-prone\n# with statement:     в”Ӯ auto cleanup вҖ” clean, safe, Pythonic\n# raise vs raise e:   в”Ӯ raise keeps traceback, raise e resets it\n# assert vs raise:    в”Ӯ assert = debug only, raise = production validation\n# LBYL vs EAFP:       в”Ӯ if/check-first vs try/catch вҖ” Python prefers EAFP\n# Exception vs warn:  в”Ӯ exception STOPS, warning CONTINUES\n# logging.exception:  в”Ӯ logs message + full traceback automatically\n# logging.error:      в”Ӯ logs message only вҖ” no traceback\n# suppress(Error):    в”Ӯ context manager вҖ” silently ignore specific exceptions\n# в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҙв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#\n# COMMON PATTERNS:\n#   Retry:      for i in range(n): try: return f() except: sleep(delay*i)\n#   Default:    try: val = d[\"key\"] except KeyError: val = default\n#   Parse:      try: x = int(s) except ValueError: x = 0\n#   Cleanup:    try: ... finally: resource.close()  OR  with resource:\n#   Log+raise:  except E: logging.exception(\"...\"); raise\n#   Safe gen:   try: yield val except E: continue\n#\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#", "reference": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  EXCEPTION HANDLING вҖ” DETAILED REFERENCE\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n# в”Җв”Җ try/except вҖ” Basic error catching в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   try:\n#       risky_code()                вҶ’ code that MIGHT raise an exception\n#   except SomeError as e:          вҶ’ catches SomeError (and its subclasses)\n#       handle(e)                   вҶ’ e is the exception object: str(e), type(e), e.args\n#   If no exception: except block is SKIPPED.\n#   If exception matches: except block runs, program continues AFTER the block.\n#   If exception doesn't match: propagates UP the call stack (crash if uncaught).\n#\n# в”Җв”Җ else вҖ” Success-only code в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   try:\n#       result = parse(data)        вҶ’ only THIS can trigger the except\n#   except ValueError:\n#       handle_error()\n#   else:\n#       use(result)                 вҶ’ runs ONLY if try succeeded вҖ” keeps try block narrow\n#   Why not put it in try? Because errors in use(result) would be caught too.\n#\n# в”Җв”Җ finally вҖ” Always runs в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   try: ...\n#   finally: cleanup()              вҶ’ runs whether exception occurred or not\n#   Even runs if: return in try, break in loop, exception propagates up.\n#   Use for: closing files, releasing locks, DB rollback, network disconnect.\n#\n# в”Җв”Җ raise вҖ” Throw exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   raise ValueError(\"msg\")         вҶ’ throw new exception\n#   raise                           вҶ’ re-raise current exception (in except block)\n#   raise NewError() from original  вҶ’ chain: NewError.__cause__ = original\n#   raise NewError() from None      вҶ’ suppress chain (hide original cause)\n#\n# в”Җв”Җ Custom exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   class MyError(Exception):       вҶ’ inherit from Exception (or a subclass)\n#   Add __init__ for custom attributes (balance, code, detail, etc.)\n#   Build hierarchies: class Base(Exception) вҶ’ class Sub(Base)\n#   Catching Base catches all Sub exceptions too.\n#\n# в”Җв”Җ ExceptionGroup (3.11+) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   raise ExceptionGroup(\"msg\", [e1, e2, e3])  вҶ’ multiple errors at once\n#   except* ValueError as eg:       вҶ’ catches only ValueErrors from group\n#   eg.exceptions                   вҶ’ tuple of matched exceptions\n#   Unmatched types propagate as a new ExceptionGroup. Used for parallel tasks.\n#\n# в”Җв”Җ Context managers вҖ” Exception-safe resource management в”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   with open(f) as fh:             вҶ’ __enter__ opens, __exit__ closes (even on error)\n#   with suppress(KeyError):        вҶ’ silently ignores KeyError (contextlib)\n#   @contextmanager + try/yield/except вҶ’ custom context manager with error handling\n#\n# в”Җв”Җ Assertions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   assert condition, \"message\"     вҶ’ raises AssertionError if False\n#   REMOVED by python -O flag! Never use for: user input, API validation, security.\n#   Use for: invariants in tests, debug-only sanity checks, \"this should never happen\".\n#\n# в”Җв”Җ Async exceptions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#   try: result = await coro() except E:    вҶ’ same syntax, just add await\n#   asyncio.gather(return_exceptions=True)  вҶ’ errors returned as values, not raised\n#   isinstance(r, Exception)                вҶ’ check which results are errors\n#\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\nimport os\nif os.path.exists(\"test_exc.txt\"):\n    os.remove(\"test_exc.txt\")"}, "file-handling.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#  PYTHON FILE, JSON & CSV HANDLING вҖ” Condensed Guide\n#  Always use \"with open(...)\" вҖ” auto-closes even on error\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\nimport os, json, csv, shutil, tempfile\nfrom pathlib import Path\nfrom datetime import datetime, date\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘              BEGINNER                            в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. File Modes в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  \"r\"  = read (default, must exist)    \"rb\" = read binary\n#  \"w\"  = write (creates/OVERWRITES)    \"wb\" = write binary\n#  \"a\"  = append (creates/adds to end)  \"x\"  = exclusive create (error if exists)\n#  \"r+\" = read+write (must exist)       \"w+\" = write+read (creates/overwrites)\n#  Add \"b\" for binary (images, PDFs). Add \"t\" for text (default).\n\n# в”Җв”Җ 2. Writing Files в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nwith open(\"sample.txt\", \"w\") as f:\n    f.write(\"Line 1: Hello World\\n\")\n    f.write(\"Line 2: Python is great\\n\")\n    f.write(\"Line 3: File handling\\n\")\n    chars = f.write(\"Line 4: Last line\\n\")  # returns char count\nprint(f\"Wrote sample.txt ({chars} chars in last write)\")\n\n# writelines() вҖ” write a list (no auto-newline)\nlines = [\"Apple\\n\", \"Banana\\n\", \"Cherry\\n\"]\nwith open(\"fruits.txt\", \"w\") as f:\n    f.writelines(lines)\n\n# в”Җв”Җ 3. Reading Files (2 Best Methods) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Method A: read() вҖ” entire file as string (small files)\nwith open(\"sample.txt\", \"r\") as f:\n    content = f.read()\n    print(f\"read(): {repr(content[:40])}...\")\n\n# Method B: for loop вҖ” line by line (BEST for large files, memory efficient)\nwith open(\"sample.txt\", \"r\") as f:\n    for i, line in enumerate(f, 1):\n        print(f\"  Line {i}: {line.strip()}\")\n\n# Also: readlines() вҶ’ list of lines, readline() вҶ’ single line\n\n# в”Җв”Җ 4. Append вҖ” \"a\" Mode в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nwith open(\"sample.txt\", \"a\") as f:\n    f.write(\"Line 5: Appended\\n\")\nwith open(\"sample.txt\", \"r\") as f:\n    print(f\"File now has {len(f.readlines())} lines\")  # 5\n\n# в”Җв”Җ 5. Exclusive Create вҖ” \"x\" Mode в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ntry:\n    with open(\"sample.txt\", \"x\") as f:  # already exists вҶ’ error\n        f.write(\"won't work\")\nexcept FileExistsError:\n    print(\"FileExistsError: sample.txt already exists\")\n\nwith open(\"new_file.txt\", \"x\") as f:\n    f.write(\"Created with x mode\\n\")\n\n# в”Җв”Җ 6. Read+Write & File Pointer в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nwith open(\"temp_rw.txt\", \"w+\") as f:\n    f.write(\"Hello from w+ mode\\n\")\n    f.seek(0)                 # move pointer back to start\n    print(f\"w+ read: {f.read().strip()}\")\n\n# seek(0) вҶ’ beginning | seek(0,2) вҶ’ end | tell() вҶ’ current position\nwith open(\"sample.txt\", \"r\") as f:\n    f.read(10); print(f\"After read(10): {f.tell()}\")  # 10\n    f.seek(0, 2); print(f\"File size: {f.tell()} bytes\")\n\n# в”Җв”Җ 7. Error Handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndef safe_read_file(filepath):\n    \"\"\"Handle FileNotFoundError, PermissionError, UnicodeDecodeError, etc.\"\"\"\n    try:\n        with open(filepath, \"r\", encoding=\"utf-8\") as f:\n            return f.read()\n    except FileNotFoundError:\n        print(f\"  ERROR: '{filepath}' not found\")\n    except PermissionError:\n        print(f\"  ERROR: No permission for '{filepath}'\")\n    except IsADirectoryError:\n        print(f\"  ERROR: '{filepath}' is a directory\")\n    except UnicodeDecodeError:\n        print(f\"  ERROR: Cannot decode '{filepath}' as UTF-8\")\n    return None\n\nsafe_read_file(\"sample.txt\")       # works\nsafe_read_file(\"nonexistent.txt\")  # FileNotFoundError\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘            INTERMEDIATE                          в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 8. Encoding в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Always specify encoding=\"utf-8\" for cross-platform consistency\nwith open(\"encoded.txt\", \"w\", encoding=\"utf-8\") as f:\n    f.write(\"English: Hello\\nJapanese: гҒ“гӮ“гҒ«гҒЎгҒҜ\\nEmoji: рҹҗҚ\\n\")\nwith open(\"encoded.txt\", \"r\", encoding=\"utf-8\") as f:\n    content = f.read()  # works with all unicode\n# errors=\"ignore\" skips bad chars | errors=\"replace\" uses ? for bad chars\ntry:\n    with open(\"encoded.txt\", \"r\", encoding=\"ascii\") as f: f.read()\nexcept UnicodeDecodeError: print(\"Wrong encoding вҶ’ UnicodeDecodeError\")\n\n# в”Җв”Җ 9. Binary Files вҖ” \"rb\"/\"wb\" в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndata = bytes([72, 101, 108, 108, 111])  # \"Hello\"\nwith open(\"binary.dat\", \"wb\") as f:\n    f.write(data)\n    f.write(b\"\\x00\\x01\\x02\\x03\")\n\nwith open(\"binary.dat\", \"rb\") as f:\n    content = f.read()\n    print(f\"Bytes: {content}, as text: {content[:5].decode('utf-8')}\")\n\n# Copy any file in binary mode\nwith open(\"binary.dat\", \"rb\") as src, open(\"binary_copy.dat\", \"wb\") as dst:\n    dst.write(src.read())\n\n# в”Җв”Җ 10. JSON Basics вҖ” dumps/loads/dump/load в”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  json.dumps(obj) вҶ’ string   |  json.dump(obj, file)  вҶ’ write to file\n#  json.loads(str) вҶ’ dict     |  json.load(file)       вҶ’ read from file\n#  Mnemonic: \"s\" = string\n#\n#  PythonвҶ’JSON: dictвҶ’{}, listвҶ’[], strвҶ’\"\", int/floatвҶ’number,\n#               TrueвҶ’true, FalseвҶ’false, NoneвҶ’null\n\nuser = {\"name\": \"Alice\", \"age\": 30, \"active\": True, \"scores\": [95, 87], \"address\": None}\n\njson_str = json.dumps(user)                          # dict вҶ’ string\nprint(f\"dumps: {json_str}\")\njson_pretty = json.dumps(user, indent=2)             # pretty-print\ncompact = json.dumps(user, separators=(\",\", \":\"))    # no spaces (for APIs)\n\nparsed = json.loads('{\"name\": \"Bob\", \"age\": 25}')   # string вҶ’ dict\nprint(f\"loads: {parsed['name']}, type={type(parsed)}\")  # Bob, <class 'dict'>\n\n# в”Җв”Җ 11. JSON File Read/Write в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nusers = [\n    {\"id\": 1, \"name\": \"Alice\", \"email\": \"alice@test.com\", \"active\": True},\n    {\"id\": 2, \"name\": \"Bob\", \"email\": \"bob@test.com\", \"active\": False},\n    {\"id\": 3, \"name\": \"Charlie\", \"email\": \"charlie@test.com\", \"active\": True},\n]\nwith open(\"users.json\", \"w\", encoding=\"utf-8\") as f:\n    json.dump(users, f, indent=2, ensure_ascii=False)  # dict вҶ’ file\n\nwith open(\"users.json\", \"r\", encoding=\"utf-8\") as f:\n    loaded = json.load(f)                               # file вҶ’ dict\nprint(f\"Loaded {len(loaded)} users from users.json\")\n\n# Common pattern: load вҶ’ modify вҶ’ save\nwith open(\"users.json\", \"r\", encoding=\"utf-8\") as f:\n    users = json.load(f)\nusers.append({\"id\": 4, \"name\": \"Diana\", \"email\": \"diana@test.com\", \"active\": True})\nusers = [u for u in users if u[\"name\"] != \"Charlie\"]  # remove Charlie\nwith open(\"users.json\", \"w\", encoding=\"utf-8\") as f:\n    json.dump(users, f, indent=2)\nprint(f\"Modified users.json: now {len(users)} users\")\n\n# в”Җв”Җ 12. JSON Error Handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Common invalid JSON: single quotes, trailing commas, unquoted keys\nfor bad in [\"{'name': 'Alice'}\", '{\"name\": \"Alice\",}', 'not json']:\n    try: json.loads(bad)\n    except json.JSONDecodeError as e: print(f\"  Invalid: {repr(bad[:25])} вҶ’ {e.msg}\")\n\ndef safe_load_json(filepath):\n    try:\n        with open(filepath, \"r\", encoding=\"utf-8\") as f:\n            return json.load(f)\n    except FileNotFoundError:\n        print(f\"  File not found: {filepath}\")\n    except json.JSONDecodeError as e:\n        print(f\"  Invalid JSON in {filepath}: {e.msg} at line {e.lineno}\")\n    return None\n\n# в”Җв”Җ 13. Nested JSON Access в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\napi = {\"data\": {\"user\": {\"profile\": {\"social\": {\"twitter\": \"@alice\"}},\n       \"orders\": [{\"id\": 1, \"items\": [{\"name\": \"Laptop\", \"price\": 999}]}]}}}\n\n# Direct access (raises KeyError if missing)\nprint(f\"Twitter: {api['data']['user']['profile']['social']['twitter']}\")\n\n# Safe deep access with .get() chains\ntwitter = api.get(\"data\", {}).get(\"user\", {}).get(\"profile\", {}).get(\"social\", {}).get(\"twitter\", \"N/A\")\nlinkedin = api.get(\"data\", {}).get(\"user\", {}).get(\"profile\", {}).get(\"social\", {}).get(\"linkedin\", \"Not found\")\nprint(f\"Safe: twitter={twitter}, linkedin={linkedin}\")\n\n# в”Җв”Җ 14. CSV Read/Write в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# csv.writer / csv.reader вҖ” rows as lists\nwith open(\"employees.csv\", \"w\", newline=\"\", encoding=\"utf-8\") as f:\n    writer = csv.writer(f)\n    writer.writerow([\"Name\", \"Department\", \"Salary\"])  # header\n    writer.writerow([\"Alice\", \"Engineering\", 90000])\n    writer.writerows([[\"Bob\", \"Marketing\", 70000], [\"Charlie\", \"Engineering\", 85000]])\n\nwith open(\"employees.csv\", \"r\", newline=\"\", encoding=\"utf-8\") as f:\n    reader = csv.reader(f)\n    header = next(reader)  # skip header\n    for row in reader:\n        print(f\"  {row[0]}: {row[1]}, ${row[2]}\")\n\n# csv.DictReader / csv.DictWriter вҖ” rows as dicts (RECOMMENDED)\nwith open(\"products.csv\", \"w\", newline=\"\", encoding=\"utf-8\") as f:\n    fields = [\"id\", \"name\", \"price\"]\n    writer = csv.DictWriter(f, fieldnames=fields)\n    writer.writeheader()\n    writer.writerow({\"id\": 1, \"name\": \"Laptop\", \"price\": 999.99})\n    writer.writerow({\"id\": 2, \"name\": \"Mouse\", \"price\": 24.99})\n\nwith open(\"products.csv\", \"r\", newline=\"\", encoding=\"utf-8\") as f:\n    for row in csv.DictReader(f):\n        print(f\"  {row['name']}: ${row['price']}\")\n\n# Custom delimiter (TSV)\nwith open(\"data.tsv\", \"w\", newline=\"\", encoding=\"utf-8\") as f:\n    writer = csv.writer(f, delimiter=\"\\t\")\n    writer.writerow([\"Name\", \"Score\"])\n    writer.writerows([[\"Alice\", 95], [\"Bob\", 87]])\n\n# в”Җв”Җ 15. pathlib вҖ” Modern File Handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# pathlib.Path vs os.path: Path objects use / operator, have cleaner API\np = Path(\"sample.txt\")\nprint(f\"name={p.name}, stem={p.stem}, suffix={p.suffix}\")  # sample.txt, sample, .txt\nprint(f\"exists={p.exists()}, is_file={p.is_file()}, size={p.stat().st_size}\")\n\n# Join paths:  Path(\"data\") / \"2024\" / \"report.csv\"  vs  os.path.join(\"data\",\"2024\",\"report.csv\")\ndata_path = Path(\"data\") / \"2024\" / \"report.csv\"\n\n# Read/write without open()\nPath(\"pathlib_test.txt\").write_text(\"Hello from pathlib!\", encoding=\"utf-8\")\ncontent = Path(\"pathlib_test.txt\").read_text(encoding=\"utf-8\")\nPath(\"pathlib_bin.dat\").write_bytes(b\"binary data\")\ndata = Path(\"pathlib_bin.dat\").read_bytes()\n\n# Glob вҖ” find files by pattern\nfor txt_file in Path(\".\").glob(\"*.txt\"):\n    print(f\"  Found: {txt_file}\")\n# Path(\".\").rglob(\"*.py\")  вҖ” recursive search into subdirs\n\n# Modify path parts\np3 = Path(\"report.txt\")\nprint(f\"Change ext: {p3.with_suffix('.pdf')}, change name: {p3.with_name('summary.txt')}\")\n\n# JSON with pathlib (one-liner read/write)\nPath(\"fw.json\").write_text(json.dumps({\"name\": \"FastAPI\"}, indent=2), encoding=\"utf-8\")\nloaded = json.loads(Path(\"fw.json\").read_text(encoding=\"utf-8\"))\n\n# в”Җв”Җ 16. os Module Essentials в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nos.path.exists(\"sample.txt\")                       # True/False\nos.path.getsize(\"sample.txt\")                      # bytes\nos.path.isfile(\"sample.txt\")                       # True\nname, ext = os.path.splitext(\"report.pdf\")         # ('report', '.pdf')\nfull = os.path.join(\"folder\", \"sub\", \"file.txt\")   # folder/sub/file.txt\nos.path.dirname(\"/home/user/f.txt\")                # /home/user\nos.path.basename(\"/home/user/f.txt\")               # f.txt\ntxt_files = [f for f in os.listdir(\".\") if f.endswith(\".txt\")]\nos.rename(\"new_file.txt\", \"renamed_file.txt\")\nos.makedirs(\"test_dir/sub_dir\", exist_ok=True)\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘              ADVANCED                            в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 17. tempfile вҖ” Auto-Cleanup Temp Files в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nwith tempfile.NamedTemporaryFile(mode=\"w\", suffix=\".txt\", delete=False) as tmp:\n    tmp.write(\"Temporary data\\n\")\n    tmp_name = tmp.name                                  # get path before close\nos.unlink(tmp_name)                                      # manual delete (delete=False)\n\nwith tempfile.TemporaryDirectory() as tmpdir:             # auto-deleted on exit\n    Path(tmpdir, \"data.txt\").write_text(\"temp data\")\nprint(f\"Temp dir gone: {not os.path.exists(tmpdir)}\")    # True\n\n# в”Җв”Җ 18. shutil вҖ” Copy, Move, Delete в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nshutil.copy(\"sample.txt\", \"sample_backup.txt\")     # copy file\nshutil.copy2(\"sample.txt\", \"sample_backup2.txt\")   # copy + metadata (timestamps)\nshutil.move(\"renamed_file.txt\", \"moved_file.txt\")  # move/rename\nshutil.copytree(\"test_dir\", \"test_dir_copy\")       # copy entire directory tree\nshutil.rmtree(\"test_dir_copy\")                     # delete dir + all contents\n\n# в”Җв”Җ 19. JSON Lines (JSONL) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# One JSON object per line вҖ” ideal for logs, streaming, large datasets\nevents = [\n    {\"ts\": \"2024-01-01T10:00\", \"event\": \"login\", \"user\": \"alice\"},\n    {\"ts\": \"2024-01-01T10:05\", \"event\": \"page_view\", \"user\": \"alice\"},\n]\n# Write: one json.dumps() per line\nwith open(\"events.jsonl\", \"w\", encoding=\"utf-8\") as f:\n    for event in events:\n        f.write(json.dumps(event) + \"\\n\")\n\n# Append (just add a line вҖ” no need to rewrite entire file like JSON arrays)\nwith open(\"events.jsonl\", \"a\", encoding=\"utf-8\") as f:\n    f.write(json.dumps({\"ts\": \"2024-01-01T10:15\", \"event\": \"logout\", \"user\": \"alice\"}) + \"\\n\")\n\n# Read: parse each line independently\nwith open(\"events.jsonl\", \"r\", encoding=\"utf-8\") as f:\n    all_events = [json.loads(line) for line in f]\n\n# в”Җв”Җ 20. Large File Reading в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nwith open(\"large_demo.txt\", \"w\") as f:\n    for i in range(1000): f.write(f\"Line {i}: test data\\n\")\n\n# Line by line (BEST for text) вҖ” never loads entire file into memory\ncount = sum(1 for _ in open(\"large_demo.txt\", \"r\"))\n\n# Chunk-based (for binary or raw processing)\ntotal_bytes = 0\nwith open(\"large_demo.txt\", \"rb\") as f:\n    while chunk := f.read(8192):  # 8KB chunks, walrus operator\n        total_bytes += len(chunk)\n\n# в”Җв”Җ 21. JSON вҶ” CSV Conversion в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# JSON вҶ’ CSV\njson_data = [\n    {\"name\": \"Alice\", \"age\": 30, \"city\": \"NYC\"},\n    {\"name\": \"Bob\", \"age\": 25, \"city\": \"LA\"},\n]\nwith open(\"people.csv\", \"w\", newline=\"\", encoding=\"utf-8\") as f:\n    writer = csv.DictWriter(f, fieldnames=json_data[0].keys())\n    writer.writeheader()\n    writer.writerows(json_data)\n\n# CSV вҶ’ JSON\nwith open(\"people.csv\", \"r\", newline=\"\", encoding=\"utf-8\") as f:\n    csv_as_json = list(csv.DictReader(f))\nwith open(\"people.json\", \"w\", encoding=\"utf-8\") as f:\n    json.dump(csv_as_json, f, indent=2)\n\n# в”Җв”Җ 22. Custom JSON Serialization в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# JSON can't serialize: datetime, set, bytes вҶ’ use default= or cls=\ndata_custom = {\n    \"event\": \"Meeting\",\n    \"date\": datetime(2024, 6, 15, 14, 30),\n    \"tags\": {\"python\", \"coding\"},\n    \"raw\": b\"hello\",\n}\n\ndef json_serializer(obj):\n    if isinstance(obj, (datetime, date)): return obj.isoformat()\n    if isinstance(obj, set): return sorted(list(obj))\n    if isinstance(obj, bytes): return obj.decode(\"utf-8\")\n    raise TypeError(f\"Type {type(obj)} not serializable\")\n\nresult = json.dumps(data_custom, default=json_serializer, indent=2)\nprint(f\"Custom serialized:\\n{result}\")\n\n# Reusable: subclass JSONEncoder\nclass CustomEncoder(json.JSONEncoder):\n    def default(self, obj):\n        if isinstance(obj, (datetime, date)): return obj.isoformat()\n        if isinstance(obj, set): return sorted(list(obj))\n        if isinstance(obj, bytes): return obj.decode(\"utf-8\")\n        return super().default(obj)\n\njson.dumps(data_custom, cls=CustomEncoder, indent=2)\n\n# в”Җв”Җ 23. JSON Merge & Diff в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\ndefaults = {\"theme\": \"light\", \"lang\": \"en\", \"notify\": True, \"font\": 14}\nuser_prefs = {\"theme\": \"dark\", \"font\": 16}\n\nmerged = {**defaults, **user_prefs}   # ** unpacking (3.5+), user_prefs wins\nmerged2 = defaults | user_prefs       # | operator (3.9+)\nprint(f\"Merged: {merged}\")\n\n# Deep merge for nested dicts\ndef deep_merge(base, override):\n    result = base.copy()\n    for key, val in override.items():\n        if key in result and isinstance(result[key], dict) and isinstance(val, dict):\n            result[key] = deep_merge(result[key], val)\n        else:\n            result[key] = val\n    return result\n\ncfg_base = {\"db\": {\"host\": \"localhost\", \"port\": 5432}, \"debug\": False}\ncfg_prod = {\"db\": {\"host\": \"prod-server\"}, \"debug\": False}\nprint(f\"Deep merged: {deep_merge(cfg_base, cfg_prod)}\")\n# {\"db\": {\"host\": \"prod-server\", \"port\": 5432}, \"debug\": False}\n\n# Simple diff\ndef json_diff(old, new):\n    changes = {}\n    for key in set(list(old) + list(new)):\n        if key not in old: changes[key] = {\"added\": new[key]}\n        elif key not in new: changes[key] = {\"removed\": old[key]}\n        elif old[key] != new[key]: changes[key] = {\"old\": old[key], \"new\": new[key]}\n    return changes\n\ndiff = json_diff({\"name\": \"Alice\", \"age\": 30, \"city\": \"NYC\"}, {\"name\": \"Alice\", \"age\": 31, \"country\": \"US\"})\n# {'age': {'old': 30, 'new': 31}, 'city': {'removed': 'NYC'}, 'country': {'added': 'US'}}\n\n# в”Җв”Җ CLEANUP в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nfor f in [\"sample.txt\", \"fruits.txt\", \"encoded.txt\", \"binary.dat\", \"binary_copy.dat\",\n          \"temp_rw.txt\", \"pathlib_test.txt\", \"pathlib_bin.dat\", \"sample_backup.txt\",\n          \"sample_backup2.txt\", \"moved_file.txt\", \"users.json\", \"fw.json\",\n          \"employees.csv\", \"products.csv\", \"data.tsv\", \"people.csv\", \"people.json\",\n          \"large_demo.txt\", \"events.jsonl\"]:\n    if os.path.exists(f):\n        os.remove(f)\nif os.path.exists(\"test_dir\"):\n    shutil.rmtree(\"test_dir\")", "cheatSheet": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#                         CHEAT SHEET\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n#  FILE MODES:\n#    \"r\" read | \"w\" write | \"a\" append | \"x\" exclusive\n#    \"r+\" read+write | \"rb\"/\"wb\" binary | seek(0) reset pointer\n#\n#  TEXT FILES:\n#    with open(path, \"r\", encoding=\"utf-8\") as f:\n#        content = f.read()          # whole file (small files)\n#        for line in f: ...          # line-by-line (large files)\n#    with open(path, \"w\") as f:\n#        f.write(text)               # write string\n#        f.writelines(list_of_str)   # write list (no auto-newline)\n#\n#  JSON:\n#    json.dumps(obj)     вҶ’ string    |  json.dump(obj, file)  вҶ’ file\n#    json.loads(string)  вҶ’ dict      |  json.load(file)       вҶ’ dict\n#    indent=2            pretty      |  separators=(\",\",\":\")   compact\n#    ensure_ascii=False  keep unicode|  default=func           custom types\n#    sort_keys=True      alphabetical|  cls=CustomEncoder      reusable\n#\n#  CSV:\n#    csv.writer(f)        вҶ’ writerow([...])         rows as lists\n#    csv.DictWriter(f, fieldnames) вҶ’ writerow({})   rows as dicts\n#    csv.reader(f)        вҶ’ iterate lists           newline=\"\" ALWAYS\n#    csv.DictReader(f)    вҶ’ iterate dicts            delimiter=\"\\t\" for TSV\n#\n#  PATHLIB vs OS:\n#    Path(\"a\")/\"b\"/\"c\"        vs  os.path.join(\"a\",\"b\",\"c\")\n#    p.exists() / p.is_file() vs  os.path.exists() / os.path.isfile()\n#    p.read_text()            vs  open()+read()\n#    p.write_text(s)          vs  open()+write()\n#    p.glob(\"*.txt\")          vs  os.listdir() + filter\n#    p.name/stem/suffix       vs  os.path.basename/splitext\n#\n#  ADVANCED:\n#    tempfile.NamedTemporaryFile/TemporaryDirectory  auto-cleanup\n#    shutil.copy/copy2/move/copytree/rmtree          file ops\n#    JSONL: json.dumps() per line, easy append, stream-friendly\n#    Large: for line in f (text) or while chunk:=f.read(8192)\n#    Merge: {**a,**b} or a|b | Deep: recursive merge function\n#\n#  ERRORS: FileNotFoundError, PermissionError, IsADirectoryError,\n#          UnicodeDecodeError, json.JSONDecodeError, OSError\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ", "reference": ""}, "functions.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# PYTHON FUNCTIONS вҖ” Essential Guide (Basic вҶ’ Advanced)\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘  BEGINNER                                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Basics вҖ” def, return, None в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\ndef greet(name):\n    return f\"Hello, {name}!\"\n\nprint(greet(\"Alice\"))           # Hello, Alice!\n\ndef no_return():\n    x = 5 + 3\n\nprint(no_return())              # None  (no return = returns None)\n\ndef early_exit(x):\n    if x < 0: return \"negative\" # function STOPS here\n    return \"positive\"           # only runs if x >= 0\n\n# Parameter = placeholder in def  |  Argument = actual value when calling\n# def greet(name):   вҶҗ PARAMETER  |  greet(\"Alice\")  вҶҗ ARGUMENT\n\ndef add(a, b):       # a, b = parameters\n    return a + b\nprint(add(3, 5))     # 3, 5 = arguments  вҶ’  8\n\n\n# в”Җв”Җ 2. Default values в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\ndef greet(name, greeting=\"Hello\"):\n    return f\"{greeting}, {name}!\"\n\nprint(greet(\"Alice\"))              # Hello, Alice!     (uses default)\nprint(greet(\"Bob\", \"Hi\"))          # Hi, Bob!          (overrides default)\n\n# DANGER: Mutable default is SHARED across calls\n# BAD:  def f(items=[])   вҶ’ same list every call!\n# GOOD: def f(items=None) вҶ’ new list each call\n\ndef bad(items=[]):\n    items.append(1); return items\nprint(bad())                 # [1]\nprint(bad())                 # [1, 1]  вҶҗ NOT [1]!\n\ndef good(items=None):\n    if items is None: items = []\n    items.append(1); return items\nprint(good())                # [1]\nprint(good())                # [1]  вҶҗ correct\n\n\n# в”Җв”Җ 3. Positional vs Keyword arguments в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Positional: order matters         вҶ’ f(\"Alice\", 30)\n# Keyword:   name matters           вҶ’ f(age=30, name=\"Alice\")\n# Mixed:     positional FIRST       вҶ’ f(\"Alice\", age=30)  OK\n#            keyword first = ERROR  вҶ’ f(name=\"Alice\", 30)  ERROR\n\ndef register(name, age, email):\n    return f\"{name}, {age}, {email}\"\n\nprint(register(\"Alice\", 30, \"a@test.com\"))                # positional\nprint(register(email=\"b@test.com\", name=\"Bob\", age=25))   # keyword\nprint(register(\"Charlie\", email=\"c@test.com\", age=35))    # mixed\n\n# Skip middle defaults using keyword\ndef setup(host, port=8000, debug=False, workers=4):\n    return f\"{host}:{port} debug={debug} workers={workers}\"\nprint(setup(\"localhost\", debug=True))     # skip port, set debug\n\n\n# в”Җв”Җ 4. Return multiple values в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\ndef min_max(numbers):\n    return min(numbers), max(numbers)   # returns a tuple\n\nlow, high = min_max([5, 2, 8, 1, 9])   # unpack into 2 vars\nprint(f\"low={low}, high={high}\")        # low=1, high=9\n\ndef analyze(nums):\n    return {\"sum\": sum(nums), \"avg\": sum(nums) / len(nums)}\nprint(analyze([10, 20, 30]))            # {'sum': 60, 'avg': 20.0}\n\n\n# в”Җв”Җ 5. Error handling в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\ndef divide(a, b):\n    if b == 0: raise ValueError(\"Cannot divide by zero\")\n    return a / b\n\ntry:\n    print(divide(10, 0))\nexcept ValueError as e:\n    print(f\"Error: {e}\")                # Error: Cannot divide by zero\n\ndef safe_int(val, default=0):\n    try: return int(val)\n    except (ValueError, TypeError): return default\n\nprint(safe_int(\"42\"))       # 42\nprint(safe_int(\"abc\"))      # 0\n\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘  INTERMEDIATE                                    в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 6. *args vs **kwargs в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  *args    вҶ’ collects positional вҶ’ tuple    вҶ’ f(1, 2, 3)\n#  **kwargs вҶ’ collects keyword    вҶ’ dict     вҶ’ f(a=1, b=2)\n\ndef add_all(*args):\n    return sum(args)           # args is a tuple\nprint(add_all(1, 2, 3))       # 6\n\ndef show(**kwargs):\n    for k, v in kwargs.items():\n        print(f\"  {k}={v}\")\nshow(name=\"Alice\", age=30)    # name=Alice  age=30\n\n# Both together вҖ” ORDER: regular, *args, **kwargs\ndef log(level, *tags, **meta):\n    print(f\"  [{level}] tags={tags} meta={meta}\")\nlog(\"INFO\", \"db\", \"slow\", host=\"prod\", latency=200)\n# [INFO] tags=('db', 'slow') meta={'host': 'prod', 'latency': 200}\n\n\n# в”Җв”Җ 7. Keyword-only (*) vs Positional-only (/) в”Җв”Җв”Җв”Җ\n#  After *  вҶ’ MUST use name=       вҶ’  def f(*, x):   f(x=5) OK, f(5) ERROR\n#  Before / вҶ’ CANNOT use name=     вҶ’  def f(x, /):   f(5) OK, f(x=5) ERROR\n\ndef connect(host, port, *, timeout=30, ssl=True):\n    return f\"{host}:{port} timeout={timeout}\"\nprint(connect(\"localhost\", 8080, timeout=60))   # OK\n# connect(\"localhost\", 8080, 60)                # TypeError!\n\ndef divide(a, b, /):\n    return a / b\nprint(divide(10, 3))       # OK вҶ’ 3.333...\n# divide(a=10, b=3)        # TypeError!\n\n# Full combo:  positional-only / normal * keyword-only\ndef hybrid(a, b, /, c, d, *, e):\n    return f\"a={a} b={b} c={c} d={d} e={e}\"\nprint(hybrid(1, 2, 3, d=4, e=5))\n\n\n# в”Җв”Җ 8. Unpacking when calling (* vs **) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  *list   вҶ’ unpacks into positional   f(*[1,2,3])  = f(1,2,3)\n#  **dict  вҶ’ unpacks into keyword      f(**{\"a\":1}) = f(a=1)\n\ndef add3(a, b, c): return a + b + c\n\nprint(add3(*[10, 20, 30]))                    # 60\nprint(add3(**{\"a\": 1, \"b\": 2, \"c\": 3}))      # 6\n\n# Forwarding вҖ” pass everything through\ndef wrapper(*args, **kwargs):\n    return add3(*args, **kwargs)\nprint(wrapper(1, 2, 3))       # 6\n\n\n# в”Җв”Җ 9. Lambda vs def в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  def    вҶ’ named, multi-line, any logic\n#  lambda вҶ’ anonymous, ONE expression only, best for sorted/map/filter\n\ndouble = lambda x: x * 2\nclassify = lambda x: \"pos\" if x > 0 else \"neg\" if x < 0 else \"zero\"\nprint(double(5))             # 10\nprint(classify(-3))          # neg\n\nusers = [(\"Bob\", 25), (\"Alice\", 30), (\"Charlie\", 20)]\nprint(sorted(users, key=lambda u: u[1]))      # sort by age\n\nnums = [1, 2, 3, 4, 5, 6, 7, 8]\nprint(list(filter(lambda n: n % 2 == 0, nums)))   # [2, 4, 6, 8]\nprint(list(map(lambda n: n ** 2, nums)))           # [1, 4, 9, 16, ...]\n\n\n# в”Җв”Җ 10. map vs filter vs reduce в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  map()    вҶ’ transform each item      вҶ’ list вҶ’ list\n#  filter() вҶ’ keep items where True    вҶ’ list вҶ’ list\n#  reduce() вҶ’ combine all into one     вҶ’ list вҶ’ value\n\nfrom functools import reduce\nnums = [1, 2, 3, 4, 5]\nprint(list(map(lambda x: x * 2, nums)))       # [2, 4, 6, 8, 10]\nprint(list(filter(lambda x: x > 3, nums)))    # [4, 5]\nprint(reduce(lambda acc, x: acc + x, nums))   # 15\n\n\n# в”Җв”Җ 11. First-class functions в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Functions ARE objects вҖ” assign, pass, store them\n\nyell = str.upper\nprint(yell(\"hello\"))                  # HELLO\n\ndef apply(func, value): return func(value)\nprint(apply(len, \"hello\"))            # 5\n\n# Dispatch pattern вҖ” store in dict\nops = {\"+\": lambda a, b: a + b, \"-\": lambda a, b: a - b}\nprint(ops[\"+\"](10, 3))               # 13\n\n\n# в”Җв”Җ 12. global vs nonlocal  (Scope: LEGB) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  global   вҶ’ modify MODULE-level variable\n#  nonlocal вҶ’ modify ENCLOSING function var\n#  LEGB: Local вҶ’ Enclosing вҶ’ Global вҶ’ Built-in\n\nx = \"global\"\ndef demo_global():\n    global x\n    x = \"modified by function\"\ndemo_global()\nprint(x)            # modified by function\n\ndef outer():\n    msg = \"original\"\n    def inner():\n        nonlocal msg\n        msg = \"changed\"\n    inner()\n    return msg\nprint(outer())      # changed\n\n\n# в”Җв”Җ 13. Type hints + Docstrings в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Hints = for humans & tools (NOT enforced at runtime)\n\nfrom typing import Optional\n\ndef find_user(user_id: int) -> Optional[dict]:\n    \"\"\"Look up a user by ID. Returns None if not found.\"\"\"\n    users = {1: {\"name\": \"Alice\"}}\n    return users.get(user_id)\n\nprint(find_user(1))        # {'name': 'Alice'}\nprint(find_user(99))       # None\n\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘  ADVANCED                                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 14. Closure вҖ” function that remembers outer vars\n#  Regular вҶ’ no memory between calls\n#  Closure вҶ’ remembers outer function's vars, even after it exits\n\ndef make_multiplier(factor):\n    def multiply(x): return x * factor  # remembers factor\n    return multiply\n\ndouble = make_multiplier(2)\ntriple = make_multiplier(3)\nprint(f\"double(5)={double(5)}, triple(5)={triple(5)}\")   # 10, 15\n\n# Closure with mutable state\ndef make_counter():\n    count = 0\n    def increment():\n        nonlocal count\n        count += 1\n        return count\n    return increment\n\nc = make_counter()\nprint(f\"{c()}, {c()}, {c()}\")    # 1, 2, 3\n\n\n# в”Җв”Җ 15. return vs yield (Generator) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  return вҶ’ sends ONE value, function ENDS\n#  yield  вҶ’ sends ONE value, function PAUSES, resumes on next()\n#  Generators are memory efficient вҖ” no full list in RAM\n\ndef get_squares_list(n):         # builds ENTIRE list in memory\n    return [x**2 for x in range(n)]\n\ndef get_squares_gen(n):          # yields ONE at a time (lazy)\n    for x in range(n):\n        yield x**2\n\nprint(list(get_squares_gen(5)))   # [0, 1, 4, 9, 16]\n\ngen = get_squares_gen(3)\nprint(next(gen), next(gen), next(gen))   # 0 1 4\n# next(gen)  вҶ’ StopIteration\n\n# Infinite generator вҖ” impossible with return!\ndef count_forever(start=0):\n    n = start\n    while True:\n        yield n\n        n += 1\n\ncounter = count_forever()\nprint([next(counter) for _ in range(5)])   # [0, 1, 2, 3, 4]\n\n# yield from вҖ” delegate to another iterable\ndef combined():\n    yield from range(3)       # 0, 1, 2\n    yield from range(10, 13)  # 10, 11, 12\nprint(list(combined()))       # [0, 1, 2, 10, 11, 12]\n\n# Generator expression vs list comprehension\ngen_exp = (x**2 for x in range(5))    # lazy вҖ” uses ()\nlst_cmp = [x**2 for x in range(5)]    # eager вҖ” builds full list\n\n\n# в”Җв”Җ 16. Decorators в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# @decorator = shorthand for func = decorator(func)\n\nimport functools, time\n\ndef timer(func):\n    @functools.wraps(func)\n    def wrapper(*args, **kwargs):\n        start = time.time()\n        result = func(*args, **kwargs)\n        print(f\"  {func.__name__} took {time.time()-start:.4f}s\")\n        return result\n    return wrapper\n\n@timer\ndef slow(): return sum(range(1_000_000))\nslow()\n\n# Decorator WITH arguments (decorator factory)\ndef repeat(times):\n    def decorator(func):\n        @functools.wraps(func)\n        def wrapper(*args, **kwargs):\n            return [func(*args, **kwargs) for _ in range(times)]\n        return wrapper\n    return decorator\n\n@repeat(3)\ndef say(word): return word\nprint(say(\"hi\"))     # ['hi', 'hi', 'hi']\n\n\n# в”Җв”Җ 17. Recursion в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Function calls itself вҖ” MUST have base case or вҶ’ crash\n\ndef factorial(n):\n    if n <= 1: return 1              # base case\n    return n * factorial(n - 1)      # recursive case\nprint(f\"5! = {factorial(5)}\")        # 120\n\ndef flatten(lst):\n    result = []\n    for item in lst:\n        if isinstance(item, list): result.extend(flatten(item))\n        else: result.append(item)\n    return result\nprint(flatten([1, [2, [3, [4]]]]))   # [1, 2, 3, 4]\n\n\n# в”Җв”Җ 18. Memoization вҖ” @lru_cache в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Caches return values by arguments вҖ” makes repeated calls instant\n\n@functools.lru_cache(maxsize=128)\ndef fib(n):\n    if n <= 1: return n\n    return fib(n-1) + fib(n-2)\n\nprint(f\"fib(50) = {fib(50)}\")        # instant! (without cache вҶ’ years)\nprint(f\"Cache: {fib.cache_info()}\")\nfib.cache_clear()                    # reset cache\n\n\n# в”Җв”Җ 19. Partial вҖ” pre-fill arguments в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\nfrom functools import partial\n\ndef power(base, exp): return base ** exp\nsquare = partial(power, exp=2)\ncube   = partial(power, exp=3)\nprint(f\"square(5)={square(5)}, cube(3)={cube(3)}\")   # 25, 27\n\n\n# в”Җв”Җ 20. Common patterns в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\n# Callback вҖ” pass a function to run later\ndef process(data, on_done):\n    on_done([x * 2 for x in data])\nprocess([1, 2, 3], lambda r: print(f\"Done: {r}\"))   # Done: [2, 4, 6]\n\n# Composition вҖ” chain functions left to right\ndef pipe(*fns):\n    def piped(x):\n        for f in fns: x = f(x)\n        return x\n    return piped\nclean = pipe(str.strip, str.lower, str.split)\nprint(clean(\"  Hello World  \"))    # ['hello', 'world']\n\n# Registry вҖ” decorator that registers handlers\nregistry = {}\ndef register(name):\n    def dec(fn): registry[name] = fn; return fn\n    return dec\n\n@register(\"greet\")\ndef greet_handler(data): return f\"Hello, {data}!\"\nprint(registry[\"greet\"](\"Alice\"))   # Hello, Alice!\n\n\n# в”Җв”Җ 21. Function introspection в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\ndef example(a: int, b: str = \"hi\") -> str:\n    \"\"\"Example function.\"\"\"\n    return f\"{a} {b}\"\n\nprint(f\"__name__:     {example.__name__}\")         # example\nprint(f\"__doc__:      {example.__doc__}\")           # Example function.\nprint(f\"__defaults__: {example.__defaults__}\")      # ('hi',)\nprint(f\"callable:     {callable(example)}\")         # True", "cheatSheet": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# CHEAT SHEET\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n#\n#  DEFINITION                            CALLING\n#  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ   в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  def f(a, b):         regular          f(1, 2)        positional\n#  def f(a, b=10):      default          f(a=1, b=2)    keyword\n#  def f(*args):        вҶ’ tuple          f(*[1,2])      unpack list\n#  def f(**kwargs):     вҶ’ dict           f(**{\"a\":1})   unpack dict\n#  def f(a, /, b, *, c): pos/kw-only\n#  lambda a, b: a + b   one-liner\n#\n#  RETURN                                SCOPE (LEGB)\n#  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ   в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  return x         single value         Local вҶ’ Enclosing вҶ’\n#  return x, y      tuple                  Global вҶ’ Built-in\n#  no return        вҶ’ None               global x    module-level\n#  yield x          generator (lazy)     nonlocal x  enclosing func\n#\n#  KEY TOOLS                             BEST PRACTICES\n#  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ   в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  map(fn, list)    transform each       Never def f(items=[])\n#  filter(fn, list) keep where True       вҶ’ use def f(items=None)\n#  reduce(fn, list) combine into one     Guard clauses: validate early\n#  partial(fn, arg) pre-fill args        One function = one job\n#  @lru_cache       cache by args        Type hints: def f(x: int)\n#  @decorator       wrap behavior", "reference": ""}, "oops.py": {"content": "# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n# PYTHON OOP вҖ” Complete Guide (Condensed)\n#\n# Class = blueprint/template  |  Object = instance from a class\n# 4 Pillars: Encapsulation, Inheritance, Polymorphism, Abstraction\n# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                  BEGINNER                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 1. Basic Class & Object в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Car:\n    def __init__(self, brand, color):  # constructor\n        self.brand = brand             # instance variable\n        self.color = color\n    def describe(self):\n        return f\"{self.color} {self.brand}\"\n\ncar1, car2 = Car(\"Toyota\", \"Red\"), Car(\"Honda\", \"Blue\")\nprint(car1.describe())  # Red Toyota\ncar1.color = \"Black\"\nprint(car1.describe())  # Black Toyota  (car2 unchanged вҖ” separate objects)\n\n# в”Җв”Җ 2. Instance vs Class Variables в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Employee:\n    company = \"Reuters\"    # class var вҖ” shared by ALL instances\n    count = 0\n    def __init__(self, name, salary):\n        self.name = name   # instance var вҖ” unique per object\n        self.salary = salary\n        Employee.count += 1\n\nemp1, emp2 = Employee(\"Alice\", 50000), Employee(\"Bob\", 60000)\nprint(emp1.name, emp2.name)       # Alice Bob  (instance вҖ” different)\nprint(emp1.company, emp2.company) # Reuters Reuters  (class вҖ” same)\nprint(Employee.count)             # 2\n\n# в”Җв”Җ 3. Methods: Instance vs Class vs Static в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  instance  вҖ” def method(self)     works on ONE object\n#  class     вҖ” @classmethod         works on the CLASS (cls), alt constructors\n#  static    вҖ” @staticmethod        utility, no self/cls\nclass Pizza:\n    base_price = 10\n    def __init__(self, size, toppings):\n        self.size, self.toppings = size, toppings\n    def get_price(self):                          # instance method\n        return Pizza.base_price + len(self.toppings) * 2\n    @classmethod\n    def set_base_price(cls, price):               # class method\n        cls.base_price = price\n    @classmethod\n    def margherita(cls):                           # alt constructor\n        return cls(\"Medium\", [\"cheese\", \"tomato\"])\n    @staticmethod\n    def is_valid_size(size):                       # static\n        return size in [\"Small\", \"Medium\", \"Large\"]\n\np1 = Pizza(\"Large\", [\"cheese\", \"mushroom\", \"olive\"])\nprint(p1.get_price())              # 16  (10 + 3*2)\nPizza.set_base_price(12)\nprint(p1.get_price())              # 18  (12 + 3*2) вҖ” changed for ALL\nprint(Pizza.margherita().toppings) # ['cheese', 'tomato']\nprint(Pizza.is_valid_size(\"Huge\")) # False\n\n# в”Җв”Җ 4. Encapsulation & Property в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n#  public    name    вҖ” anyone can access\n#  protected _name   вҖ” convention: \"internal use\"\n#  private   __name  вҖ” name-mangled to _ClassName__name\n#  @property         вҖ” getter/setter/deleter as attribute syntax\nclass BankAccount:\n    def __init__(self, owner, balance):\n        self.owner = owner        # public\n        self._bank = \"Chase\"      # protected (convention)\n        self.__balance = balance   # private (mangled)\n    @property\n    def balance(self):\n        return self.__balance\n    @balance.setter\n    def balance(self, amount):\n        if amount < 0: raise ValueError(\"Balance cannot be negative\")\n        self.__balance = amount\n    def deposit(self, amount):\n        if amount > 0: self.__balance += amount\n        return self.__balance\n\nacc = BankAccount(\"Alice\", 1000)\nprint(acc.owner)                    # Alice  (public)\nprint(acc._bank)                    # Chase  (protected вҖ” works but discouraged)\n# print(acc.__balance)              # AttributeError!\nprint(acc._BankAccount__balance)    # 1000  (name mangling вҖ” not recommended)\nprint(acc.balance)                  # 1000  (property getter)\nacc.balance = 2000                  # property setter\nprint(acc.deposit(500))             # 2500\ntry:\n    acc.balance = -500\nexcept ValueError as e:\n    print(f\"Error: {e}\")            # Balance cannot be negative\n\n# Computed properties вҖ” no stored value\nclass Temperature:\n    def __init__(self, celsius): self._celsius = celsius\n    @property\n    def fahrenheit(self):       return (self._celsius * 9/5) + 32\n    @fahrenheit.setter\n    def fahrenheit(self, v):    self._celsius = (v - 32) * 5/9\n\ntemp = Temperature(100)\nprint(temp.fahrenheit)   # 212.0\ntemp.fahrenheit = 32\nprint(temp._celsius)     # 0.0\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                INTERMEDIATE                      в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 5. Inheritance вҖ” Single в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Animal:\n    def __init__(self, name, sound):\n        self.name, self.sound = name, sound\n    def speak(self):  return f\"{self.name} says {self.sound}!\"\n    def info(self):   return f\"Animal: {self.name}\"\n\nclass Dog(Animal):\n    def __init__(self, name, breed):\n        super().__init__(name, \"Woof\")  # call parent __init__\n        self.breed = breed\n    def info(self):  return f\"Dog: {self.name}, Breed: {self.breed}\"  # override\n\nclass Cat(Animal):\n    def __init__(self, name): super().__init__(name, \"Meow\")\n\ndog, cat = Dog(\"Rex\", \"Labrador\"), Cat(\"Whiskers\")\nprint(dog.speak())  # Rex says Woof!       (inherited)\nprint(dog.info())   # Dog: Rex, Breed: ... (overridden)\nprint(cat.info())   # Animal: Whiskers     (parent's)\nprint(isinstance(dog, Animal), isinstance(cat, Dog))  # True False\n\n# в”Җв”Җ 6. Multi-Level & Multiple Inheritance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n# Multi-level: Vehicle -> ElectricVehicle -> Tesla\nclass Vehicle:\n    def __init__(self, brand): self.brand = brand\n    def start(self): return f\"{self.brand} starting...\"\nclass ElectricVehicle(Vehicle):\n    def __init__(self, brand, bat):\n        super().__init__(brand); self.battery = bat\n    def charge(self): return f\"Charging {self.brand} ({self.battery}kWh)\"\nclass Tesla(ElectricVehicle):\n    def __init__(self, model, bat):\n        super().__init__(\"Tesla\", bat); self.model = model\n\nt = Tesla(\"Model 3\", 75)\nprint(t.start())   # Tesla starting...  (grandparent)\nprint(t.charge())  # Charging Tesla...  (parent)\nprint(Tesla.__mro__)  # Tesla -> ElectricVehicle -> Vehicle -> object\n\n# Multiple: two parents вҖ” MRO decides conflict winner\nclass Flyable:\n    def move(self): return \"Flying\"\nclass Swimmable:\n    def move(self): return \"Swimming\"\nclass Duck(Flyable, Swimmable): pass  # Flyable listed first\n\nduck = Duck()\nprint(duck.move())   # Flying  (Flyable wins вҖ” listed first)\n\n# в”Җв”Җ 7. Polymorphism в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Circle:\n    def __init__(self, r):    self.r = r\n    def area(self):           return 3.14 * self.r ** 2\nclass Rectangle:\n    def __init__(self, w, h): self.w, self.h = w, h\n    def area(self):           return self.w * self.h\nclass Triangle:\n    def __init__(self, b, h): self.b, self.h = b, h\n    def area(self):           return 0.5 * self.b * self.h\n\nfor s in [Circle(5), Rectangle(4, 6), Triangle(3, 8)]:\n    print(f\"{s.__class__.__name__} -> {s.area()}\")  # 78.5, 24, 12.0\n\n# в”Җв”Җ 8. Abstraction вҖ” ABC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nfrom abc import ABC, abstractmethod\n\nclass Shape(ABC):\n    @abstractmethod\n    def area(self): pass         # child MUST implement\n    @abstractmethod\n    def perimeter(self): pass\n    def description(self):        # concrete вҖ” inherited as-is\n        return f\"I am a {self.__class__.__name__}\"\n\nclass Square(Shape):\n    def __init__(self, side): self.side = side\n    def area(self):           return self.side ** 2\n    def perimeter(self):      return 4 * self.side\n\n# Shape()  # TypeError: Can't instantiate abstract class\nsq = Square(5)\nprint(sq.area(), sq.perimeter(), sq.description())  # 25 20 I am a Square\n\n# в”Җв”Җ 9. Magic / Dunder Methods в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Product:\n    def __init__(self, name, price):\n        self.name, self.price = name, price\n    def __str__(self):        return f\"{self.name}: ${self.price}\"           # print()\n    def __repr__(self):       return f\"Product('{self.name}', {self.price})\" # debug\n    def __eq__(self, other):  return self.name == other.name and self.price == other.price\n    def __lt__(self, other):  return self.price < other.price               # enables sort\n    def __add__(self, other): return Product(f\"{self.name}+{other.name}\", self.price + other.price)\n    def __len__(self):        return len(self.name)\n    def __bool__(self):       return self.price > 0\n\np1, p2 = Product(\"Laptop\", 999), Product(\"Mouse\", 25)\nprint(p1)                # Laptop: $999          (__str__)\nprint(repr(p2))          # Product('Mouse', 25)  (__repr__)\nprint(p1 == Product(\"Laptop\", 999))  # True      (__eq__)\nprint(p2 < p1)           # True  (25 < 999)      (__lt__)\nprint(p1 + p2)           # Laptop+Mouse: $1024   (__add__)\nprint(len(p1))           # 6                     (__len__)\nprint(bool(Product(\"Free\", 0)))  # False         (__bool__)\n\n# в”Җв”Җ 10. Subscriptable Objects в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Inventory:\n    def __init__(self):          self._items = {}\n    def __getitem__(self, k):    return self._items.get(k, \"Not found\")\n    def __setitem__(self, k, v): self._items[k] = v\n    def __delitem__(self, k):\n        if k in self._items: del self._items[k]\n    def __contains__(self, k):   return k in self._items\n    def __len__(self):           return len(self._items)\n    def __iter__(self):          return iter(self._items)\n\ninv = Inventory()\ninv[\"laptop\"] = 5; inv[\"mouse\"] = 20  # __setitem__\nprint(inv[\"laptop\"])      # 5     (__getitem__)\nprint(\"mouse\" in inv)     # True  (__contains__)\ndel inv[\"mouse\"]          #       (__delitem__)\nprint(len(inv))           # 1     (__len__)\n\n# в”Җв”Җ 11. Composition вҖ” \"has a\" vs \"is a\" в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Engine:\n    def __init__(self, hp): self.hp, self.running = hp, False\n    def start(self):        self.running = True; return f\"Engine ({self.hp}hp) started\"\nclass GPS:\n    def navigate(self, dest): return f\"Navigating to {dest}...\"\n\nclass MyCar:  # Car HAS an Engine + GPS (composition > inheritance)\n    def __init__(self, brand, hp):\n        self.brand, self.engine, self.gps = brand, Engine(hp), GPS()\n    def start(self):    return f\"{self.brand}: {self.engine.start()}\"\n    def go_to(self, p): return self.gps.navigate(p) if self.engine.running else \"Start first!\"\n\nmy_car = MyCar(\"BMW\", 300)\nprint(my_car.start())           # BMW: Engine (300hp) started\nprint(my_car.go_to(\"Airport\"))  # Navigating to Airport...\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\n# в•‘                  ADVANCED                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n\n# в”Җв”Җ 12. Dataclass в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nfrom dataclasses import dataclass, field\n\n@dataclass\nclass User:\n    name: str; email: str; age: int\n    active: bool = True\n    tags: list = field(default_factory=list)  # mutable default\n\nu1 = User(\"Alice\", \"a@test.com\", 30)\nprint(u1)           # User(name='Alice', ...) вҖ” auto __repr__\nprint(u1 == User(\"Alice\", \"a@test.com\", 30))  # True вҖ” auto __eq__\n\n@dataclass\nclass Point:\n    x: float; y: float\n    def distance(self): return (self.x**2 + self.y**2) ** 0.5\nprint(Point(3, 4).distance())  # 5.0\n\n@dataclass(frozen=True)   # immutable вҖ” can't change after creation\nclass Color:\n    r: int; g: int; b: int\n# Color(255,0,0).r = 100  # FrozenInstanceError!\n\n@dataclass(order=True)    # enables <, >, sorted()\nclass Score:\n    value: int; player: str = \"\"\nprint(sorted([Score(85,\"A\"), Score(92,\"B\"), Score(78,\"C\")]))  # [78, 85, 92]\n\n# в”Җв”Җ 13. __slots__ вҖ” Memory Optimization в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass WithSlots:\n    __slots__ = (\"x\", \"y\")  # fixed attrs вҖ” no __dict__, ~40% less memory\n    def __init__(self, x, y): self.x, self.y = x, y\n\nb = WithSlots(1, 2)\n# b.z = 3    # AttributeError! z not in __slots__\n# b.__dict__ # AttributeError вҖ” no __dict__ with slots\n\n# в”Җв”Җ 14. Mixins вҖ” Reusable Behavior в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nimport json\n\nclass JsonMixin:\n    def to_json(self):     return json.dumps(self.__dict__, indent=2)\n    @classmethod\n    def from_json(cls, s): return cls(**json.loads(s))\n\nclass PrintableMixin:\n    def print_info(self):\n        attrs = \", \".join(f\"{k}={v}\" for k, v in self.__dict__.items())\n        print(f\"[{self.__class__.__name__}] {attrs}\")\n\nclass Article(JsonMixin, PrintableMixin):\n    def __init__(self, title, author, words=0):\n        self.title, self.author, self.words = title, author, words\n\nart = Article(\"Breaking News\", \"Alice\", 500)\nart.print_info()  # [Article] title=Breaking News, author=Alice, words=500\nArticle.from_json('{\"title\":\"Update\",\"author\":\"Bob\",\"words\":300}').print_info()\n\n# в”Җв”Җ 15. Enum вҖ” Named Constants в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nfrom enum import Enum, auto\n\nclass Status(Enum):\n    PENDING = \"pending\"; ACTIVE = \"active\"; INACTIVE = \"inactive\"\nclass Priority(Enum):\n    LOW = auto(); MEDIUM = auto(); HIGH = auto()  # auto: 1, 2, 3\n\nprint(Status.ACTIVE.value)   # active\nprint(Priority.HIGH.value)   # 3\n\n# в”Җв”Җ 16. Method Chaining вҖ” return self в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass QueryBuilder:\n    def __init__(self, table):\n        self.table, self._conds, self._order, self._limit = table, [], None, None\n    def where(self, c):   self._conds.append(c); return self\n    def order_by(self, c): self._order = c; return self\n    def limit(self, n):   self._limit = n; return self\n    def build(self):\n        q = f\"SELECT * FROM {self.table}\"\n        if self._conds: q += \" WHERE \" + \" AND \".join(self._conds)\n        if self._order: q += f\" ORDER BY {self._order}\"\n        if self._limit: q += f\" LIMIT {self._limit}\"\n        return q\n\nq = QueryBuilder(\"users\").where(\"age > 18\").where(\"active = true\").order_by(\"name\").limit(10).build()\nprint(q)  # SELECT * FROM users WHERE age > 18 AND active = true ORDER BY name LIMIT 10\n\n# в”Җв”Җ 17. Context Manager вҖ” __enter__ / __exit__ в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass FileLogger:\n    def __init__(self, fn): self.fn, self.logs = fn, []\n    def __enter__(self):\n        print(f\"Logger started for {self.fn}\"); return self\n    def __exit__(self, exc_type, exc_val, exc_tb):\n        print(f\"Logger finished. {len(self.logs)} logs.\")\n        return False  # don't suppress exceptions\n    def log(self, msg):\n        self.logs.append(msg); print(f\"  LOG: {msg}\")\n\nwith FileLogger(\"app.log\") as logger:\n    logger.log(\"Started\"); logger.log(\"Logged in\")\n\n# в”Җв”Җ 18. Singleton вҖ” Only ONE Instance в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Database:\n    _instance = None\n    def __new__(cls, *args, **kwargs):\n        if cls._instance is None: cls._instance = super().__new__(cls)\n        return cls._instance\n    def __init__(self, host=\"localhost\"): self.host = host\n\ndb1, db2 = Database(\"server1\"), Database(\"server2\")\nprint(db1 is db2)  # True вҖ” same object!\nprint(db1.host)    # server2 вҖ” last __init__ overwrote\n\n# в”Җв”Җ 19. __call__ вҖ” Callable Object в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Multiplier:\n    def __init__(self, factor):  self.factor = factor\n    def __call__(self, value):   return value * self.factor\n\ndouble = Multiplier(2)\nprint(double(5))          # 10\nprint(callable(double))   # True\n\n# в”Җв”Җ 20. Descriptor вҖ” Reusable Attribute Logic в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass PositiveNumber:\n    def __set_name__(self, owner, name): self.name = name\n    def __get__(self, obj, typ=None):    return getattr(obj, f\"_{self.name}\", 0)\n    def __set__(self, obj, value):\n        if value < 0: raise ValueError(f\"{self.name} must be positive, got {value}\")\n        setattr(obj, f\"_{self.name}\", value)\n\nclass Order:\n    quantity = PositiveNumber()\n    price = PositiveNumber()\n    def __init__(self, item, qty, price):\n        self.item, self.quantity, self.price = item, qty, price\n    def total(self): return self.quantity * self.price\n\norder = Order(\"Widget\", 5, 9.99)\nprint(order.total())  # 49.95\ntry:    order.quantity = -3\nexcept ValueError as e: print(f\"Error: {e}\")  # quantity must be positive\n\n# в”Җв”Җ 21. isinstance / issubclass в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Media: pass\nclass Video(Media): pass\nclass Audio(Media): pass\nclass Podcast(Audio): pass\n\nprint(isinstance(Video(), Media))      # True  вҖ” Video IS-A Media\nprint(isinstance(Podcast(), Audio))    # True  вҖ” Podcast IS-A Audio\nprint(issubclass(Podcast, Media))      # True  вҖ” Podcast -> Audio -> Media\nprint(issubclass(Video, Audio))        # False\n\n# в”Җв”Җ 22. __init_subclass__ вҖ” Auto-Register Subclasses в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\nclass Plugin:\n    registry = []\n    def __init_subclass__(cls, **kwargs):\n        super().__init_subclass__(**kwargs)\n        Plugin.registry.append(cls.__name__)\n\nclass PDFExporter(Plugin): pass\nclass CSVExporter(Plugin): pass\nclass XMLExporter(Plugin): pass\nprint(Plugin.registry)  # ['PDFExporter', 'CSVExporter', 'XMLExporter']\n\n# в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—", "cheatSheet": "# в•‘               CHEAT SHEET                        в•‘\n# в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\n# CLASS BASICS:    class Foo | __init__(self) | self.x (instance) | Foo.x (class)\n# METHOD TYPES:    def m(self) instance | @classmethod def(cls) | @staticmethod def()\n# ACCESS CONTROL:  name (public) | _name (protected) | __name (private/mangled)\n# PROPERTY:        @property getter | @x.setter | @x.deleter вҖ” attr syntax\n# INHERITANCE:     class B(A) single | class C(B) multi-level | class D(A,B) multiple\n#                  super().__init__() | __mro__ resolution order\n# POLYMORPHISM:    same method name, different behavior per class\n# ABSTRACTION:     ABC + @abstractmethod вҖ” must implement in child\n# DUNDERS:         __str__ print | __repr__ debug | __eq__ == | __lt__ < (sort)\n#                  __add__ + | __len__ len() | __bool__ bool() | __call__ obj()\n#                  __getitem__ obj[k] | __setitem__ obj[k]=v | __contains__ in\n#                  __iter__ for | __enter__/__exit__ with | __new__ singleton\n#                  __init_subclass__ hook | __set_name__/__get__/__set__ descriptor\n# DATACLASS:       @dataclass auto init/repr/eq | frozen=True immutable | order=True\n# SLOTS:           __slots__=(...) no __dict__, less memory, faster access\n# PATTERNS:        Mixin (reusable MI) | Enum/auto() | return self (chaining)\n#                  Composition > Inheritance вҖ” \"has-a\" beats \"is-a\"", "reference": ""}}};
